// Fallback prayer windows for Cairo when no location yet (approximate year-round)
const AZKAR_FALLBACK_TIMES = { Fajr: '04:30', Dhuhr: '12:00', Asr: '15:30', Maghrib: '18:00', Isha: '19:30' };

// Siraj-only: fake current time for testing azkar windows (cleared on page unload / logout)
let _azkarFakeHour = null; // 0-23, or null = use real time
let _azkarFakeMin  = null;

// Returns 'morning' (Fajr→Dhuhr), 'evening' (Asr→Isha), or null
function getCurrentAzkarType() {
    const times = (gameState.prayer && gameState.prayer.times) ? gameState.prayer.times : AZKAR_FALLBACK_TIMES;
    const toMin = (s) => { if (!s) return null; const [h, m] = s.split(':').map(Number); return h * 60 + m; };
    const fajr  = toMin(times.Fajr);
    const dhuhr = toMin(times.Dhuhr);
    const asr   = toMin(times.Asr);
    const isha  = toMin(times.Isha);
    if (fajr == null || dhuhr == null || asr == null || isha == null) return null;
    let cur;
    if (_azkarFakeHour !== null) {
        cur = _azkarFakeHour * 60 + (_azkarFakeMin || 0);
    } else {
        const now = new Date();
        cur = now.getHours() * 60 + now.getMinutes();
    }
    if (cur >= fajr && cur < dhuhr) return 'morning';
    if (cur >= asr && cur < isha)   return 'evening';
    return null;
}

function _todayDateStr() {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
}

function updateAzkarButton() {
    const btn = document.getElementById('azkar-btn');
    if (!btn) return;

    // Throttle to ~1/s (called from main loop)
    const now = Date.now();
    if (now - gameState.azkar._lastButtonRefresh < 1000) return;
    gameState.azkar._lastButtonRefresh = now;

    const type = getCurrentAzkarType();
    const inSharedPomo = gameState.sharedPomo && gameState.sharedPomo.phase && gameState.sharedPomo.phase !== 'idle';
    const inPrayerOverlay = gameState.prayer && gameState.prayer.isOverlayActive;
    const azkarOpen = gameState.azkar.active;
    const today = _todayDateStr();
    const doneToday = type && gameState.azkar.completed && gameState.azkar.completed[type] === today;

    // Gate on _completionLoaded so the button never flashes on start before we've
    // checked Firebase (it used to show, then snap away once "already read" loaded).
    const az = gameState.azkar;
    const shouldShow = az._completionLoaded
        && !!type && !inSharedPomo && !inPrayerOverlay && !azkarOpen && !doneToday;

    const wasShown = az._btnShown === true;
    if (shouldShow && !wasShown) {
        // Appear — fade/scale in.
        if (az._btnHideTimer) { clearTimeout(az._btnHideTimer); az._btnHideTimer = null; }
        btn.classList.remove('hidden', 'azkar-leaving');
        btn.classList.add('azkar-entering');
        setTimeout(() => btn.classList.remove('azkar-entering'), 460);
        az._btnShown = true;
    } else if (!shouldShow && wasShown) {
        // Disappear — fade/scale out, THEN collapse (display:none) so it never snaps.
        btn.classList.remove('azkar-entering');
        btn.classList.add('azkar-leaving');
        if (az._btnHideTimer) clearTimeout(az._btnHideTimer);
        az._btnHideTimer = setTimeout(() => {
            btn.classList.add('hidden');
            btn.classList.remove('azkar-leaving');
            az._btnHideTimer = null;
        }, 340);
        az._btnShown = false;
    } else if (!shouldShow && !wasShown && !az._btnHideTimer) {
        // Steady hidden (incl. initial state) — no animation.
        btn.classList.add('hidden');
    }

    if (!shouldShow) {
        hideAzkarConfirm();
    }

    const label = document.getElementById('azkar-btn-label');
    if (shouldShow) {
        if (type === 'morning') {
            btn.classList.add('morning'); btn.classList.remove('evening');
            if (label) label.textContent = 'أذكار الصباح';
        } else {
            btn.classList.add('evening'); btn.classList.remove('morning');
            if (label) label.textContent = 'أذكار المساء';
        }
    }

    // Mobile floating button: show when card is focus-hidden and azkar conditions are met
    const floatBtn = document.getElementById('azkar-focus-float-btn');
    if (floatBtn && isMobile()) {
        const cardHidden = document.getElementById('user-card')?.classList.contains('focus-hidden');
        const floatShouldShow = shouldShow && !!cardHidden;
        // Use style.display directly — avoids any CSS class specificity issues
        floatBtn.style.display = floatShouldShow ? 'flex' : 'none';
        if (floatShouldShow && type) {
            floatBtn.textContent = type === 'morning' ? 'أذكار الصباح' : 'أذكار المساء';
            floatBtn.classList.toggle('morning', type === 'morning');
            floatBtn.classList.toggle('evening', type === 'evening');
        }
    } else if (floatBtn) {
        floatBtn.style.display = 'none'; // always hidden on desktop
    }
}

function showAzkarConfirm() {
    const type = getCurrentAzkarType();
    const modal = document.getElementById('azkar-confirm-modal');
    if (!modal) return;
    const typeEl = document.getElementById('azkar-confirm-modal-type');
    if (typeEl) typeEl.textContent = type === 'morning' ? 'أذكار الصباح' : 'أذكار المساء';
    modal.classList.remove('hidden');
}
function hideAzkarConfirm() {
    document.getElementById('azkar-confirm-modal')?.classList.add('hidden');
}

function markAzkarCompleted(type) {
    const today = _todayDateStr();
    gameState.azkar.completed = gameState.azkar.completed || {};
    gameState.azkar.completed[type] = today;
    if (gameState.userId) {
        update(ref(database), { [`users/${gameState.userId}/azkarCompleted`]: gameState.azkar.completed }).catch(() => {});
    }
    gameState.azkar._lastButtonRefresh = 0;   // bypass the 1/s throttle so the fade-out fires now
    updateAzkarButton();
}

function loadAzkarCompletedFromFirebase() {
    if (!gameState.userId) return;
    get(ref(database, `users/${gameState.userId}/azkarCompleted`)).then(snap => {
        gameState.azkar.completed = snap.val() || {};
        gameState.azkar._completionLoaded = true;
        updateAzkarButton();
    }).catch(() => {
        // Offline / read failed — assume not-done so the button can still appear.
        gameState.azkar._completionLoaded = true;
        updateAzkarButton();
    });
}

// Fisher–Yates shuffle (returns a new array, leaves the source untouched).
function _shuffledCopy(arr) {
    const a = arr.slice();
    for (let i = a.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
}

// opts.afterPrayer = post-salah azkar opened ON TOP of the prayer overlay; the
// prayer overlay already froze the timer + faded audio, so we DON'T touch them
// here (closeAzkarOverlay delegates the resume to dismissPrayerOverlay).
function openAzkarOverlay(type, opts) {
    const az = gameState.azkar;
    if (az.active) return;
    opts = opts || {};
    const afterPrayer = !!opts.afterPrayer;

    az.active = true;
    az.type = type;
    az.afterPrayer = afterPrayer;
    az.startTime = Date.now();
    az.currentIndex = 0;
    // Build the active list: custom (after-prayer) or the standard morning/evening
    // set, optionally shuffled if the user enabled "ترتيب الأذكار عشوائي".
    let baseList = afterPrayer ? AZKAR_AFTER_PRAYER
                 : (type === 'morning' ? AZKAR_MORNING : AZKAR_EVENING);
    az.items = (getRandomizeAzkar() && !afterPrayer) ? _shuffledCopy(baseList) : baseList.slice();
    az.counts = az.items.map(z => z.count);

    // Siraj: shorter lock for testing. After-prayer azkar: the انتهيت here closes BOTH
    // overlays (returns to work), so it must obey the same lock as the prayer overlay's
    // "صلّيت" button — otherwise opening azkar then pressing انتهيت would bypass the wait.
    // We anchor az.startTime to the prayer overlay's start so both timers tick in sync.
    if (afterPrayer && gameState.prayer && gameState.prayer.isOverlayActive) {
        az.startTime  = gameState.prayer.overlayStartTime;
        az.minLockMs  = gameState.prayer.prayerLockMs;
    } else {
        az.minLockMs = afterPrayer ? 0 : (gameState.isSirajGhost ? 3000 : 180000);
    }

    document.body.classList.add('azkar-active');
    if (afterPrayer) document.body.classList.add('azkar-after-prayer');
    else document.body.classList.remove('azkar-after-prayer');
    document.body.classList.remove('azkar-sounds-collapsed'); // always start expanded
    const overlay = document.getElementById('azkar-overlay');
    if (overlay) {
        // `mode` still drives the layout/accents; after-prayer keeps the morning base
        // so anything the per-prayer rules below don't override stays sane.
        overlay.dataset.mode = afterPrayer ? 'morning' : type;
        // After-prayer azkar continues the prayer overlay it opened from, so it wears
        // that prayer's sky (dark blue for Isha, sunset for Maghrib, …) rather than a
        // fixed morning blue. Read the key straight off the prayer overlay — that's
        // where showPrayerOverlayDOM already normalised it.
        const prayerKey = afterPrayer
            ? (document.getElementById('prayer-overlay')?.dataset.prayer || '')
            : '';
        if (prayerKey) overlay.dataset.prayer = prayerKey;
        else delete overlay.dataset.prayer;
        overlay.classList.remove('hidden');
        requestAnimationFrame(() => requestAnimationFrame(() => overlay.classList.add('active')));
    }

    // ── Pause pomodoro / freeMode timers ──
    // After-prayer azkar skips this entirely — the prayer overlay already froze
    // everything and owns the resume when it's dismissed.
    if (!afterPrayer) {
        // Solo pomo: snapshot remaining ms (we'll keep extending endTime in update loop)
        if (gameState.pomodoro.active && gameState.sharedPomo.phase !== 'active') {
            az.pausedPomoRemaining = Math.max(0, gameState.pomodoro.endTime - Date.now());
            az.pausedPomoPhase = gameState.pomodoro.phase;
            // Push the frozen endTime to Firebase so other lobby members watching
            // this laptop don't see it expire while the user is in azkar.
            if (gameState.pomodoro.laptopId !== null) {
                update(ref(database), {
                    [lobbyPath(`pomodoro/${gameState.pomodoro.laptopId}/endTime`)]:
                        Date.now() + az.pausedPomoRemaining
                }).catch(() => {});
            }
        }
        // Free mode: snapshot accumulated work, freeze workStartTime
        if (gameState.freeMode.active) {
            const fm = gameState.freeMode;
            if (fm.phase === 'work' && fm.workStartTime > 0) {
                fm.totalWorkMs  += Date.now() - fm.workStartTime;
                fm.workStartTime = 0;
            }
            if (fm.phase === 'break') {
                az.pausedFreeWorkSnap = Math.max(0, fm.breakEndTime - Date.now());
            }
        }
    }

    // Stop player movement
    const _local = gameState.players[gameState.userId];
    if (_local) { _local.isMoving = false; _local.isSprinting = false; }
    if (gameState.joystick) { gameState.joystick.active = false; gameState.joystick.dx = 0; gameState.joystick.dy = 0; gameState.joystick.magnitude = 0; gameState.joystick.sprinting = false; }
    ['KeyW','KeyA','KeyS','KeyD','ArrowUp','ArrowDown','ArrowLeft','ArrowRight','ShiftLeft','ShiftRight']
        .forEach(k => { if (gameState.keys) gameState.keys[k] = false; });

    // ── Stop YouTube (remember if was playing so we can restore) ──
    // After-prayer azkar: the prayer overlay already faded YT out and owns the
    // restore, so don't touch it here.
    if (!afterPrayer && gameState.focusYTPlayer) {
        try {
            const state = gameState.focusYTPlayer.player?.getPlayerState?.() ?? -1;
            az.ytWasPlaying = (state === 1 /* PLAYING */);
            az.ytVolumeBefore = gameState.focusYTPlayer.volume ?? 80;
        } catch (e) { az.ytWasPlaying = false; }
        gameState.focusYTPlayer.fadeOutAndPause(1200);
    }
    // Show "انتهي من أذكارك" overlay above YT
    if (!afterPrayer) document.getElementById('yt-azkar-overlay')?.classList.add('active');

    // On mobile: un-hide user card / logout if they were hidden by focus mode (we need an exit)
    az.focusMobileWasActive = document.body.classList.contains('mobile-focus-mode') ||
        document.querySelector('.user-card.focus-hidden') != null;

    // Block wheel events on the overlay so they don't zoom the game or scroll the page
    const _overlayEl = document.getElementById('azkar-overlay');
    if (_overlayEl && !_overlayEl._azkarWheelBlock) {
        _overlayEl._azkarWheelBlock = (e) => {
            // Allow scroll within the azkar list; block everything else
            if (!e.target.closest('.azkar-list')) {
                e.preventDefault();
            }
            e.stopPropagation();
        };
        _overlayEl.addEventListener('wheel', _overlayEl._azkarWheelBlock, { passive: false });
    }

    // Render & start lock timer
    renderAzkarList();
    // Reset scroll to top so first azkar is always visible
    const _listEl = document.getElementById('azkar-list');
    if (_listEl) _listEl.scrollTop = 0;
    updateAzkarFinishTimer();

    // The lock countdown must not depend on the rAF game loop — that loop is throttled
    // (or paused) in a backgrounded tab, which froze the انتهيت timer mid-count. A plain
    // interval keeps ticking (and unlocks) even when the tab isn't focused.
    if (az._lockInterval) clearInterval(az._lockInterval);
    az._lockInterval = setInterval(updateAzkarFinishTimer, 250);
}

function _ar(n) {
    const map = ['٠','١','٢','٣','٤','٥','٦','٧','٨','٩'];
    return String(n).split('').map(c => map[c] || c).join('');
}

function renderAzkarList() {
    const az = gameState.azkar;
    const listEl = document.getElementById('azkar-list');
    const titleEl = document.getElementById('azkar-title');
    const progEl = document.getElementById('azkar-progress');
    if (!listEl) return;

    const items = az.items;
    if (titleEl) titleEl.textContent = az.afterPrayer ? 'أذكار بعد الصلاة'
        : (az.type === 'morning' ? 'أذكار الصباح' : 'أذكار المساء');
    const completedCount = az.counts.filter(c => c === 0).length;
    if (progEl) progEl.textContent = `${_ar(completedCount)} / ${_ar(items.length)}`;

    listEl.innerHTML = '';
    items.forEach((z, i) => {
        const wrap = document.createElement('div');
        wrap.className = 'azkar-item';
        wrap.style.animationDelay = `${Math.min(i, 12) * 50}ms`;
        if (i === az.currentIndex) wrap.classList.add('current');
        if (az.counts[i] === 0) { wrap.classList.add('done'); wrap.classList.remove('current'); }

        const txt = document.createElement('div');
        txt.className = 'azkar-item-text';
        // Compose: bold highlight (if any), then the rest
        if (z.highlight && z.highlight.trim()) {
            const hi = document.createElement('span');
            hi.className = 'azkar-highlight';
            hi.textContent = z.highlight + ' ';
            txt.appendChild(hi);
        }
        txt.appendChild(document.createTextNode(z.text));
        wrap.appendChild(txt);

        const footer = document.createElement('div');
        footer.className = 'azkar-item-footer';
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'azkar-count-btn';
        btn.dataset.idx = String(i);
        const remaining = az.counts[i];
        if (remaining > 0) {
            btn.textContent = _ar(remaining);
        } else {
            btn.classList.add('done');
            btn.textContent = '✓';
            btn.disabled = true;
        }
        btn.addEventListener('click', (e) => {
            if (document.body.classList.contains('is-mobile')) e.stopPropagation();
            onAzkarCountClick(i);
        });
        footer.appendChild(btn);
        wrap.appendChild(footer);

        // Mobile: tap anywhere on the row triggers the count, not just the tiny button
        wrap.addEventListener('click', () => {
            if (!document.body.classList.contains('is-mobile')) return;
            onAzkarCountClick(i);
        });

        listEl.appendChild(wrap);

        if (i < items.length - 1) {
            const sep = document.createElement('div');
            sep.className = 'azkar-sep';
            listEl.appendChild(sep);
        }
    });
}

function onAzkarCountClick(idx) {
    const az = gameState.azkar;
    if (!az.active) return;
    if (az.counts[idx] <= 0) return;
    az.counts[idx] -= 1;
    const items = az.items;
    const listEl = document.getElementById('azkar-list');
    const itemEls = listEl?.querySelectorAll('.azkar-item');
    if (!itemEls) return;
    const itemEl = itemEls[idx];
    const btn = itemEl?.querySelector('.azkar-count-btn');

    if (az.counts[idx] === 0) {
        // Mark done
        if (btn) { btn.classList.add('done'); btn.textContent = '✓'; btn.disabled = true; }
        itemEl?.classList.add('done');
        itemEl?.classList.remove('current');

        // Update progress label
        const progEl = document.getElementById('azkar-progress');
        const completedCount = az.counts.filter(c => c === 0).length;
        if (progEl) progEl.textContent = `${_ar(completedCount)} / ${_ar(items.length)}`;

        // Advance to next non-done index
        let next = idx + 1;
        while (next < items.length && az.counts[next] === 0) next++;
        if (next < items.length) {
            az.currentIndex = next;
            itemEls.forEach((el, j) => el.classList.toggle('current', j === next));
            // Smooth scroll to next — scroll ONLY the list, never let it bubble to the
            // overlay/page (scrollIntoView used to scroll the whole overlay down, which
            // looked like the overlay jumping when the list couldn't scroll on its own).
            const nextEl = itemEls[next];
            if (nextEl && listEl) {
                setTimeout(() => {
                    const lr = listEl.getBoundingClientRect();
                    const nr = nextEl.getBoundingClientRect();
                    const delta = (nr.top - lr.top) - (listEl.clientHeight / 2 - nr.height / 2);
                    const maxTop = listEl.scrollHeight - listEl.clientHeight;
                    const top = Math.max(0, Math.min(maxTop, listEl.scrollTop + delta));
                    listEl.scrollTo({ top, behavior: 'smooth' });
                }, 220);
            }
        }
    } else {
        if (btn) btn.textContent = _ar(az.counts[idx]);
    }
}

function updateAzkarFinishTimer() {
    const az = gameState.azkar;
    if (!az.active) return;
    const elapsed = Date.now() - az.startTime;
    const remaining = Math.max(0, az.minLockMs - elapsed);
    const btn = document.getElementById('azkar-finish-btn');
    const timerEl = document.getElementById('azkar-finish-timer');
    if (remaining <= 0) {
        if (btn) { btn.removeAttribute('disabled'); btn.classList.add('unlocked'); }
        if (timerEl) timerEl.textContent = '';
    } else {
        const m = Math.floor(remaining / 60000);
        const s = Math.floor((remaining % 60000) / 1000);
        if (timerEl) timerEl.textContent = `${m}:${String(s).padStart(2, '0')}`;
        // Don't use disabled — it leaks taps on iOS. Use class only; click handler checks .unlocked.
        if (btn) { btn.removeAttribute('disabled'); btn.classList.remove('unlocked'); }
    }
}

// After-prayer "رجوع": close the azkar overlay but stay in the prayer overlay (no resume).
// The prayer overlay underneath keeps the work session frozen; we only tear down the azkar
// UI. The lock is anchored to the prayer overlay, so reopening azkar resumes the same count.
function closeAzkarToPrayerOverlay() {
    const az = gameState.azkar;
    if (!az.active || !az.afterPrayer) return;
    az.active = false;
    az.afterPrayer = false;

    const overlay = document.getElementById('azkar-overlay');
    if (overlay) {
        overlay.classList.remove('active');
        // `azkar-after-prayer` must outlive the fade — its per-prayer bg rules are
        // what's actually painted, and `.azkar-overlay-bg` transitions `background`
        // over 1.2s. Dropping the class immediately swaps it back to the plain
        // data-mode="morning" blue WHILE the overlay is still visibly fading out,
        // i.e. a blue flash right before it disappears. Strip it only once hidden.
        setTimeout(() => {
            overlay.classList.add('hidden');
            document.body.classList.remove('azkar-after-prayer');
        }, 700);
    } else {
        document.body.classList.remove('azkar-after-prayer');
    }
    document.body.classList.remove('azkar-active');
    document.body.classList.remove('azkar-sounds-collapsed');
    if (az._lockInterval) { clearInterval(az._lockInterval); az._lockInterval = null; }
    az.type = null;
    az.items = [];
    updateAzkarButton();
    // The prayer overlay stays active and visible — nothing else to do.
}

function closeAzkarOverlay(markDone) {
    const az = gameState.azkar;
    if (!az.active) return;
    const wasAfterPrayer = az.afterPrayer;
    az.active = false;
    az.afterPrayer = false;

    // After-prayer azkar: the prayer overlay owns the timer/audio resume. Just fade
    // the azkar overlay out and then dismiss the prayer overlay (which un-freezes the
    // timer + fades focus sounds / YouTube back in → normal work session). Skip all
    // the solo/free resume logic below so we don't double-resume.
    if (wasAfterPrayer) {
        const overlay = document.getElementById('azkar-overlay');
        if (overlay) {
            overlay.classList.remove('active');
            // Same reasoning as closeAzkarToPrayerOverlay: keep `azkar-after-prayer`
            // through the fade so the overlay doesn't flash back to default blue
            // right before it disappears.
            setTimeout(() => {
                overlay.classList.add('hidden');
                document.body.classList.remove('azkar-after-prayer');
            }, 700);
        } else {
            document.body.classList.remove('azkar-after-prayer');
        }
        document.body.classList.remove('azkar-active');
        document.body.classList.remove('azkar-sounds-collapsed');
        if (az._lockInterval) { clearInterval(az._lockInterval); az._lockInterval = null; }
        az.type = null;
        az.items = [];
        // Dismiss the prayer overlay underneath — this resumes the work session.
        if (gameState.prayer && gameState.prayer.isOverlayActive) dismissPrayerOverlay();
        updateAzkarButton();
        return;
    }

    // Resume pomodoro endTime (solo)
    if (gameState.pomodoro.active && gameState.sharedPomo.phase !== 'active') {
        if (az.pausedPomoRemaining > 0) {
            gameState.pomodoro.endTime = Date.now() + az.pausedPomoRemaining;
            if (gameState.pomodoro.laptopId !== null) {
                const updates = {};
                updates[lobbyPath(`pomodoro/${gameState.pomodoro.laptopId}/endTime`)] = gameState.pomodoro.endTime;
                update(ref(database), updates).catch(() => {});
            }
        }
    }
    // Resume free-mode
    if (gameState.freeMode.active) {
        const fm = gameState.freeMode;
        if (fm.phase === 'work' && fm.workStartTime === 0) {
            fm.workStartTime = Date.now();
        }
        if (fm.phase === 'break' && az.pausedFreeWorkSnap > 0) {
            fm.breakEndTime = Date.now() + az.pausedFreeWorkSnap;
        }
    }

    // Restore YouTube
    document.getElementById('yt-azkar-overlay')?.classList.remove('active');
    if (gameState.focusYTPlayer && az.ytWasPlaying) {
        const targetPct = az.ytVolumeBefore || gameState.focusYTPlayer.volume || 80;
        try {
            gameState.focusYTPlayer.setVolumePercent(0);
            gameState.focusYTPlayer.resume().then(() => {
                let e = 0;
                const iv = setInterval(() => {
                    e += 50;
                    gameState.focusYTPlayer.setVolumePercent(Math.min(targetPct, Math.round(targetPct * e / 1500)));
                    if (e >= 1500) clearInterval(iv);
                }, 50);
            }).catch(() => { gameState.focusYTPlayer.setVolumePercent(targetPct); });
        } catch (e) {}
    }
    az.ytWasPlaying = false;

    // Fade out overlay
    const overlay = document.getElementById('azkar-overlay');
    if (overlay) {
        overlay.classList.remove('active');
        setTimeout(() => { overlay.classList.add('hidden'); }, 700);
    }
    document.body.classList.remove('azkar-active');

    if (markDone && az.type) markAzkarCompleted(az.type);

    // Stop the independent lock countdown
    if (az._lockInterval) { clearInterval(az._lockInterval); az._lockInterval = null; }

    // If the panel was used as a live mixer outside a work phase, fade master back
    // down so ambient sounds don't keep playing after azkar closes. Skip this while
    // still sitting on the big sofa — that has its own ambience session running
    // (applySofaFocusUI) that should keep playing after azkar closes, not get killed.
    const inWork = (gameState.pomodoro.active && gameState.pomodoro.phase === 'work')
        || (gameState.freeMode.active && gameState.freeMode.phase === 'work')
        || sofaFocusActive();
    if (gameState.focusAudioEngine && !inWork) gameState.focusAudioEngine.fadeToMaster(0, 0.6);

    // Reset the collapsed state so the panel is expanded next time
    document.body.classList.remove('azkar-sounds-collapsed');

    az.type = null;
    az.pausedPomoRemaining = 0;
    az.pausedFreeWorkSnap = 0;
    az.pausedPomoPhase = null;
    updateAzkarButton();
}

function setupAzkarTimePicker() {
    const spoofBtn = document.getElementById('azkar-time-spoof-btn');
    const modal    = document.getElementById('azkar-time-picker-modal');
    const hEl      = document.getElementById('azkar-tp-h');
    const mEl      = document.getElementById('azkar-tp-m');
    const preview  = document.getElementById('azkar-tp-preview');
    const setBtn   = document.getElementById('azkar-tp-set');
    const clearBtn = document.getElementById('azkar-tp-close-x'); // alias below
    const clearBtn2= document.getElementById('azkar-tp-clear');
    const closeBtn = document.getElementById('azkar-tp-close');
    if (!spoofBtn || !modal) return;

    let tpH = _azkarFakeHour !== null ? _azkarFakeHour : new Date().getHours();
    let tpM = _azkarFakeMin  !== null ? _azkarFakeMin  : new Date().getMinutes();

    function fmt2(n) { return String(n).padStart(2, '0'); }

    function _updatePreview() {
        hEl.textContent = fmt2(tpH);
        mEl.textContent = fmt2(tpM);
        // compute what azkar type this would yield using real prayer times
        const times = (gameState.prayer && gameState.prayer.times) ? gameState.prayer.times : AZKAR_FALLBACK_TIMES;
        const toMin = (s) => { if (!s) return null; const [h, m] = s.split(':').map(Number); return h * 60 + m; };
        const fajr  = toMin(times.Fajr);
        const dhuhr = toMin(times.Dhuhr);
        const asr   = toMin(times.Asr);
        const isha  = toMin(times.Isha);
        const cur   = tpH * 60 + tpM;
        let label = 'خارج النافذة';
        if (fajr != null && dhuhr != null && cur >= fajr && cur < dhuhr) label = 'أذكار الصباح 🌅';
        else if (asr != null && isha != null && cur >= asr && cur < isha)  label = 'أذكار المساء 🌙';
        preview.textContent = label;
    }

    function _open() {
        tpH = _azkarFakeHour !== null ? _azkarFakeHour : new Date().getHours();
        tpM = _azkarFakeMin  !== null ? _azkarFakeMin  : new Date().getMinutes();
        _updatePreview();
        modal.classList.remove('hidden');
        spoofBtn.classList.add('active');
    }
    function _close() {
        modal.classList.add('hidden');
        // Keep 'active' styling on the button when a fake time is in effect
        if (_azkarFakeHour === null) spoofBtn.classList.remove('active');
    }

    spoofBtn.addEventListener('click', (e) => { e.stopPropagation(); _open(); });

    modal.addEventListener('click', (e) => { if (e.target === modal) _close(); });
    closeBtn?.addEventListener('click', _close);

    // Arrow buttons
    modal.querySelectorAll('.azkar-tp-arrow').forEach(btn => {
        btn.addEventListener('click', () => {
            const field = btn.dataset.field;
            const isUp  = btn.classList.contains('azkar-tp-up');
            if (field === 'h') { tpH = (tpH + (isUp ? 1 : -1) + 24) % 24; }
            if (field === 'm') { tpM = (tpM + (isUp ? 5 : -5) + 60) % 60; }
            _updatePreview();
        });
    });

    // Scroll wheel — normalize by deltaMode so one physical click = one unit on any mouse
    const _scrollAcc = { h: 0, m: 0 };
    [hEl, mEl].forEach(el => {
        el.addEventListener('wheel', (e) => {
            e.preventDefault();
            const key = el === hEl ? 'h' : 'm';
            // Normalize: pixels(0)→as-is, lines(1)→×40, pages(2)→×800
            const norm = e.deltaMode === 0 ? e.deltaY : e.deltaMode === 1 ? e.deltaY * 40 : e.deltaY * 800;
            _scrollAcc[key] += norm;
            if (Math.abs(_scrollAcc[key]) >= 40) {
                const dir = _scrollAcc[key] > 0 ? -1 : 1;
                _scrollAcc[key] = 0;
                if (key === 'h') tpH = (tpH + dir + 24) % 24;
                else             tpM = (tpM + dir + 60) % 60;
                _updatePreview();
            }
        }, { passive: false });
    });

    // Apply — also clears azkarCompleted so the button appears fresh for the new time window
    setBtn?.addEventListener('click', () => {
        _azkarFakeHour = tpH;
        _azkarFakeMin  = tpM;
        spoofBtn.title = `الوقت التجريبي: ${fmt2(tpH)}:${fmt2(tpM)}`;
        // Clear local completion state
        gameState.azkar.completed = {};
        // Clear from Firebase
        if (gameState.userId) {
            update(ref(database), { [`users/${gameState.userId}/azkarCompleted`]: null }).catch(() => {});
        }
        gameState.azkar._lastButtonRefresh = 0; // force immediate button refresh
        _close(); // _close keeps active class when fake time is set
    });

    // Clear fake time
    clearBtn2?.addEventListener('click', () => {
        _azkarFakeHour = null;
        _azkarFakeMin  = null;
        spoofBtn.title = 'تغيير الوقت (سراج)';
        spoofBtn.classList.remove('active');
        gameState.azkar._lastButtonRefresh = 0;
        _close();
    });
}

function setupAzkarUI() {
    // Both the regular button and the mobile float button open the confirm popup
    const _openConfirm = () => showAzkarConfirm();

    document.getElementById('azkar-btn')?.addEventListener('click', (e) => {
        e.stopPropagation();
        _openConfirm();
    });

    // Mobile floating azkar button — also shows confirm modal (same flow on all devices)
    document.getElementById('azkar-focus-float-btn')?.addEventListener('click', () => {
        _openConfirm();
    });

    // Confirm modal buttons
    document.getElementById('azkar-confirm-modal-yes')?.addEventListener('click', () => {
        const type = getCurrentAzkarType();
        if (type) markAzkarCompleted(type);
        hideAzkarConfirm();
    });

    document.getElementById('azkar-confirm-modal-no')?.addEventListener('click', () => {
        const type = getCurrentAzkarType();
        hideAzkarConfirm();
        if (type) openAzkarOverlay(type);
    });

    // Clicking outside the modal box closes it
    document.getElementById('azkar-confirm-modal')?.addEventListener('click', (e) => {
        if (e.target === document.getElementById('azkar-confirm-modal')) hideAzkarConfirm();
    });

    document.getElementById('azkar-finish-btn')?.addEventListener('click', () => {
        const fb = document.getElementById('azkar-finish-btn');
        if (!fb?.classList.contains('unlocked')) return; // still locked
        closeAzkarOverlay(true);
    });

    // رجوع — only in the after-prayer flow: hide the azkar overlay and reveal the prayer
    // overlay underneath WITHOUT resuming the work session (the prayer overlay still owns
    // the freeze). The 3-min lock keeps running, so flipping back and forth can't bypass it.
    document.getElementById('azkar-back-btn')?.addEventListener('click', () => {
        closeAzkarToPrayerOverlay();
    });

    // Hide / show the focus-sounds panel during azkar (smooth slide, CSS-driven)
    document.getElementById('azkar-sounds-hide')?.addEventListener('click', () => {
        document.body.classList.add('azkar-sounds-collapsed');
    });
    document.getElementById('azkar-sounds-show')?.addEventListener('click', () => {
        document.body.classList.remove('azkar-sounds-collapsed');
    });

    loadAzkarCompletedFromFirebase();

    // Show time-spoof button only for Siraj
    if (gameState.isSirajGhost) {
        document.getElementById('azkar-time-spoof-btn')?.classList.remove('hidden');
        setupAzkarTimePicker();
    }
}

// Called every frame; lightweight (button update is throttled, timer only when overlay open).
function updateAzkarSystem() {
    if (gameState.azkar.active) {
        updateAzkarFinishTimer();
    }
    updateAzkarButton();
}

// ─── Laptop Boss Fight Minigame ───────────────────────────────────────────────
// Single-player platformer boss fight. Mirrors the race/coffee minigame structure
// (Firebase session, teleport animation, return point) but the gameplay is local-only.

function laptopBossSessionPath(sub) {
    const k = gameState.laptopBoss.sessionKey;
    if (!k) return null;
    return lobbyPath(`minigames/laptop-boss/sessions/${k}${sub ? '/' + sub : ''}`);
}

function drawLaptopBossMachine() {
    if (!isBreakActive()) return;
    const ctx = gameState.ctx;
    const img = gameState.assets.laptopBossZone;
    if (!img || !img.complete || !img.naturalWidth) return;

    const cx = LAPTOP_BOSS_ZONE_CX;
    const cy = LAPTOP_BOSS_ZONE_CY;
    ctx.save();
    ctx.imageSmoothingEnabled = false;
    if (gameState.activeLaptopBossZone && !gameState.laptopBoss.teleportAnim) {
        ctx.shadowBlur  = 28;
        ctx.shadowColor = 'rgba(180, 80, 255, 0.7)';
    }
    ctx.drawImage(img, cx - LAPTOP_BOSS_ZONE_IMG_W / 2, cy - LAPTOP_BOSS_ZONE_IMG_H / 2, LAPTOP_BOSS_ZONE_IMG_W, LAPTOP_BOSS_ZONE_IMG_H);
    ctx.shadowBlur = 0;

    const zonePlayers = gameState.laptopBossZonePlayers;
    if (zonePlayers.length > 0 && !gameState.laptopBoss.teleportAnim) {
        drawBossReadyList(ctx, cx, cy - LAPTOP_BOSS_ZONE_IMG_H / 2 - 6, zonePlayers);
    }
    ctx.restore();
}

function drawBossReadyList(ctx, cx, bottomY, players) {
    const rowH = 34, listW = 158, padTop = 22;
    const listH = players.length * rowH + padTop + 4;
    const listX = cx - listW / 2;
    const listY = bottomY - listH - 6;

    ctx.save();
    ctx.fillStyle = 'rgba(18, 8, 28, 0.90)';
    drawRoundedRectPath(ctx, listX, listY, listW, listH, 10);
    ctx.fill();
    ctx.strokeStyle = 'rgba(180,100,255,0.18)';
    ctx.lineWidth   = 1;
    drawRoundedRectPath(ctx, listX, listY, listW, listH, 10);
    ctx.stroke();

    ctx.fillStyle = 'rgba(220,180,255,0.85)';
    ctx.font      = 'bold 12px Rubik';
    ctx.textAlign = 'center';
    ctx.fillText('جاهز للقتال ⚔', cx, listY + 15);

    players.forEach((p, i) => {
        const rowY    = listY + padTop + i * rowH;
        const avatarR = 12;
        const avatarX = listX + 22;
        const avatarCY = rowY + rowH / 2;

        ctx.beginPath();
        ctx.arc(avatarX, avatarCY, avatarR, 0, Math.PI * 2);
        ctx.fillStyle = p.userId === gameState.userId ? COLORS.blue : '#444';
        ctx.fill();

        const avImg = gameState.avatarCache[p.userId];
        if (avImg && avImg !== 'failed') {
            ctx.save();
            ctx.beginPath();
            ctx.arc(avatarX, avatarCY, avatarR, 0, Math.PI * 2);
            ctx.clip();
            ctx.drawImage(avImg, avatarX - avatarR, avatarCY - avatarR, avatarR * 2, avatarR * 2);
            ctx.restore();
        }
        ctx.fillStyle = 'white';
        ctx.font      = '13px Rubik';
        ctx.textAlign = 'left';
        ctx.fillText((p.username || '?').slice(0, 12), listX + 40, avatarCY + 4);
        ctx.fillStyle = '#c084fc';
        ctx.font      = 'bold 11px Rubik';
        ctx.textAlign = 'right';
        ctx.fillText('✓', listX + listW - 8, avatarCY + 4);
    });
    ctx.restore();
}

function drawLaptopBossHint() {
    if (!gameState.activeLaptopBossZone) return;
    if (gameState.laptopBoss.teleportAnim) return;
    const ctx = gameState.ctx;
    ctx.save();
    ctx.fillStyle   = 'white';
    ctx.font        = 'bold 13px Rubik';
    ctx.textAlign   = 'center';
    ctx.shadowBlur  = 6;
    ctx.shadowColor = 'black';
    ctx.fillText('اضغط زر البدء', LAPTOP_BOSS_BTN_CX, LAPTOP_BOSS_BTN_CY - LAPTOP_BOSS_BTN_R - 10);
    ctx.shadowBlur = 0;
    ctx.restore();
}

function listenToLaptopBoss() {
    onValue(ref(database, lobbyPath('minigames/laptop-boss/sessions')), (snap) => {
        const sessions = snap.val() || {};
        const active = {};
        const now = Date.now();
        for (const [key, s] of Object.entries(sessions)) {
            if (!s) continue;
            // Stale cleanup — sessions older than 15 min go away
            if (s.createdAt && now - s.createdAt > 15 * 60 * 1000) {
                update(ref(database), { [lobbyPath(`minigames/laptop-boss/sessions/${key}`)]: null });
                continue;
            }
            active[key] = s;
        }
        gameState.laptopBoss.activeSessions = active;

        let myKey = null, mySession = null;
        for (const [key, s] of Object.entries(active)) {
            if (s.participants?.[gameState.userId]) { myKey = key; mySession = s; break; }
        }

        if (!mySession) {
            if (gameState.laptopBoss.active) returnFromLaptopBoss(false);
            gameState.laptopBoss.session = null;
            gameState.laptopBoss.sessionKey = null;
            return;
        }

        gameState.laptopBoss.session = mySession;
        gameState.laptopBoss.sessionKey = myKey;

        if (mySession.phase === 'teleporting') {
            if (!gameState.laptopBoss.teleportAnim) {
                const elapsed = Math.max(0, (serverNow() - (mySession.teleportAt || serverNow())) / 1000);
                gameState.laptopBoss.teleportAnim = {
                    t: elapsed, phase: 'fly', flyProgress: 0, screenAlpha: 0,
                    pendingSession: null, gameStarted: false, sessionCreated: false,
                    isHost: mySession.hostId === gameState.userId,
                    players: [{
                        userId: gameState.userId,
                        startX: (gameState.players[gameState.userId]?.x) || 0,
                        startY: (gameState.players[gameState.userId]?.y) || 0,
                    }],
                };
            }
        } else if (mySession.phase === 'active') {
            if (gameState.laptopBoss.teleportAnim) {
                gameState.laptopBoss.teleportAnim.pendingSession = gameState.laptopBoss.teleportAnim.pendingSession || mySession;
            } else {
                startLocalLaptopBoss(mySession);
            }
        } else if (mySession.phase === 'finished') {
            gameState.laptopBoss.active = true;
            gameState.laptopBoss.session = mySession;
            gameState.laptopBoss.showResultsInGame = true;
        }
    });
}

async function triggerLaptopBossTeleport() {
    if (!gameState.userId || !isBreakActive()) return;
    if (gameState.laptopBoss.teleportAnim) return;
    if (gameState.laptopBoss.active) return;
    const player = gameState.players[gameState.userId];
    if (!player) return;

    // Make sure the boss SFX (deferred at startup) are loading — the teleport
    // animation gives them time to arrive before gameplay starts.
    gameState.focusAudioEngine?.ensureBossSounds?.();

    playSoundRobust(gameState.sounds.minigameButtonPressed);

    const alreadyIn = Object.values(gameState.laptopBoss.activeSessions || {}).some(
        s => s && s.participants?.[gameState.userId]
    );
    if (alreadyIn) return;

    const sessionId = `${gameState.userId}_${Date.now()}`;
    // Single-player game — safe to auto-remove session on disconnect.
    onDisconnect(ref(database, lobbyPath(`minigames/laptop-boss/sessions/${sessionId}`))).remove();

    update(ref(database), {
        [lobbyPath(`minigames/laptop-boss/sessions/${sessionId}`)]: {
            id:         sessionId,
            hostId:     gameState.userId,
            phase:      'teleporting',
            createdAt:  Date.now(),
            teleportAt: serverNow(),
            participants: {
                [gameState.userId]: {
                    username:    player.username || gameState.currentUser || 'لاعب',
                    avatar:      player.avatar || '',
                    returnPoint: { x: player.x, y: player.y },
                }
            }
        }
    });
}

function createLaptopBossSession() {
    if (!gameState.laptopBoss.sessionKey) return;
    update(ref(database), {
        [laptopBossSessionPath('phase')]:     'active',
        [laptopBossSessionPath('startTime')]: serverNow() + 800,  // tiny lead-in so player can settle
    });
}

function updateLaptopBossTeleportAnim() {
    const anim = gameState.laptopBoss.teleportAnim;
    if (!anim) return;
    const FLY_DUR = 0.45, FADE_DUR = 0.30, HOLD_DUR = 0.40, FADEIN_DUR = 0.60;
    anim.t += gameState.dtFactor / 60;

    const tryStart = () => {
        if (anim.pendingSession && !anim.gameStarted) {
            anim.gameStarted = true;
            startLocalLaptopBoss(anim.pendingSession);
        }
    };

    if (anim.t < FLY_DUR) {
        anim.phase = 'fly'; anim.flyProgress = anim.t / FLY_DUR; anim.screenAlpha = 0;
    } else if (anim.t < FLY_DUR + FADE_DUR) {
        anim.phase = 'fade'; anim.flyProgress = 1;
        anim.screenAlpha = (anim.t - FLY_DUR) / FADE_DUR;
    } else if (anim.t < FLY_DUR + FADE_DUR + HOLD_DUR) {
        anim.phase = 'hold'; anim.flyProgress = 1; anim.screenAlpha = 1;
        if (anim.isHost && !anim.sessionCreated) {
            anim.sessionCreated = true;
            createLaptopBossSession();
        }
        tryStart();
    } else if (anim.t < FLY_DUR + FADE_DUR + HOLD_DUR + FADEIN_DUR) {
        anim.phase = 'fadein'; anim.flyProgress = 1;
        anim.screenAlpha = 1 - (anim.t - FLY_DUR - FADE_DUR - HOLD_DUR) / FADEIN_DUR;
        tryStart();
    } else {
        tryStart();
        gameState.laptopBoss.teleportAnim = null;
    }
}

// ─── Boss audio helpers ───────────────────────────────────────────────────────
// All boss sounds go through the FocusAudioEngine's Web Audio context so they
// work in background tabs. They bypass the focus mixer's masterGain and connect
// directly to ctx.destination via their own gain nodes.

function _bossCtx() {
    const eng = gameState.focusAudioEngine;
    if (!eng) return null;
    if (!eng.ctx) eng.init();
    return eng.ctx;
}

// Play a one-shot boss sound by buffer key
// Volume levels for each one-shot boss sound.
// Crowd/applause are loud by default; gameplay SFX need a boost.
const BOSS_APPLAUSE_VOL = 0.45; // max volume for the looping applause track
const BOSS_SOUND_VOLUMES = {
    crowdCheer:         0.60,
    crowdShock:         0.60,
    bossAnticipate:     2.0,
    bossAttackInitiate: 2.0,
    bossGrabInitiate:   2.0,
    bossGrabSuccess:    2.0,
    bossWeakInitiate:   2.0,
    bossWeakEnd:        2.0,
    bossHit:            2.0,
    bossAttackStomp:    2.0,
    playerHitBoss:      2.0,
    playerLooseBoss:    2.0,
    playerWinBoss:      2.0,
    bossWeakIdle:       1.0,  // managed separately (loop)
};

function bossPlaySound(key) {
    const ctx = _bossCtx();
    if (!ctx) return;
    const buf = gameState.focusAudioEngine.buffers[key];
    if (!buf) return;
    const vol = BOSS_SOUND_VOLUMES[key] ?? 1.0;
    ctx.resume().then(() => {
        try {
            const src = ctx.createBufferSource();
            src.buffer = buf;
            const g = ctx.createGain();
            g.gain.setValueAtTime(vol, ctx.currentTime);
            src.connect(g);
            g.connect(ctx.destination);
            src.start(0);
        } catch(e) {}
    });
}

// Start the looping crowd applause for the boss fight.
// Trims first 4 s and last 4 s by using loopStart/loopEnd.
// Fades in over fadeMs milliseconds.
function startBossApplause(fadeMs = 1500) {
    const ctx = _bossCtx();
    const ba = gameState.laptopBoss.bossAudio;
    if (!ctx) return;
    const buf = gameState.focusAudioEngine.buffers.bossApplause;
    if (!buf) return;
    ctx.resume().then(() => {
        try {
            const dur = buf.duration;
            const loopStart = 4.0;
            const loopEnd   = Math.max(loopStart + 1, dur - 4.0);

            const gainNode = ctx.createGain();
            gainNode.gain.setValueAtTime(0, ctx.currentTime);
            gainNode.gain.linearRampToValueAtTime(BOSS_APPLAUSE_VOL, ctx.currentTime + fadeMs / 1000);
            gainNode.connect(ctx.destination);

            const src = ctx.createBufferSource();
            src.buffer = buf;
            src.loop = true;
            src.loopStart = loopStart;
            src.loopEnd   = loopEnd;
            src.connect(gainNode);
            src.start(0, loopStart); // skip into audio past the file's own fade-in

            ba.applauseSource = src;
            ba.applauseGain   = gainNode;
        } catch(e) {}
    });
}

// Fade out and stop the applause. fadeMs = 0 means instant.
function stopBossApplause(fadeMs = 1200) {
    const ctx = _bossCtx();
    const ba  = gameState.laptopBoss.bossAudio;
    if (!ctx || !ba.applauseSource) return;
    const src  = ba.applauseSource;
    const gain = ba.applauseGain;
    ba.applauseSource = null;
    ba.applauseGain   = null;
    if (ba.duckTimer) { clearTimeout(ba.duckTimer); ba.duckTimer = null; }
    try {
        gain.gain.cancelScheduledValues(ctx.currentTime);
        gain.gain.setValueAtTime(gain.gain.value, ctx.currentTime);
        if (fadeMs > 0) {
            gain.gain.linearRampToValueAtTime(0, ctx.currentTime + fadeMs / 1000);
            setTimeout(() => { try { src.stop(); } catch(e) {} }, fadeMs + 50);
        } else {
            src.stop();
        }
    } catch(e) {}
}

// Duck applause to 20%, play a crowd sound, then ramp back up.
// duckKey = 'crowdCheer' | 'crowdShock'
function bossDuckApplause(duckKey) {
    const ctx = _bossCtx();
    const ba  = gameState.laptopBoss.bossAudio;
    bossPlaySound(duckKey);
    if (!ctx || !ba.applauseGain) return;
    const g = ba.applauseGain;
    if (ba.duckTimer) { clearTimeout(ba.duckTimer); ba.duckTimer = null; }
    try {
        g.gain.cancelScheduledValues(ctx.currentTime);
        g.gain.setValueAtTime(g.gain.value, ctx.currentTime);
        g.gain.linearRampToValueAtTime(0.20, ctx.currentTime + 0.30); // duck in 300 ms
    } catch(e) {}
    // Recover after 2 s
    ba.duckTimer = setTimeout(() => {
        ba.duckTimer = null;
        if (!ba.applauseGain) return;
        try {
            g.gain.cancelScheduledValues(ctx.currentTime);
            g.gain.setValueAtTime(g.gain.value, ctx.currentTime);
            g.gain.linearRampToValueAtTime(BOSS_APPLAUSE_VOL, ctx.currentTime + 0.80); // ramp up 800 ms
        } catch(e) {}
    }, 2000);
}

// Start looping weak-idle sound, with a 1-second startup delay and fade-in.
function startBossWeakIdle() {
    const ba = gameState.laptopBoss.bossAudio;
    if (ba.weakIdleTimer) { clearTimeout(ba.weakIdleTimer); ba.weakIdleTimer = null; }
    stopBossWeakIdle(0); // kill any existing one instantly
    ba.weakIdleTimer = setTimeout(() => {
        ba.weakIdleTimer = null;
        const ctx = _bossCtx();
        if (!ctx) return;
        const buf = gameState.focusAudioEngine.buffers.bossWeakIdle;
        if (!buf) return;
        ctx.resume().then(() => {
            try {
                const gainNode = ctx.createGain();
                gainNode.gain.setValueAtTime(0, ctx.currentTime);
                gainNode.gain.linearRampToValueAtTime(1.0, ctx.currentTime + 0.5);
                gainNode.connect(ctx.destination);

                const src = ctx.createBufferSource();
                src.buffer = buf;
                src.loop = true;
                src.connect(gainNode);
                src.start(0);

                ba.weakIdleSource = src;
                ba.weakIdleGain   = gainNode;
            } catch(e) {}
        });
    }, 1000);
}

// Fade out and stop the weak-idle loop.
function stopBossWeakIdle(fadeMs = 500) {
    const ctx = _bossCtx();
    const ba  = gameState.laptopBoss.bossAudio;
    if (ba.weakIdleTimer) { clearTimeout(ba.weakIdleTimer); ba.weakIdleTimer = null; }
    if (!ba.weakIdleSource) return;
    const src  = ba.weakIdleSource;
    const gain = ba.weakIdleGain;
    ba.weakIdleSource = null;
    ba.weakIdleGain   = null;
    try {
        if (fadeMs > 0 && ctx) {
            gain.gain.cancelScheduledValues(ctx.currentTime);
            gain.gain.setValueAtTime(gain.gain.value, ctx.currentTime);
            gain.gain.linearRampToValueAtTime(0, ctx.currentTime + fadeMs / 1000);
            setTimeout(() => { try { src.stop(); } catch(e) {} }, fadeMs + 50);
        } else {
            src.stop();
        }
    } catch(e) {}
}

// Stop all boss audio (called on fight end / return to world)
function stopAllBossAudio() {
    stopBossApplause(1200);
    stopBossWeakIdle(400);
}

function startLocalLaptopBoss(session) {
    if (gameState.laptopBoss.active && gameState.laptopBoss.local) return;

    // Hide world UI; show our own mobile controls
    const _uc = document.getElementById('user-card');
    if (_uc) _uc.style.display = 'none';
    const _jy = document.getElementById('mobile-joystick');
    if (_jy) _jy.style.display = 'none';
    setMinigameHideUI(true);
    showMobileBossButtons(true);

    const participant = session.participants?.[gameState.userId] || {};
    gameState.laptopBoss.active        = true;
    gameState.laptopBoss.returnPoint   = participant.returnPoint || null;

    const canvas = gameState.canvas;
    const dpr = gameState.dpr || 1;
    const W = canvas ? canvas.width / dpr : window.innerWidth;
    const H = canvas ? canvas.height / dpr : window.innerHeight;
    const groundY = H * 0.84;

    // Reduce particle counts on mobile for weaker devices
    const lowEnd = isMobile();
    const auraCount = lowEnd ? 14 : 22;
    const windCount = lowEnd ? 10 : 20;

    gameState.laptopBoss.local = {
        // Player
        player: {
            x: W * 0.82, y: groundY - 36,
            vx: 0, vy: 0,
            w: 72, h: 72,
            onGround: true,
            coyoteT: 0,
            jumpHoldT: 0,
            jumping: false,
            invulnT: 0,
            flashRedT: 0,
            flashWhiteT: 0,
            squashT: 1,
            health: PLAYER_BOSS_MAX_HEALTH,
            dead: false,
            fallDoneT: 0,
        },
        // Boss
        boss: {
            x: W * 0.22, y: H * 0.42,
            baseY: H * 0.42,
            floatT: 0,
            state: 'intro',         // intro → idle → grab/attack → weak → ...
            stateT: 0,
            stateDur: 1.0,
            attackCount: 0,         // number of grab/attack since last weak (resets to 0 after weak)
            scoopStartX: 0, scoopStartY: 0,
            scoopTargetX: 0, scoopTargetY: 0,
            scoopProgress: 0,
            grabTargetX: 0, grabTargetY: 0,    // locked at end of phase 1 of grab
            grabPullStartT: 0,                  // time at which pull started
            grabHitFired: false,
            attackHitFired: false,
            scale: 1,
            scaleTarget: 1,
            health: BOSS_MAX_HEALTH,
            flashWhiteT: 0,
            knockbackX: 0, knockbackY: 0,
            recoveryFromX: 0, recoveryFromY: 0,
            motionTrail: [],        // {x,y,t} for motion blur
            endFallVy: 0,
            offScreen: false,
            attacksThisCycle: 0,    // 0..3 then weak
            shieldAlpha: 0.10,      // rendered over boss when NOT in weak state
            shieldScale: 1.0,       // animates up on weak entry, down on exit
            reboundVX: 0, reboundVY: 0, // physics velocity during rebound
            _trailTimer: 0,
        },
        // World
        groundY,
        W, H,
        // FX
        particles: [],
        floatTexts: [],
        screenShakeX: 0, screenShakeY: 0, shakeT: 0, shakeAmp: 0,
        aura: Array.from({ length: auraCount }, (_, i) => ({
            angle: (Math.PI * 2 * i) / auraCount,
            speed: 0.0009 + Math.random() * 0.0006,
            r: 70 + Math.random() * 18,
            phase: Math.random() * Math.PI * 2,
        })),
        windParticles: Array.from({ length: windCount }, () => ({
            x: Math.random() * W,
            y: Math.random() * H,
            vx: -(0.4 + Math.random() * 0.9),
            size: 1 + Math.floor(Math.random() * 2),
            len: 4 + Math.floor(Math.random() * 5),
            alpha: 0.08 + Math.random() * 0.18,
        })),
        // Weak-state stepping platform (one-way, jumps through from below)
        stair: { alpha: 0, x: 0, y: 0, w: 170, h: 14 },
        // Avatar image
        avatarImg: gameState.avatarCache[gameState.userId] || null,
        groundImpact: null, // { x, t, maxT } shockwave ring
        outcome: null, // 'win' | 'lose' | null
        outcomeT: 0,
        startedAt: Date.now(),
        introT: 0,
        // Touch input ids
        _touchLeftId: null,
        _touchRightId: null,
        _touchJumpId: null,
    };

    setupBossKeyHandlers();
    setupBossTouchHandlers();

    // Start fight applause (fades in over 1.5 s)
    startBossApplause(1500);

    // Siraj ghost cleanup
    if (gameState.isSirajGhost && gameState.laptopBoss.sessionKey) {
        const cleanupPath = lobbyPath(`minigames/laptop-boss/sessions/${gameState.laptopBoss.sessionKey}`);
        onDisconnect(ref(database, cleanupPath)).remove();
        if (gameState.laptopBoss._sirajCleanupTimer) clearTimeout(gameState.laptopBoss._sirajCleanupTimer);
        gameState.laptopBoss._sirajCleanupTimer = setTimeout(() => {
            update(ref(database), { [cleanupPath]: null });
            gameState.laptopBoss._sirajCleanupTimer = null;
        }, 90000);
    }

    // Mark player as "working" so others see them as busy
    update(ref(database), { [`users/${gameState.userId}/isWorking`]: true });
}

function setupBossKeyHandlers() {
    if (gameState.laptopBoss._keyDownHandler) return;
    gameState.laptopBoss._keyDownHandler = (e) => {
        if (!gameState.laptopBoss.active) return;
        if (e.code === 'Space' || e.code === 'ArrowUp' || e.code === 'KeyW') {
            e.preventDefault();
            // `e.repeat` guard: held keys auto-repeat ~30×/sec, and each repeat would
            // re-arm the jump buffer — so holding the key would re-jump the instant
            // the player touched down, forever.
            if (e.repeat) return;
            gameState.laptopBossButtons.jump = true;
            gameState.laptopBossButtons.jumpPressed = true;
        }
    };
    gameState.laptopBoss._keyUpHandler = (e) => {
        if (e.code === 'Space' || e.code === 'ArrowUp' || e.code === 'KeyW') {
            gameState.laptopBossButtons.jump = false;
        }
    };
    window.addEventListener('keydown', gameState.laptopBoss._keyDownHandler);
    window.addEventListener('keyup', gameState.laptopBoss._keyUpHandler);
}

function setupBossTouchHandlers() {
    // Wired once in initMobileControls()
}

function showMobileBossButtons(show) {
    const dpad = document.getElementById('mobile-boss-btns');
    const joystick = document.getElementById('mobile-joystick');
    if (dpad) dpad.classList.toggle('hidden', !show);
    if (joystick && isMobile()) joystick.style.display = show ? 'none' : '';
    if (!show) {
        gameState.laptopBossButtons.left = false;
        gameState.laptopBossButtons.right = false;
        gameState.laptopBossButtons.jump = false;
        gameState.laptopBossButtons.jumpPressed = false;
        gameState.laptopBossButtons.jumpBufferT = 0;
        document.querySelectorAll('.boss-btn.pressed').forEach(b => b.classList.remove('pressed'));
    }
}

function returnFromLaptopBoss(clearState) {
    stopAllBossAudio();
    if (gameState.laptopBoss._sirajCleanupTimer) {
        clearTimeout(gameState.laptopBoss._sirajCleanupTimer);
        gameState.laptopBoss._sirajCleanupTimer = null;
    }
    if (gameState.laptopBoss._keyDownHandler) {
        window.removeEventListener('keydown', gameState.laptopBoss._keyDownHandler);
        gameState.laptopBoss._keyDownHandler = null;
    }
    if (gameState.laptopBoss._keyUpHandler) {
        window.removeEventListener('keyup', gameState.laptopBoss._keyUpHandler);
        gameState.laptopBoss._keyUpHandler = null;
    }
    // Restore world UI
    const _uc = document.getElementById('user-card');
    if (_uc) _uc.style.display = '';
    const _jy = document.getElementById('mobile-joystick');
    if (_jy) _jy.style.display = '';
    setMinigameHideUI(false);
    showMobileBossButtons(false);

    const sessionKeyToDelete = gameState.laptopBoss.sessionKey;
    if (sessionKeyToDelete) {
        update(ref(database), { [lobbyPath(`minigames/laptop-boss/sessions/${sessionKeyToDelete}`)]: null });
    }

    const player = gameState.players[gameState.userId];
    const returnPoint = gameState.laptopBoss.returnPoint;
    if (player && returnPoint) {
        teleportEntity(player, returnPoint.x, returnPoint.y);
        updatePlayerPosition(returnPoint.x, returnPoint.y);
    }
    gameState.laptopBoss.active = false;
    gameState.laptopBoss.local = null;
    gameState.laptopBoss.session = null;
    gameState.laptopBoss.sessionKey = null;
    gameState.laptopBoss.showResultsInGame = false;
    gameState.laptopBoss.resultsButtonRect = null;
    if (gameState.userId) update(ref(database), { [`users/${gameState.userId}/isWorking`]: false });
}

// ─── Boss game tick ───────────────────────────────────────────────────────────

// Jump tuning. The old numbers were floaty because the hold boost (-0.62) almost
// exactly cancelled gravity (0.6): holding jump left a NET accel of -0.02, so the
// player coasted upward at a near-constant 15.5px/frame for 12 frames before
// gravity took over — a hang in mid-air, not an arc. These keep the jump's HEIGHT
// (~365px full, ~220px short-hop — the boss's hitbox is tuned against it) but cut
// the airtime from ~1.25s to ~0.9s: a stronger kick off the ground, real
// deceleration during the hold, and a heavier fall than rise (the standard
// platformer asymmetry — a floaty descent is what actually reads as "floaty").
const BOSS_GRAVITY = 0.95;                // per-frame at 60fps; multiplied by dtFactor
const BOSS_JUMP_VEL = -20.5;             // initial jump velocity
const BOSS_JUMP_HOLD_BOOST = -0.55;      // extra upward accel while holding jump (net 0.40 up)
const BOSS_JUMP_HOLD_MAX = 14;           // frames of hold boost
const BOSS_FALL_GRAVITY_MULT = 1.3;      // descent is heavier than the rise
const BOSS_VY_MAX = 22;                  // terminal fall speed
const BOSS_MOVE_ACCEL = 2.2;
const BOSS_MOVE_MAX = 7.5;
const BOSS_MOVE_FRICTION = 0.80;
const BOSS_COYOTE_MAX = 8;
// Frames a jump press stays live waiting for the ground. Without it, a press
// landing a frame or two before touchdown was silently eaten — on a phone (where
// you can't feel the landing) that read as "the button didn't work".
const BOSS_JUMP_BUFFER = 8;

function bossSpawnParticles(local, x, y, count, opts = {}) {
    const color = opts.color || 'rgba(220,180,255,0.9)';
    const speed = opts.speed || 4;
    const life = opts.life || 30;
    const size = opts.size || 4;
    for (let i = 0; i < count; i++) {
        const angle = (Math.PI * 2 * i / count) + (Math.random() - 0.5) * 0.6;
        const sp = speed * (0.6 + Math.random() * 0.8);
        local.particles.push({
            x, y, vx: Math.cos(angle) * sp, vy: Math.sin(angle) * sp,
            life, maxLife: life, color, size,
        });
    }
}

function bossAddShake(local, amp) {
    local.shakeAmp = Math.max(local.shakeAmp || 0, amp);
    local.shakeT = 10;
}

function bossFloatText(local, x, y, text, color) {
    local.floatTexts.push({ x, y, text, color: color || '#ff4d6d', life: 60, maxLife: 60, vy: -1.2 });
}

function bossSetState(boss, state, dur) {
    boss.state = state;
    boss.stateT = 0;
    boss.stateDur = dur;
}

function updateLaptopBoss() {
    const local = gameState.laptopBoss.local;
    if (!local) return;
    const dt = Math.min(2, gameState.dtFactor || 1);
    const session = gameState.laptopBoss.session;

    // Hard exit if break ends mid-fight
    if (!isBreakActive()) {
        if (session && session.hostId === gameState.userId) {
            update(ref(database), { [lobbyPath(`minigames/laptop-boss/sessions/${gameState.laptopBoss.sessionKey}`)]: null });
        }
        returnFromLaptopBoss(false);
        return;
    }

    // Prayer overlay or azkar steal priority — pause boss
    if (gameState.prayer?.isOverlayActive || gameState.azkar?.active) {
        // freeze updates
        return;
    }

    const player = local.player;
    const boss = local.boss;

    // ── Input ────────────────────────────────────────────────────────────────
    const k = gameState.keys || {};
    const leftHeld  = !!(k['ArrowLeft']  || k['KeyA'] || gameState.laptopBossButtons.left);
    const rightHeld = !!(k['ArrowRight'] || k['KeyD'] || gameState.laptopBossButtons.right);
    const jumpHeld  = !!(k['Space'] || k['ArrowUp'] || k['KeyW'] || gameState.laptopBossButtons.jump);

    // ── Player physics ───────────────────────────────────────────────────────
    if (!player.dead && !boss.grabbedPlayer) {
        // Horizontal
        if (leftHeld && !rightHeld) player.vx -= BOSS_MOVE_ACCEL * dt;
        else if (rightHeld && !leftHeld) player.vx += BOSS_MOVE_ACCEL * dt;
        else {
            // Friction when no input
            player.vx *= Math.pow(BOSS_MOVE_FRICTION, dt);
            if (Math.abs(player.vx) < 0.05) player.vx = 0;
        }
        player.vx = Math.max(-BOSS_MOVE_MAX, Math.min(BOSS_MOVE_MAX, player.vx));

        // Coyote tracking
        if (player.onGround) player.coyoteT = BOSS_COYOTE_MAX;
        else player.coyoteT = Math.max(0, player.coyoteT - dt);

        // Jump. A press opens a short buffer rather than being tested against the
        // ground on the one frame it arrived (see BOSS_JUMP_BUFFER).
        const btns = gameState.laptopBossButtons;
        if (btns.jumpPressed) { btns.jumpBufferT = BOSS_JUMP_BUFFER; btns.jumpPressed = false; }
        if (btns.jumpBufferT > 0 && (player.onGround || player.coyoteT > 0)) {
            player.vy = BOSS_JUMP_VEL;
            player.onGround = false;
            player.jumping = true;
            player.jumpHoldT = BOSS_JUMP_HOLD_MAX;
            player.coyoteT = 0;
            btns.jumpBufferT = 0;
            // Squash for jump anim
            player.squashT = 0.5;
            // Tiny dust
            bossSpawnParticles(local, player.x, player.y + player.h / 2, 4, { color: 'rgba(160,160,180,0.6)', speed: 1.5, life: 18, size: 3 });
        } else {
            btns.jumpBufferT = Math.max(0, (btns.jumpBufferT || 0) - dt);
        }

        // Variable jump height
        if (player.jumping && jumpHeld && player.jumpHoldT > 0 && player.vy < 0) {
            player.vy += BOSS_JUMP_HOLD_BOOST * dt;
            player.jumpHoldT -= dt;
        } else if (!jumpHeld) {
            player.jumping = false;
            player.jumpHoldT = 0;
        }

        // Gravity — heavier on the way down than on the way up.
        player.vy += BOSS_GRAVITY * (player.vy > 0 ? BOSS_FALL_GRAVITY_MULT : 1) * dt;
        player.vy = Math.min(BOSS_VY_MAX, player.vy);

        // Integrate
        player.x += player.vx * dt;
        player.y += player.vy * dt;

        // Bounds (world walls)
        const halfW = player.w / 2;
        if (player.x < halfW) { player.x = halfW; player.vx = 0; }
        if (player.x > local.W - halfW) { player.x = local.W - halfW; player.vx = 0; }

        // Ground collision (offset +10 so player sits flush with visual floor)
        const feetY = player.y + player.h / 2;
        const groundSnap = local.groundY + 10;
        if (feetY >= groundSnap) {
            player.y = groundSnap - player.h / 2;
            const wasFalling = player.vy > 4;
            player.vy = 0;
            if (!player.onGround && wasFalling) {
                bossSpawnParticles(local, player.x, groundSnap, 5, { color: 'rgba(140,140,160,0.55)', speed: 2, life: 18, size: 3 });
                player.squashT = 0.5;
            }
            player.onGround = true;
            player.jumping = false;
            player.jumpHoldT = 0;
        } else {
            // One-way stair platform: land only when falling down onto top face
            const stair = local.stair;
            const prevFeetY = feetY - player.vy * dt;
            if (stair.alpha > 0.1 && player.vy > 0 &&
                prevFeetY <= stair.y && feetY >= stair.y &&
                player.x + player.w / 2 > stair.x && player.x - player.w / 2 < stair.x + stair.w) {
                player.y = stair.y - player.h / 2;
                player.vy = 0;
                if (!player.onGround) {
                    bossSpawnParticles(local, player.x, stair.y, 5, { color: 'rgba(140,140,160,0.55)', speed: 2, life: 18, size: 3 });
                    player.squashT = 0.5;
                }
                player.onGround = true;
                player.jumping = false;
                player.jumpHoldT = 0;
            } else {
                player.onGround = false;
            }
        }
    } else {
        // Death fall — keep falling till offscreen
        player.vy += BOSS_GRAVITY * dt;
        player.y += player.vy * dt;
        if (player.y > local.H + 200 && !player.fallDoneT) {
            player.fallDoneT = Date.now();
            local.outcome = 'lose';
            local.outcomeT = 0;
        }
    }

    // Visual timers
    if (player.invulnT > 0) player.invulnT -= dt;
    if (player.flashRedT > 0) player.flashRedT -= dt;
    if (player.flashWhiteT > 0) player.flashWhiteT -= dt;
    player.squashT += (1 - player.squashT) * 0.16 * dt;

    // ── Boss AI ──────────────────────────────────────────────────────────────
    boss.floatT += dt / 60;
    boss.stateT += dt;

    // Float anim when not in motion states
    const floatingStates = ['intro', 'idle', 'grab_predict', 'grab_shoot', 'grab_hold', 'grab_release_kidnap', 'attack_anticipate', 'attack_return', 'weak'];
    if (floatingStates.includes(boss.state)) {
        boss.y = boss.baseY + Math.sin(boss.floatT * Math.PI) * 20;
    }

    // Scale ease toward target
    boss.scale += (boss.scaleTarget - boss.scale) * 0.12 * dt;
    if (boss.flashWhiteT > 0) boss.flashWhiteT -= dt;

    // State machine
    const startedActive = session && session.startTime && serverNow() >= session.startTime;

    if (boss.state === 'intro') {
        // Wait for startTime to elapse
        if (startedActive) {
            bossSetState(boss, 'idle', 90); // 1.5s @ 60fps
        }
    } else if (boss.state === 'idle') {
        if (boss.stateT >= boss.stateDur) {
            // If player is dead, just keep idling — finish current animation, don't attack
            if (player.dead) {
                bossSetState(boss, 'idle', 60 * 2);
            } else {
                // Pick next attack: grab or scoop
                boss.attacksThisCycle++;
                if (boss.attacksThisCycle > 3) {
                    // Go to weak
                    bossSetState(boss, 'weak', 60 * 3); // 3 s weak window
                    boss.attacksThisCycle = 0;
                    bossSpawnParticles(local, boss.x, boss.y, 14, { color: 'rgba(120,80,255,0.85)', speed: 5, life: 36, size: 4 });
                    // ♪ weak entry sounds
                    bossPlaySound('bossWeakInitiate');
                    startBossWeakIdle();
                } else {
                    const grabRoll = Math.random() < 0.5;
                    if (grabRoll) {
                        boss.grabHitFired = false;
                        bossSetState(boss, 'grab_predict', 60 * 1.2);  // 1.2s
                        bossPlaySound('bossAnticipate');  // anticipation starts
                    } else {
                        boss.scaleTarget = 1.15;
                        boss.attackHitFired = false;
                        bossSetState(boss, 'attack_anticipate', 60 * 0.8); // 0.8s
                        bossPlaySound('bossAnticipate');  // anticipation starts
                    }
                }
            }
        }
    } else if (boss.state === 'grab_predict') {
        if (boss.stateT >= boss.stateDur) {
            // Lock target at player's current position and shoot
            boss.grabTargetX = player.x;
            boss.grabTargetY = player.y;
            bossSetState(boss, 'grab_shoot', 60 * 0.35); // line extends over 0.35s
            bossPlaySound('bossGrabInitiate'); // grab sequence begins
        }
    } else if (boss.state === 'grab_shoot') {
        if (boss.stateT >= boss.stateDur) {
            // Check if player is still near the locked target
            const gdx = player.x - boss.grabTargetX;
            const gdy = player.y - boss.grabTargetY;
            if (Math.hypot(gdx, gdy) < 60 && player.invulnT <= 0 && !player.dead) {
                // Hit — start kidnap pull
                boss.grabbedPlayer = true;
                boss.grabPullStartX = player.x;
                boss.grabPullStartY = player.y;
                boss.grabDamageFired = false;
                bossSetState(boss, 'grab_pull', 60 * 0.45);
                bossPlaySound('bossGrabSuccess'); // grab connected
            } else {
                // Miss
                bossSetState(boss, 'idle', 60 * 1.5);
            }
        }
    } else if (boss.state === 'grab_pull') {
        // Smoothly pull player to front of boss — hold last attack frame throughout
        const pullP = Math.min(1, boss.stateT / boss.stateDur);
        const pullEased = 1 - Math.pow(1 - pullP, 2.5);
        const destX = boss.x + 95;
        const destY = boss.y;
        player.x = boss.grabPullStartX + (destX - boss.grabPullStartX) * pullEased;
        player.y = boss.grabPullStartY + (destY - boss.grabPullStartY) * pullEased;
        player.vx = 0; player.vy = 0; player.onGround = false;
        if (boss.stateT >= boss.stateDur) {
            bossSetState(boss, 'grab_hold', 60 * 0.5);
        }
    } else if (boss.state === 'grab_hold') {
        // Hold player in place — deal damage once after a short pause
        player.x = boss.x + 95;
        player.y = boss.y;
        player.vx = 0; player.vy = 0; player.onGround = false;
        if (!boss.grabDamageFired && boss.stateT >= 8) {
            boss.grabDamageFired = true;
            damagePlayer(local, player, boss, true /*fromGrab*/);
            // Override damagePlayer's knockback — player stays held
            player.vx = 0; player.vy = 0;
        }
        if (boss.stateT >= boss.stateDur) {
            // Release with knockback
            boss.grabbedPlayer = false;
            player.vx = 9; // flung right away from boss
            player.vy = -10;
            player.onGround = false;
            bossSetState(boss, 'grab_release_kidnap', 60 * 0.35);
        }
    } else if (boss.state === 'grab_release_kidnap') {
        if (boss.stateT >= boss.stateDur) {
            bossSetState(boss, 'idle', 60 * 1.5);
        }
    } else if (boss.state === 'attack_anticipate') {
        if (boss.stateT >= boss.stateDur) {
            // Anticipation done — fire attack
            boss.scoopStartX = boss.x;
            boss.scoopStartY = boss.y;
            boss.scoopTargetX = player.x;
            boss.scoopTargetY = local.groundY + 10 - 20; // boss center near ground
            boss.attackHitFired = false;
            boss.scaleTarget = 1.0;
            boss.motionTrail = [];
            boss._trailTimer = 0;
            bossSetState(boss, 'attack_stomp', 60 * 0.60);
            bossPlaySound('bossAttackInitiate'); // attack (not grab) launches
        }
    } else if (boss.state === 'attack_stomp') {
        const p = Math.min(1, boss.stateT / boss.stateDur);
        // Ease-in cubic for fast approach
        const ease = p < 0.5
            ? 4 * p * p * p
            : 1 - Math.pow(-2 * p + 2, 3) / 2;
        // Arc: X smooth, Y curves up slightly then slams down
        boss.x = boss.scoopStartX + (boss.scoopTargetX - boss.scoopStartX) * ease;
        boss.y = (boss.scoopStartY + (boss.scoopTargetY - boss.scoopStartY) * ease)
                 - Math.sin(p * Math.PI) * 60;

        // Motion trail — add position every 3 frames
        boss._trailTimer += dt;
        if (boss._trailTimer >= 3) {
            boss._trailTimer = 0;
            boss.motionTrail.unshift({ x: boss.x, y: boss.y, alpha: 0.55 });
            if (boss.motionTrail.length > 5) boss.motionTrail.pop();
        }

        // Damage player on contact during dive
        if (!boss.attackHitFired) {
            const ddx = player.x - boss.x;
            const ddy = player.y - boss.y;
            if (Math.hypot(ddx, ddy) < 70 && player.invulnT <= 0) {
                boss.attackHitFired = true;
                damagePlayer(local, player, boss, false /*fromStomp*/);
            }
        }

        if (boss.stateT >= boss.stateDur) {
            // GROUND IMPACT
            boss.x = boss.scoopTargetX;
            boss.y = boss.scoopTargetY;
            boss.motionTrail = [];
            bossAddShake(local, 16);
            boss.flashWhiteT = 22;
            bossSpawnParticles(local, boss.x, local.groundY + 10, 24, {
                color: 'rgba(255,255,180,0.95)', speed: 9, life: 38, size: 5
            });
            bossSpawnParticles(local, boss.x, local.groundY + 10, 10, {
                color: 'rgba(255,200,100,0.80)', speed: 5, life: 28, size: 3
            });
            local.groundImpact = { x: boss.x, t: 0, maxT: 36 };
            bossPlaySound('bossAttackStomp'); // ground slam
            bossSetState(boss, 'attack_impact', 60 * 0.32);
        }
    } else if (boss.state === 'attack_impact') {
        // Freeze boss at impact point while effects play
        boss.x = boss.scoopTargetX;
        boss.y = boss.scoopTargetY;
        if (boss.stateT >= boss.stateDur) {
            // Launch rebound — continues RIGHT (same direction as stomp) and upward off-screen
            boss.reboundVX = 20;
            boss.reboundVY = -15;
            boss._trailTimer = 0;
            bossSetState(boss, 'attack_rebound', 9999);
        }
    } else if (boss.state === 'attack_rebound') {
        // Physics-driven bounce off screen
        boss.reboundVY += 0.38 * dt;
        boss.x += boss.reboundVX * dt;
        boss.y += boss.reboundVY * dt;

        // Trail during rebound
        boss._trailTimer += dt;
        if (boss._trailTimer >= 3) {
            boss._trailTimer = 0;
            boss.motionTrail.unshift({ x: boss.x, y: boss.y, alpha: 0.45 });
            if (boss.motionTrail.length > 5) boss.motionTrail.pop();
        }

        // Once fully off-screen right, instant-snap to off-screen left, then return
        if (boss.x > local.W + 200) {
            boss.motionTrail = [];
            // One-frame snap to off-screen LEFT — no transition
            boss.x = -180;
            boss.y = local.H * 0.42;
            bossSetState(boss, 'attack_return', 60 * 0.75);
        }
    } else if (boss.state === 'attack_return') {
        const p = Math.min(1, boss.stateT / boss.stateDur);
        const eased = 1 - Math.pow(1 - p, 3);
        boss.x = -180 + (local.W * 0.22 - (-180)) * eased;
        boss.y = local.H * 0.42;
        boss.baseY = local.H * 0.42;
        if (boss.stateT >= boss.stateDur) {
            boss.x = local.W * 0.22;
            bossSetState(boss, 'idle', 60 * 1.5);
        }
    } else if (boss.state === 'weak') {
        // Decay trail
        boss.motionTrail = [];
        // Check player collision with boss
        if (player.invulnT <= 0) {
            const ddx = player.x - boss.x;
            const ddy = player.y - boss.y;
            if (Math.hypot(ddx, ddy) < 60) {
                // Player hits boss
                boss.health -= 1;
                boss.flashWhiteT = 12;
                player.flashWhiteT = 12;
                player.invulnT = 18;
                // Knockback boss slightly
                boss.x += 20 * (player.x < boss.x ? 1 : -1);
                bossSpawnParticles(local, boss.x, boss.y, 12, { color: 'rgba(255,255,255,0.95)', speed: 6, life: 30, size: 4 });
                bossAddShake(local, 6);
                bossFloatText(local, boss.x, boss.y - 40, '-1 HP', '#ff4d6d');
                // Bounce player up
                player.vy = -10;
                player.onGround = false;

                if (boss.health <= 0) {
                    // ♪ player wins — kill boss; fade out applause (don't duck-and-recover)
                    bossPlaySound('playerWinBoss');
                    bossPlaySound('crowdCheer');
                    stopBossApplause(2500);
                    stopBossWeakIdle(300);
                    bossSetState(boss, 'end', 9999);
                    boss.endFallVy = 0;
                } else {
                    // ♪ boss takes a hit but survives — wakes up
                    bossPlaySound('bossHit');
                    bossDuckApplause('crowdCheer');
                    stopBossWeakIdle(200);
                    bossSetState(boss, 'idle', 60 * 1.5);
                }
            }
        }
        // Time window expired — boss recovers on its own
        if (boss.state === 'weak' && boss.stateT >= boss.stateDur) {
            bossPlaySound('bossWeakEnd');
            stopBossWeakIdle(400);
            bossSetState(boss, 'idle', 60 * 1.5);
        }
    } else if (boss.state === 'end') {
        // Drop straight down
        boss.endFallVy += 0.3 * dt;
        boss.endFallVy = Math.min(8, boss.endFallVy);
        boss.y += boss.endFallVy * dt;
        if (boss.y > local.H + 200 && !boss.offScreen) {
            boss.offScreen = true;
            local.outcome = 'win';
            local.outcomeT = 0;
            // Dashboard high score: laptop game is best-by-lowest-time (fires once per win).
            if (gameState.laptopBoss.session?.startTime) {
                dashRecordGameOnce('laptop', gameState.laptopBoss.sessionKey, serverNow() - gameState.laptopBoss.session.startTime);
            }
            bossSpawnParticles(local, boss.x, local.groundY, 18, { color: 'rgba(220,180,255,0.95)', speed: 7, life: 40, size: 5 });
            bossAddShake(local, 10);
        }
        // Sparkle particles
        if (Math.random() < 0.4) {
            bossSpawnParticles(local, boss.x + (Math.random() - 0.5) * 60, boss.y, 1, { color: 'rgba(220,180,255,0.7)', speed: 1.4, life: 24, size: 3 });
        }
    }

    // ── Shield alpha/scale (visible when not weak, animates on transition) ──
    const isWeak = boss.state === 'weak' || boss.state === 'end';
    const shieldAlphaTarget = isWeak ? 0 : 0.10;
    const shieldScaleTarget = isWeak ? 1.35 : 1.0;
    boss.shieldAlpha += (shieldAlphaTarget - boss.shieldAlpha) * 0.10 * dt;
    boss.shieldScale += (shieldScaleTarget - boss.shieldScale) * 0.10 * dt;
    if (boss.shieldAlpha < 0.002) boss.shieldAlpha = 0;

    // ── Stair alpha (fade in during weak, fade out otherwise) ────────────────
    const stair = local.stair;
    stair.x = local.W * 0.40 - stair.w / 2;
    stair.y = local.groundY - 165;
    const stairTarget = (boss.state === 'weak') ? 1 : 0;
    stair.alpha += (stairTarget - stair.alpha) * 0.08 * dt;
    if (stair.alpha < 0.01) stair.alpha = 0;
    // If player was standing on stair and stair fades out, drop them
    if (stair.alpha < 0.1 && player.onGround) {
        const feetY2 = player.y + player.h / 2;
        if (Math.abs(feetY2 - stair.y) < 4) player.onGround = false;
    }

    // ── Ground impact timer (advances every frame, cleared when expired) ──────
    if (local.groundImpact) {
        local.groundImpact.t += dt;
        if (local.groundImpact.t >= local.groundImpact.maxT) local.groundImpact = null;
    }

    // ── Particles tick ──────────────────────────────────────────────────────
    local.particles = local.particles.filter(p => {
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        p.vy += 0.15 * dt;
        p.life -= dt;
        return p.life > 0;
    });

    // Float texts
    local.floatTexts = local.floatTexts.filter(t => {
        t.y += t.vy * dt;
        t.life -= dt;
        return t.life > 0;
    });

    // Wind particles
    local.windParticles.forEach(wp => {
        wp.x += wp.vx * dt;
        if (wp.x < -20) { wp.x = local.W + 20; wp.y = Math.random() * local.H; }
    });

    // Aura update — handled in render via boss state
    local.aura.forEach(a => a.phase += a.speed * 1000 * dt);

    // Shake decay
    if (local.shakeT > 0) {
        local.shakeT -= dt;
        const amp = local.shakeAmp * (local.shakeT / 10);
        local.screenShakeX = (Math.random() - 0.5) * 2 * amp;
        local.screenShakeY = (Math.random() - 0.5) * 2 * amp * 0.6;
        if (local.shakeT <= 0) { local.screenShakeX = 0; local.screenShakeY = 0; local.shakeAmp = 0; }
    } else {
        local.screenShakeX = 0; local.screenShakeY = 0;
    }

    // Outcome handling
    if (local.outcome && session && session.phase === 'active') {
        local.outcomeT += dt;
        if (local.outcomeT > 60 * 0.8) {
            update(ref(database), { [laptopBossSessionPath('phase')]: 'finished' });
        }
    }
}

function damagePlayer(local, player, boss, fromGrab = false) {
    if (player.invulnT > 0 || player.dead) return;
    player.health -= 1;
    player.flashRedT = 14;
    player.invulnT = 60; // 1s invuln
    // Knockback away from boss
    const dir = player.x < boss.x ? -1 : 1;
    player.vx = dir * 7;
    player.vy = -8;
    player.onGround = false;
    bossSpawnParticles(local, player.x, player.y, 8, { color: 'rgba(255,80,80,0.85)', speed: 4, life: 28, size: 4 });
    bossAddShake(local, 5);
    bossFloatText(local, player.x, player.y - 30, '-1', '#ff4d6d');
    if (player.health <= 0) {
        player.dead = true;
        player.vy = -10;
        // ♪ player loses
        bossPlaySound('playerLooseBoss');
        bossDuckApplause('crowdShock');
        stopBossApplause(1400);
    } else {
        // ♪ player takes damage (not from grab, not final hit)
        if (!fromGrab) {
            bossPlaySound('playerHitBoss');
        }
        bossDuckApplause('crowdShock');
    }
}

// ─── Boss render ──────────────────────────────────────────────────────────────

// Draws `img` covering a W×H box with no stretch — crops the overflow, like CSS
// `background-size: cover`. The boss art is a fixed 3200×1800 (16:9); a portrait
// mobile canvas would otherwise squash it to fit.
function _bossDrawCover(ctx, img, W, H) {
    const ir = img.naturalWidth / img.naturalHeight;
    const cr = W / H;
    let sx, sy, sw, sh;
    if (ir > cr) {
        sh = img.naturalHeight;
        sw = sh * cr;
        sx = (img.naturalWidth - sw) / 2;
        sy = 0;
    } else {
        sw = img.naturalWidth;
        sh = sw / cr;
        sx = 0;
        sy = (img.naturalHeight - sh) / 2;
    }
    ctx.drawImage(img, sx, sy, sw, sh, 0, 0, W, H);
}

function renderLaptopBoss() {
    const ctx = gameState.ctx;
    const canvas = gameState.canvas;
    const local = gameState.laptopBoss.local;
    const session = gameState.laptopBoss.session;
    if (!ctx || !canvas) return;

    // Defensive reset — clears any leaked canvas state from previous frames
    ctx.globalAlpha = 1;
    ctx.globalCompositeOperation = 'source-over';
    ctx.filter = 'none';
    ctx.setLineDash([]);

    const dpr = gameState.dpr || 1;
    const W = canvas.width / dpr;
    const H = canvas.height / dpr;

    // Update local W/H if window changed
    if (local && (local.W !== W || local.H !== H)) {
        // Recalc groundY proportionally
        local.W = W; local.H = H;
        local.groundY = H * 0.84;
        // Snap player to new ground if was on ground
        if (local.player && local.player.onGround) {
            local.player.y = local.groundY - local.player.h / 2;
        }
        if (local.boss) {
            local.boss.baseY = H * 0.42;
        }
        // Stair position is recomputed each frame in update, so no action needed
    }

    ctx.save();
    ctx.scale(dpr, dpr);
    ctx.imageSmoothingEnabled = false;

    // Background — fallback gradient if image not loaded
    const bgImg = gameState.assets.bossBg;
    if (bgImg && bgImg.complete && bgImg.naturalWidth) {
        _bossDrawCover(ctx, bgImg, W, H);
    } else {
        const g = ctx.createLinearGradient(0, 0, 0, H);
        g.addColorStop(0, '#1a0f2e');
        g.addColorStop(1, '#0a0617');
        ctx.fillStyle = g;
        ctx.fillRect(0, 0, W, H);
    }

    if (!local) {
        // No local state — just darken (teleport hold)
        ctx.restore();
        // Apply teleport overlay if active
        ctx.save();
        ctx.scale(dpr, dpr);
        drawTeleportOverlay(W, H);
        drawMinigameLoadFade(W, H);
        ctx.restore();
        return;
    }

    const player = local.player;
    const boss = local.boss;

    // Screen shake transform
    ctx.save();
    ctx.translate(local.screenShakeX, local.screenShakeY);

    // Wind particles (background polish)
    ctx.save();
    local.windParticles.forEach(wp => {
        ctx.fillStyle = `rgba(220,220,255,${wp.alpha})`;
        ctx.fillRect(wp.x, wp.y, wp.len, wp.size);
    });
    ctx.restore();

    // Ground image
    const groundImg = gameState.assets.bossGround;
    if (groundImg && groundImg.complete && groundImg.naturalWidth) {
        _bossDrawCover(ctx, groundImg, W, H);
    } else {
        ctx.fillStyle = '#3a2d1c';
        ctx.fillRect(0, local.groundY, W, H - local.groundY);
    }

    // Stepping platform (weak state only, fades in/out) — pixel-art yellow
    if (local.stair.alpha > 0.01) {
        const st = local.stair;
        ctx.save();
        ctx.globalAlpha = st.alpha;
        ctx.imageSmoothingEnabled = false;
        // Dark shadow band underneath
        ctx.fillStyle = '#5a3e00';
        ctx.fillRect(st.x, st.y + st.h, st.w, 4);
        // Main platform body — bright gold
        ctx.fillStyle = '#f5c400';
        ctx.fillRect(st.x, st.y, st.w, st.h);
        // Dark shading bottom 3px
        ctx.fillStyle = '#b88f00';
        ctx.fillRect(st.x, st.y + st.h - 3, st.w, 3);
        // Pixel-art checkerboard highlight on top row
        const tileW = 8;
        for (let tx = st.x; tx < st.x + st.w; tx += tileW * 2) {
            ctx.fillStyle = '#ffe066';
            ctx.fillRect(tx, st.y, tileW, 3);
        }
        ctx.restore();
    }

    // Aura around boss (skip during weak/end)
    if (boss.state !== 'weak' && boss.state !== 'end') {
        local.aura.forEach(a => {
            const ax = boss.x + Math.cos(a.phase) * a.r;
            const ay = boss.y + Math.sin(a.phase) * a.r * 0.7;
            const alpha = 0.35 + Math.sin(a.phase * 1.5) * 0.18;
            ctx.fillStyle = `rgba(190,140,255,${alpha})`;
            ctx.beginPath();
            ctx.arc(ax, ay, 3, 0, Math.PI * 2);
            ctx.fill();
        });
    }

    // Grab target circle (predict phase)
    if (boss.state === 'grab_predict') {
        // Lock to player live during predict
        const p = boss.stateT / boss.stateDur;
        const pulse = 0.6 + Math.abs(Math.sin(p * Math.PI * 4)) * 0.4;
        ctx.save();
        ctx.strokeStyle = `rgba(0,0,0,${pulse})`;
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.arc(player.x, player.y, 40, 0, Math.PI * 2);
        ctx.stroke();
        ctx.restore();
    }

    // Grab line — shoot phase (extends from boss to locked target)
    if (boss.state === 'grab_shoot') {
        const lerpT = Math.min(1, (boss.stateT / boss.stateDur) * 2.5);
        ctx.save();
        ctx.strokeStyle = 'rgba(0,0,0,0.85)';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(boss.x, boss.y);
        ctx.lineTo(boss.x + (boss.grabTargetX - boss.x) * lerpT, boss.y + (boss.grabTargetY - boss.y) * lerpT);
        ctx.stroke();
        ctx.restore();
    }
    // Grab line — pull/hold phase (tether from boss to held player)
    if (boss.state === 'grab_pull' || boss.state === 'grab_hold') {
        ctx.save();
        ctx.strokeStyle = 'rgba(0,0,0,0.60)';
        ctx.lineWidth = 2;
        ctx.setLineDash([6, 4]);
        ctx.beginPath();
        ctx.moveTo(boss.x, boss.y);
        ctx.lineTo(player.x, player.y);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.restore();
    }

    // Ground impact shockwave ring
    if (local.groundImpact && local.groundImpact.t < local.groundImpact.maxT) {
        const gi = local.groundImpact;
        const ip = Math.max(0.01, gi.t / gi.maxT); // never 0 — avoids zero-radius ellipse crash
        const ir = ip * 140;
        const ia = (1 - ip) * 0.75;
        ctx.save();
        if (ir > 1) { // guard against sub-pixel radius
            ctx.strokeStyle = `rgba(255,240,140,${ia})`;
            ctx.lineWidth = 3 * (1 - ip) + 1;
            ctx.beginPath();
            ctx.ellipse(gi.x, local.groundY + 10, ir, Math.max(1, ir * 0.3), 0, Math.PI, 0);
            ctx.stroke();
        }
        // Inner ring slightly delayed
        if (ip > 0.15) {
            const ir2 = (ip - 0.15) / 0.85 * 80;
            const ia2 = (1 - ip) * 0.4;
            if (ir2 > 1) {
                ctx.strokeStyle = `rgba(255,200,80,${ia2})`;
                ctx.lineWidth = 2;
                ctx.beginPath();
                ctx.ellipse(gi.x, local.groundY + 10, ir2, Math.max(1, ir2 * 0.28), 0, Math.PI, 0);
                ctx.stroke();
            }
        }
        ctx.restore();
    }

    // Motion trail echoes — stomp dive and rebound
    if ((boss.state === 'attack_stomp' || boss.state === 'attack_rebound') && boss.motionTrail.length > 0) {
        boss.motionTrail.forEach((tr, i) => {
            if (tr.alpha > 0) drawBossSprite(ctx, boss, tr.x, tr.y, tr.alpha * 0.45);
            tr.alpha = Math.max(0, tr.alpha - 0.018);
        });
    }

    // Boss sprite
    drawBossSprite(ctx, boss, boss.x, boss.y, 1);

    // Shield overlay (over boss sprite, visible when NOT weak)
    const shieldImg = gameState.assets.bossShield;
    if (boss.shieldAlpha > 0.005 && shieldImg && shieldImg.complete && shieldImg.naturalWidth) {
        const sw = BOSS_FRAME_W * BOSS_SPRITE_SCALE * boss.shieldScale * 1.5;
        const sh = BOSS_FRAME_H * BOSS_SPRITE_SCALE * boss.shieldScale * 1.5;
        ctx.save();
        ctx.globalAlpha = boss.shieldAlpha;
        ctx.imageSmoothingEnabled = false;
        ctx.drawImage(shieldImg, boss.x - sw / 2, boss.y - sh / 2, sw, sh);
        ctx.restore();
    }

    // Boss hearts above boss
    drawBossHearts(ctx, boss.x, boss.y - 90, boss.health, BOSS_MAX_HEALTH, 1);

    // Weak-state time bar (below hearts, depletes over 3 s)
    if (boss.state === 'weak') {
        const barW = 80;
        const barH = 6;
        const barX = boss.x - barW / 2;
        const barY = boss.y - 90 + 38; // just below hearts row
        const pct  = Math.max(0, 1 - boss.stateT / boss.stateDur);
        // Background track
        ctx.save();
        ctx.fillStyle = 'rgba(0,0,0,0.55)';
        ctx.beginPath();
        if (ctx.roundRect) ctx.roundRect(barX - 1, barY - 1, barW + 2, barH + 2, 3);
        else ctx.rect(barX - 1, barY - 1, barW + 2, barH + 2);
        ctx.fill();
        // Fill — yellow → red as it drains
        const r = Math.round(255);
        const g = Math.round(220 * pct);
        ctx.fillStyle = `rgb(${r},${g},0)`;
        if (ctx.roundRect) {
            ctx.beginPath();
            ctx.roundRect(barX, barY, barW * pct, barH, 2);
            ctx.fill();
        } else {
            ctx.fillRect(barX, barY, barW * pct, barH);
        }
        ctx.restore();
    }

    // Player avatar
    if (!player.dead || player.y < local.H + 100) {
        drawPlayerAvatar(ctx, player, local);
    }

    // Player hearts above avatar (world space, moves with player)
    if (!player.dead || player.y < local.H + 100) {
        drawBossHearts(ctx, player.x, player.y - player.h / 2 - 36, player.health, PLAYER_BOSS_MAX_HEALTH, 0.8, false);
    }

    // Particles
    local.particles.forEach(p => {
        const a = Math.max(0, p.life / p.maxLife);
        ctx.fillStyle = p.color.replace(/[\d.]+\)$/, `${a.toFixed(2)})`);
        ctx.fillRect(p.x - p.size / 2, p.y - p.size / 2, p.size, p.size);
    });

    // Float texts
    local.floatTexts.forEach(t => {
        const a = t.life / t.maxLife;
        ctx.save();
        ctx.fillStyle = t.color;
        ctx.globalAlpha = a;
        ctx.font = 'bold 18px Rubik';
        ctx.textAlign = 'center';
        ctx.fillText(t.text, t.x, t.y);
        ctx.restore();
    });

    ctx.restore(); // shake

    // Foreground overlay — sits above EVERYTHING in the arena (background, ground,
    // boss and player), so it goes after the shake transform is popped but before the
    // countdown/results/teleport screens, which must stay readable on top of it.
    const overlayImg = gameState.assets.bossOverlay;
    if (overlayImg && overlayImg.complete && overlayImg.naturalWidth) {
        _bossDrawCover(ctx, overlayImg, W, H);
    }

    // Countdown overlay (if not yet started)
    if (session && session.startTime && serverNow() < session.startTime) {
        const remaining = Math.max(0, session.startTime - serverNow());
        const sec = Math.ceil(remaining / 1000);
        ctx.save();
        ctx.fillStyle = 'rgba(0,0,0,0.4)';
        ctx.fillRect(0, 0, W, H);
        ctx.fillStyle = '#fff';
        ctx.font = 'bold 90px Rubik';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(sec.toString(), W / 2, H / 2);
        ctx.font = 'bold 22px Rubik';
        ctx.fillText('استعد', W / 2, H / 2 + 70);
        ctx.restore();
    }

    // Outcome overlay (win/lose pre-results screen)
    if (local.outcome) {
        const a = Math.min(1, local.outcomeT / 30);
        ctx.save();
        ctx.fillStyle = `rgba(0,0,0,${0.55 * a})`;
        ctx.fillRect(0, 0, W, H);
        if (gameState.laptopBoss.showResultsInGame) {
            drawBossResultsPanel(ctx, W, H, local.outcome);
        }
        ctx.restore();
    } else if (gameState.laptopBoss.showResultsInGame && session?.phase === 'finished') {
        // Direct render of results panel (re-entered finished phase)
        ctx.save();
        ctx.fillStyle = 'rgba(0,0,0,0.55)';
        ctx.fillRect(0, 0, W, H);
        drawBossResultsPanel(ctx, W, H, local.outcome || 'win');
        ctx.restore();
    }

    // Teleport overlay (fade in/out)
    drawTeleportOverlay(W, H);
    drawMinigameLoadFade(W, H);

    ctx.restore(); // dpr
}

// The boss arena art is warm, so the laptop and the player get a light warm wash to
// sit in it. Baked ONCE per sheet into a cached canvas rather than a per-frame
// ctx.filter — live canvas filters take a slow path on mobile GPUs (same reason
// _tintedAvatar exists). Keyed off the <img>, so a sheet that hasn't decoded yet
// simply isn't tinted until it has.
const _BOSS_WARM = 'rgba(255,150,60,0.16)';
const _bossWarmCache = new WeakMap();
function _warmSheet(img) {
    if (!img || !img.complete || !img.naturalWidth) return null;
    const hit = _bossWarmCache.get(img);
    if (hit) return hit;
    try {
        const c = document.createElement('canvas');
        c.width = img.naturalWidth; c.height = img.naturalHeight;
        const cx = c.getContext('2d');
        cx.imageSmoothingEnabled = false;
        cx.drawImage(img, 0, 0);
        // source-atop → only the sprite's own pixels are tinted, not its padding.
        cx.globalCompositeOperation = 'source-atop';
        cx.fillStyle = _BOSS_WARM;
        cx.fillRect(0, 0, c.width, c.height);
        _bossWarmCache.set(img, c);
        return c;
    } catch (e) { return null; }
}

function drawBossSprite(ctx, boss, x, y, alpha) {
    let sheet = null;
    let frames = 0;
    let frameIdx = 0;
    if (boss.state === 'intro' || boss.state === 'idle') {
        sheet = gameState.assets.bossIdle;
        frames = BOSS_IDLE_FRAMES;
        frameIdx = Math.floor((boss.floatT * 600) / 100) % frames;
    } else if (boss.state === 'grab_predict' || boss.state === 'attack_anticipate') {
        sheet = gameState.assets.bossAnticipation;
        frames = BOSS_ANTICIPATION_FRAMES;
        // Play through 0..7 across the state's duration
        frameIdx = Math.min(frames - 1, Math.floor((boss.stateT / boss.stateDur) * frames));
    } else if (boss.state === 'grab_shoot' || boss.state === 'attack_stomp') {
        sheet = gameState.assets.bossAttack;
        frames = BOSS_ATTACK_FRAMES;
        frameIdx = Math.min(frames - 1, Math.floor((boss.stateT / boss.stateDur) * frames));
    } else if (boss.state === 'grab_pull' || boss.state === 'grab_hold' ||
               boss.state === 'attack_impact' || boss.state === 'attack_rebound') {
        // Hold last frame of attack sheet
        sheet = gameState.assets.bossAttack;
        frames = BOSS_ATTACK_FRAMES;
        frameIdx = frames - 1;
    } else if (boss.state === 'grab_release_kidnap' || boss.state === 'attack_return') {
        sheet = gameState.assets.bossIdle;
        frames = BOSS_IDLE_FRAMES;
        frameIdx = Math.floor((boss.floatT * 600) / 100) % frames;
    } else if (boss.state === 'weak' || boss.state === 'end') {
        sheet = gameState.assets.bossWeak;
        frames = BOSS_WEAK_FRAMES;
        if (boss.state === 'weak') {
            // Animate once, then hold
            frameIdx = Math.min(frames - 1, Math.floor(boss.stateT / 6));  // 100ms/frame at 60fps = 6 frames per sprite frame
        } else {
            frameIdx = frames - 1;
        }
    }

    if (!sheet || !sheet.complete || !sheet.naturalWidth) {
        // Fallback: solid purple box
        ctx.save();
        ctx.globalAlpha = alpha;
        ctx.fillStyle = '#7b4dff';
        const w = BOSS_FRAME_W * BOSS_SPRITE_SCALE;
        const h = BOSS_FRAME_H * BOSS_SPRITE_SCALE;
        ctx.fillRect(x - w / 2, y - h / 2, w, h);
        ctx.restore();
        return;
    }

    const sw = BOSS_FRAME_W;
    const sh = BOSS_FRAME_H;
    const dw = sw * BOSS_SPRITE_SCALE * (boss.scale || 1);
    const dh = sh * BOSS_SPRITE_SCALE * (boss.scale || 1);

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.imageSmoothingEnabled = false;
    if (boss.flashWhiteT > 0) {
        ctx.filter = 'brightness(2.5)';
    }
    ctx.drawImage(_warmSheet(sheet) || sheet, frameIdx * sw, 0, sw, sh, x - dw / 2, y - dh / 2, dw, dh);
    ctx.filter = 'none';
    ctx.restore();
}

function drawPlayerAvatar(ctx, player, local) {
    const r = player.w / 2;
    // Squash/stretch
    const sx = 1 + (1 - player.squashT) * 0.25;
    const sy = player.squashT;

    // Blink during invuln
    const blink = player.invulnT > 0 && Math.floor(player.invulnT / 4) % 2 === 0;
    if (blink) {
        // skip drawing for a flicker effect
        return;
    }

    ctx.save();
    ctx.translate(player.x, player.y);
    ctx.scale(sx, sy);
    // Avatar circle clip
    ctx.beginPath();
    ctx.arc(0, 0, r, 0, Math.PI * 2);
    ctx.clip();
    const av = gameState.avatarCache[gameState.userId];
    if (av && av !== 'failed' && av.complete) {
        ctx.imageSmoothingEnabled = true;
        ctx.drawImage(av, -r, -r, r * 2, r * 2);
    } else {
        ctx.fillStyle = COLORS.blue;
        ctx.fillRect(-r, -r, r * 2, r * 2);
    }
    // Warm wash, to match the arena art (and the same tint baked onto the laptop).
    // Free here — the avatar circle is already clipped, so this is one small fill.
    ctx.fillStyle = _BOSS_WARM;
    ctx.fillRect(-r, -r, r * 2, r * 2);
    // Flash overlays
    if (player.flashRedT > 0) {
        ctx.fillStyle = `rgba(255,40,40,${Math.min(1, player.flashRedT / 14)})`;
        ctx.fillRect(-r, -r, r * 2, r * 2);
    }
    if (player.flashWhiteT > 0) {
        ctx.fillStyle = `rgba(255,255,255,${Math.min(1, player.flashWhiteT / 14)})`;
        ctx.fillRect(-r, -r, r * 2, r * 2);
    }
    ctx.restore();

    // Outline ring
    ctx.save();
    ctx.beginPath();
    ctx.arc(player.x, player.y, r, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(255,255,255,0.55)';
    ctx.lineWidth = 2;
    ctx.stroke();
    ctx.restore();
}

function drawBossHearts(ctx, x, y, current, max, scale, leftAnchored) {
    const heartSize = 30 * (scale || 1);
    const gap = 6;
    const totalW = max * heartSize + (max - 1) * gap;
    const startX = leftAnchored ? x - heartSize / 2 : x - totalW / 2;
    const fullImg = gameState.assets.bossHeart;
    const deadImg = gameState.assets.bossHeartDead;
    ctx.save();
    ctx.imageSmoothingEnabled = false;
    for (let i = 0; i < max; i++) {
        const hx = startX + i * (heartSize + gap);
        const hy = y;
        const img = i < current ? fullImg : deadImg;
        if (img && img.complete && img.naturalWidth) {
            ctx.drawImage(img, hx, hy, heartSize, heartSize);
        } else {
            ctx.fillStyle = i < current ? '#ff4d6d' : '#444';
            ctx.fillRect(hx, hy, heartSize, heartSize);
        }
    }
    ctx.restore();
}

function drawBossResultsPanel(ctx, W, H, outcome) {
    const panelW = 360;
    const panelH = 220;
    const px = (W - panelW) / 2;
    const py = (H - panelH) / 2;
    ctx.save();
    ctx.fillStyle = 'rgba(20,12,32,0.94)';
    if (ctx.roundRect) {
        ctx.beginPath();
        ctx.roundRect(px, py, panelW, panelH, 18);
        ctx.fill();
    } else {
        ctx.fillRect(px, py, panelW, panelH);
    }
    ctx.strokeStyle = 'rgba(180,140,255,0.20)';
    ctx.lineWidth = 1;
    if (ctx.roundRect) {
        ctx.beginPath();
        ctx.roundRect(px, py, panelW, panelH, 18);
        ctx.stroke();
    }
    ctx.fillStyle = 'white';
    ctx.font = 'bold 36px Rubik';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(outcome === 'win' ? 'انتصرت!' : 'هزمت!', W / 2, py + 60);
    ctx.font = 'bold 18px Rubik';
    ctx.fillStyle = 'rgba(255,255,255,0.7)';
    ctx.fillText(outcome === 'win' ? 'لقد قضيت على الحاسوب' : 'حاول مرة أخرى', W / 2, py + 110);

    // Return button
    const btnW = 160, btnH = 48;
    const bx = px + (panelW - btnW) / 2;
    const by = py + panelH - btnH - 22;
    ctx.fillStyle = outcome === 'win' ? '#5b3aff' : '#553344';
    if (ctx.roundRect) {
        ctx.beginPath();
        ctx.roundRect(bx, by, btnW, btnH, 24);
        ctx.fill();
    } else {
        ctx.fillRect(bx, by, btnW, btnH);
    }
    ctx.fillStyle = 'white';
    ctx.font = 'bold 18px Rubik';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('عودة', bx + btnW / 2, by + btnH / 2);
    gameState.laptopBoss.resultsButtonRect = { x: bx, y: by, w: btnW, h: btnH };
    ctx.restore();
}

// ============================================================================
//  Personal Dashboard (لوحة المتابعة) — "paper stack" analytics + journal + to-dos
//  ------------------------------------------------------------------------
//  Open to ALL users: the map entry-circle + UI show for everyone (dashboardAllowed
//  now returns true). Each user reads/writes their OWN node. DATA TRACKING runs for
//  every real member too (dashSaveSession / dashRecordGameOnce).
//
//  COST NOTE (Spark plan): dashboard data lives at the top-level `dashboards/{uid}`
//  node, deliberately NOT under `users/`. The in-game `onValue('users')` listener
//  fires on every descendant change, so a dashboard write under users/{uid}/… would
//  re-stream the whole users node to every client. `dashboards/{uid}` is read with
//  one-shot get()s only — zero fan-out. Per-day journals + denormalized completed
//  tasks keep each read to a single small day node.
// ============================================================================
const DASH_TARGET_UID      = '567266235163738112';
const DASH_MIN_SESSION_MS  = 10 * 60 * 1000;       // sessions under 10 min are never saved
const DASH_LONG_FREE_MS    = 2 * 60 * 60 * 1000;   // free sessions over 2h trigger the idle-check
const DASH_MAX_TODOS       = 5;
const DASH_JOURNAL_MAX_WORDS = 100;
const DASH_JOURNAL_PLACEHOLDER = 'يوم مثمر، أنجزت أغلب ما خططت له والحمد لله.';
const DASH_SEED_VERSION    = 2;                    // bump to re-inject mock data

// World entry circle (dev-art placeholder) — left side of the freely-walkable work room.
const DASH_ZONE_X = -380, DASH_ZONE_Y = 0, DASH_ZONE_R = 56, DASH_ZONE_SELECT_R = 120;

let _dashFreeHandled = false;   // set by the >2h confirm flow so endFreeMode doesn't double-save
let _dashFreeOverrideMins = null;  // adjusted minutes from the >2h confirm → shown on the end card
let _dashFreeDiscarded = false;    // the >2h confirm "discard" choice → suppress the end card
let _dashJournalSaveTimer = null;
let _dashTodoSaveTimer = null;
let _dashState = { open: false, dayOffset: 0, side: 'main', animating: false, todos: [] };

// Scattered-stack slots. Active = bright front (centred); the rest are tinted,
// askew sheets behind it. z values keep them layered below the active sheet.
const DASH_ACTIVE_SLOT = { x: 0, y: 0, r: -0.6, z: 40, tint: false };
const DASH_BG_SLOTS = [
    { x: -17, y: 13, r: -4.8, z: 10, tint: true },
    { x: 19,  y: 8,  r: 4.2,  z: 20, tint: true },
    { x: -8,  y: -9, r: 2.6,  z: 30, tint: true },
];
let _dashSheets = [];          // sheet elements in #dash-main-stack
let _dashActiveSheet = null;   // the one currently holding #dash-day-paper content

function dashboardIsOpen() { return !!(_dashState && _dashState.open); }
// Paper UI sounds — via the Web Audio engine so they fire even in a background tab.
function dashSound(name) { try { gameState.focusAudioEngine?.playEffect(name); } catch (_) {} }
// Surface write failures instead of swallowing them (a PERMISSION_DENIED here means
// the Realtime Database rules don't allow the `dashboards` node — see database.rules.json).
function _dashErr(where) {
    return (e) => console.warn(`[dashboard] ${where} write failed:`, e && (e.code || e.message || e));
}

function dashboardAllowed() { return true; }   // open to ALL users (was: owner UID + Siraj only)
// Everyone — including a Siraj test ghost — reads/writes their OWN node. A Siraj ghost
// builds its own throwaway dashboard data that is removed from Firebase on disconnect
// (armed in setupDashboardUI), so it never inherits or pollutes the real owner's data.
function dashTrackingEnabled() { return !!gameState.userId; }
function dashViewUid()  { return gameState.userId; }
function dashReadOnly() { return false; }

// Firebase keys can't contain . # $ / [ ] — sanitise task names used as map keys.
function dashSlug(s) { return (s || '').replace(/[.#$/\[\]]/g, '_').slice(0, 64) || '_'; }

function pomoWorkedMsNow() {
    const p = gameState.pomodoro;
    return (p._workedMs || 0) + (p._workStartMs ? Date.now() - p._workStartMs : 0);
}
function freeWorkedMsNow() {
    const fm = gameState.freeMode;
    return fm.totalWorkMs + (fm.phase === 'work' && fm.workStartTime > 0 ? Date.now() - fm.workStartTime : 0);
}

// ── Saving a finished work session (pomodoro OR free) ───────────────────────
// Bouncy toast telling the user a just-ended session was too short to be saved (under the
// 10-minute floor) — so the missing session/end-card isn't confusing. Auto-hides after ~3.6s.
function showSessionNotSavedToast() {
    const el = document.getElementById('session-toast');
    if (!el) return;
    clearTimeout(el._hideT); clearTimeout(el._rmT);
    el.classList.remove('hide', 'show');
    void el.offsetWidth;            // restart the entrance animation if re-triggered
    el.classList.add('show');
    el._hideT = setTimeout(() => {
        el.classList.remove('show');
        el.classList.add('hide');
        el._rmT = setTimeout(() => el.classList.remove('hide'), 360);   // matches sessionToastOut
    }, 3600);
}

function dashSaveSession(mode, task, workedMs) {
    if (!dashTrackingEnabled()) return;
    if (!(workedMs >= DASH_MIN_SESSION_MS)) return;        // 10-minute floor
    const uid = gameState.userId;
    const finishMs = Date.now();
    const tsKey = String(finishMs);
    const dateKey = _todayDateStr();
    task = (task || '').trim();
    // Session log feeds the analytics (total hours / most-worked task / high scores).
    // The day paper's "المهام المنجزة" comes from the per-day TO-DO list, not from
    // sessions, so we no longer denormalise tasks under days/{date}.
    const rec = { mode, task: task || null, finishMs, durMs: workedMs };
    update(ref(database), { [`dashboards/${uid}/sessions/${tsKey}`]: rec }).catch(_dashErr('session'));
    dashBumpAnalytics(uid, task, workedMs);
}

// Read-modify-write the small aggregate doc (infrequent — only at session end).
function dashBumpAnalytics(uid, task, workedMs) {
    get(ref(database, `dashboards/${uid}/stats`)).then(snap => {
        const s = snap.val() || {};
        const updates = { [`dashboards/${uid}/stats/totalWorkMs`]: (s.totalWorkMs || 0) + workedMs };
        if (task) {
            const slug = dashSlug(task);
            const totals = s.taskTotals || {};
            const newMs = ((totals[slug] && totals[slug].ms) || 0) + workedMs;
            totals[slug] = { name: task, ms: newMs };
            updates[`dashboards/${uid}/stats/taskTotals/${slug}`] = totals[slug];
            let best = null;
            for (const k in totals) if (!best || totals[k].ms > best.ms) best = totals[k];
            if (best) updates[`dashboards/${uid}/stats/mostTask`] = { name: best.name, ms: best.ms };
        }
        update(ref(database), updates).catch(_dashErr('analytics'));
    }).catch(_dashErr('analytics-read'));
}

// ── Minigame high scores (fires once per session via an in-memory guard) ─────
// race + laptop: best = LOWEST time (ms). coffee: best = HIGHEST score.
function dashRecordGameOnce(game, sessionKey, value) {
    if (!dashTrackingEnabled() || value == null || sessionKey == null) return;
    gameState._dashGameKeys = gameState._dashGameKeys || new Set();
    const guard = `${game}:${sessionKey}`;
    if (gameState._dashGameKeys.has(guard)) return;
    gameState._dashGameKeys.add(guard);
    const uid = gameState.userId;
    const path = `dashboards/${uid}/stats/high/${game}`;
    get(ref(database, path)).then(snap => {
        const cur = snap.val();
        const better = cur == null || (game === 'coffee' ? value > cur : value < cur);
        if (better) update(ref(database), { [path]: value }).catch(_dashErr('highscore'));
    }).catch(_dashErr('highscore-read'));
}

// ── >2h free-mode idle-protection confirm modal ─────────────────────────────
function openFreeLongConfirmModal(elapsedMs) {
    const modal = document.getElementById('dash-longfree-modal');
    if (!modal) { endFreeMode(); return; }   // safety: never trap the user
    let h = Math.floor(elapsedMs / 3600000);
    let m = Math.round((elapsedMs % 3600000) / 60000);
    if (m === 60) { h++; m = 0; }
    const hBox = document.getElementById('dash-lf-hours');
    const mBox = document.getElementById('dash-lf-mins');
    const qEl  = document.getElementById('dash-lf-question');
    const sync = () => { hBox.textContent = h; mBox.textContent = String(m).padStart(2, '0');
        qEl.textContent = `هل عملت لمدة ${formatDurationArabic(h * 60 + m)} فعلًا؟`; };
    sync();
    modal._adj = (which, delta) => {
        if (which === 'h') h = Math.max(0, Math.min(23, h + delta));
        else { m += delta; if (m > 59) m = 0; if (m < 0) m = 59; }
        sync();
    };
    modal._confirm = () => {
        dashSaveSession('free', getCurrentTaskText(), (h * 60 + m) * 60000);
        _dashFreeHandled = true;
        _dashFreeOverrideMins = h * 60 + m;   // the end card should reflect the adjusted time
        modal.classList.remove('active');
        endFreeMode();
    };
    modal._discard = () => {
        _dashFreeHandled = true;   // discard: end the session WITHOUT saving to the dashboard
        _dashFreeDiscarded = true; // …and without the end card / sound
        modal.classList.remove('active');
        endFreeMode();
    };
    modal.classList.add('active');
}

// ── World entry-circle drawing + prompt ─────────────────────────────────────
function drawDashboardZone() {
    if (!dashboardAllowed()) return;
    const ctx = gameState.ctx;
    const t = Date.now() * 0.002;
    const pulse = 0.5 + 0.5 * Math.sin(t);
    ctx.save();
    ctx.translate(DASH_ZONE_X, DASH_ZONE_Y);
    // soft floor shadow
    ctx.fillStyle = 'rgba(0,0,0,0.22)';
    ctx.beginPath(); ctx.ellipse(0, DASH_ZONE_R * 0.62, DASH_ZONE_R * 0.9, DASH_ZONE_R * 0.34, 0, 0, Math.PI * 2); ctx.fill();
    // dev-art placeholder body: paper-toned disc
    ctx.fillStyle = '#efe4cc';
    ctx.beginPath(); ctx.arc(0, 0, DASH_ZONE_R, 0, Math.PI * 2); ctx.fill();
    ctx.lineWidth = 3;
    ctx.strokeStyle = `rgba(120,96,60,${0.55 + 0.25 * pulse})`;
    ctx.setLineDash([10, 8]);
    ctx.beginPath(); ctx.arc(0, 0, DASH_ZONE_R - 4, t, t + Math.PI * 2); ctx.stroke();
    ctx.setLineDash([]);
    // icon
    ctx.font = '40px serif';
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.fillText('📋', 0, 2);
    ctx.restore();
}

const _dashPrompt = { alpha: 0, pop: 0 };
function drawDashboardPrompt() {
    if (!dashboardAllowed()) return;
    const ctx = gameState.ctx;
    const show = !!gameState.activeDashboardZone && !gameState.isLockedIn && !gameState.anim.active
                 && !sessionBlocksInteraction();
    const lerp = 1 - Math.pow(1 - 0.22, gameState.dtFactor);
    _dashPrompt.alpha += ((show ? 1 : 0) - _dashPrompt.alpha) * lerp;
    _dashPrompt.pop   += ((show ? 1 : 0) - _dashPrompt.pop)   * lerp;
    if (_dashPrompt.alpha < 0.02) return;
    const a = _dashPrompt.alpha;
    const bob = Math.sin(Date.now() * 0.004) * 2.5;
    const pop = 0.82 + 0.18 * easeOutBack(Math.min(1, _dashPrompt.pop));
    ctx.save();
    // Float above the second-floor papers desk (scaled up like everything on the
    // mezzanine so it doesn't look tiny).
    ctx.translate(PAPERS_X, PAPERS_Y - 70 - (1 - a) * 10 + bob);
    ctx.scale(pop * FLOOR2_SCALE, pop * FLOOR2_SCALE);
    ctx.textAlign = 'center';
    ctx.shadowBlur = 4; ctx.shadowColor = `rgba(0,0,0,${0.65 * a})`;
    ctx.fillStyle = `rgba(255,255,255,${a})`;
    ctx.font = 'bold 16px Rubik';
    ctx.fillText('انقر لفتح الأوراق', 0, 0);
    ctx.shadowBlur = 0;
    ctx.restore();
}

// "اضغط للجلوس" — floats above whichever sofa spot is currently in range (sofa1's
// nearest point on the strip, or sofa2's nearest free fixed spot). Same fade/pop
// pattern as the dashboard prompt.
const _seatPrompt = { alpha: 0, pop: 0, x: 0, y: 0, shownKey: null };

// Cross-fades a floating world-space prompt between different targets by KEY — fades
// the old one out, then pops the new one in at its position — instead of snapping
// text/position the instant the target identity changes. Mirrors the laptop prompt
// (drawPrompt / gameState.promptState). `data` (any extra fields the caller needs,
// e.g. locked/type) is only adopted into `state.shown` once the new key is adopted —
// never mid fade-out, or the old prompt would render with the new target's data.
// Returns true once something should be drawn.
function _updatePromptCrossfade(state, key, x, y, data) {
    const lerp = 1 - Math.pow(1 - 0.22, gameState.dtFactor);
    if (key !== state.shownKey) {
        state.alpha += (0 - state.alpha) * lerp;
        if (state.alpha < 0.06 || state.shownKey === null) {
            state.shownKey = key;
            if (key !== null) { state.x = x; state.y = y; state.shown = data; }
            state.alpha = 0;
            state.pop = 0;
        }
    } else if (state.shownKey !== null) {
        state.x = x; state.y = y;
        state.alpha += (1 - state.alpha) * lerp;
        state.pop  += (1 - state.pop)  * lerp;
    }
    return state.shownKey !== null && state.alpha >= 0.02;
}
function drawSeatPrompt() {
    const target = gameState.activeSofa1 || gameState.activeSofa2Spot;
    const ctx = gameState.ctx;
    // Sofa1 is one continuous strip (no id) — key it as a single seat so sliding along
    // it doesn't re-fade; each sofa2 spot gets its own id so switching couches fades.
    const key = target ? (target.id || 'sofa1') : null;
    if (!_updatePromptCrossfade(_seatPrompt, key, target && target.x, target && target.y)) return;
    const a = _seatPrompt.alpha;
    const bob = Math.sin(Date.now() * 0.004) * 2.5;
    const pop = 0.82 + 0.18 * easeOutBack(Math.min(1, _seatPrompt.pop));
    ctx.save();
    ctx.translate(_seatPrompt.x, _seatPrompt.y - 60 - (1 - a) * 10 + bob);
    ctx.scale(pop, pop);
    ctx.textAlign = 'center';
    ctx.shadowBlur = 4; ctx.shadowColor = `rgba(0,0,0,${0.65 * a})`;
    ctx.fillStyle = `rgba(255,255,255,${a})`;
    ctx.font = 'bold 16px Rubik';
    ctx.fillText('اضغط للجلوس', 0, 0);
    ctx.shadowBlur = 0;
    ctx.restore();
}

// وقوف (stand up) — a small pill button that floats above the LOCAL player's head
// while seated. Its hit-test lives in the mousedown handler (setupControls). Same
// fade/pop crossfade pattern as the seat/game-zone prompts, for a bouncy fade in/out
// instead of snapping into existence.
const _standUpBtn = { alpha: 0, pop: 0, x: 0, y: 0, shownKey: null };
function drawStandUpButton() {
    const local = gameState.players[gameState.userId];
    // While reading, the reading panel/drawer already has its own exit button —
    // hide وقوف everywhere (desktop and mobile) so there's one clear way to end
    // a reading session.
    const readingBlocksIt = gameState.reading.active;
    const target = (gameState.isSitting && !gameState.sitAnim.active && local && !readingBlocksIt) ? local : null;
    const key = target ? 'stand' : null;
    if (!_updatePromptCrossfade(_standUpBtn, key, target && target.x, target && target.y)) return;
    const ctx = gameState.ctx;
    const a = _standUpBtn.alpha;
    const bob = Math.sin(Date.now() * 0.004) * 2.5;
    const pop = 0.82 + 0.18 * easeOutBack(Math.min(1, _standUpBtn.pop));
    ctx.save();
    ctx.translate(_standUpBtn.x, _standUpBtn.y - 90 - (1 - a) * 10 + bob);
    ctx.scale(pop, pop);
    ctx.shadowBlur = 6; ctx.shadowColor = `rgba(0,0,0,${0.4 * a})`;
    ctx.fillStyle = `rgba(18,18,18,${0.82 * a})`;
    ctx.beginPath();
    ctx.roundRect ? ctx.roundRect(-34, -16, 68, 32, 16) : ctx.rect(-34, -16, 68, 32);
    ctx.fill();
    ctx.shadowBlur = 0;
    ctx.fillStyle = `rgba(255,255,255,${0.92 * a})`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 14px Rubik';
    ctx.fillText('وقوف', 0, 1);
    ctx.restore();
}

// Games-table trigger prompt: "press to join" when it's break time, or a locked
// "closed — opens on break" notice (with a 🔒) otherwise. Same fade/pop pattern.
const _GAME_ZONE_LABEL = { race: 'اضغط للانضمام لسباق السيارات', coffee: 'اضغط للانضمام للعبة التين', boss: 'اضغط لتحدي الحاسوب' };
const _gameZonePrompt = { alpha: 0, pop: 0, x: 0, y: 0, shownKey: null, shown: null };
function drawGameZonePrompt() {
    const target = gameState.activeGameZone;
    const ctx = gameState.ctx;
    // Key includes locked state + type so the locked notice / a different game's
    // prompt properly fades out/in instead of snapping in place.
    const key = target ? `${target.type}|${target.locked}` : null;
    if (!_updatePromptCrossfade(_gameZonePrompt, key, target && target.x, target && target.y, target)) return;
    const a = _gameZonePrompt.alpha;
    const bob = Math.sin(Date.now() * 0.004) * 2.5;
    const pop = 0.82 + 0.18 * easeOutBack(Math.min(1, _gameZonePrompt.pop));
    ctx.save();
    ctx.translate(_gameZonePrompt.x, _gameZonePrompt.y - 60 - (1 - a) * 10 + bob);
    ctx.scale(pop, pop);
    ctx.textAlign = 'center';
    ctx.shadowBlur = 4; ctx.shadowColor = `rgba(0,0,0,${0.65 * a})`;
    if (_gameZonePrompt.shown.locked) {
        ctx.fillStyle = `rgba(255,190,90,${a})`;
        ctx.font = 'bold 16px Rubik';
        ctx.fillText('🔒 مغلق - يفتح في الاستراحة', 0, 0);
    } else {
        ctx.fillStyle = `rgba(255,255,255,${a})`;
        ctx.font = 'bold 16px Rubik';
        ctx.fillText(_GAME_ZONE_LABEL[_gameZonePrompt.shown.type] || 'اضغط للدخول', 0, 0);
    }
    ctx.shadowBlur = 0;
    ctx.restore();
}

// ── Opening / day navigation / rendering ────────────────────────────────────
function _dashDateInfo(offset) {
    const d = new Date();
    d.setDate(d.getDate() - offset);
    const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
    let label;
    try { label = d.toLocaleDateString('ar-EG', { weekday: 'long', day: 'numeric', month: 'long' }); }
    catch (_) { label = key; }
    const rel = offset === 0 ? 'اليوم' : offset === 1 ? 'أمس' : `قبل ${offset} أيام`;
    return { key, label, rel };
}

// ── Scattered sheet management ──────────────────────────────────────────────
// The background-sheet "tint" is a `filter: brightness()` set inline here (with an
// explicit filter transition) rather than a CSS pseudo-element — a class-toggled
// ::after opacity was snapping instead of fading. This is fully under JS control.
const DASH_SHEET_TRANSITION = 'transform 0.46s cubic-bezier(0.34,1.12,0.5,1), opacity 0.3s ease, filter 0.5s ease';
function _dashApplySheet(sheet, slot, withTransition) {
    sheet._slot = slot;
    sheet.style.transition = withTransition ? DASH_SHEET_TRANSITION : 'none';
    sheet.style.transform = `translate(${slot.x}px, ${slot.y}px) rotate(${slot.r}deg)`;
    sheet.style.zIndex = slot.z;
    sheet.style.opacity = '1';
    sheet.style.filter = slot.tint ? 'brightness(0.62)' : 'brightness(1)';
}

// Resting slot for a given sheet: active sheet → front; others → sequential bg slots.
function _dashSlotFor(sheet) {
    if (sheet === _dashActiveSheet) return DASH_ACTIVE_SLOT;
    const bg = _dashSheets.filter(s => s !== _dashActiveSheet);
    return DASH_BG_SLOTS[bg.indexOf(sheet) % DASH_BG_SLOTS.length];
}

function openDashboard() {
    if (!dashboardAllowed()) return;
    const ov = document.getElementById('dashboard-overlay');
    if (!ov) return;
    _dashState.open = true;
    _dashState.dayOffset = 0;
    _dashState.side = 'main';
    _dashState.animating = false;
    dashResetInvoices();   // start with the memories view closed (temp card peeping left)
    dashRenderInvoicePeep();   // fill the peep with a blank (placeholder) cropped receipt
    _invPeepUnderDashboard();  // hidden under the dashboard until the open sequence slides it out
    dashSound('paperIntro');
    document.body.classList.add('dash-active');
    ov.classList.remove('hidden');
    requestAnimationFrame(() => ov.classList.add('active'));
    const stage = document.getElementById('dash-stage');
    if (stage) { stage.classList.remove('side-todo'); stage.classList.add('side-main'); }

    // Collect sheets; the last one (holding the content) is the active sheet.
    _dashSheets = Array.from(document.querySelectorAll('#dash-main-stack .dash-sheet'));
    const contentSheet = document.getElementById('dash-day-paper')?.closest('.dash-sheet');
    _dashActiveSheet = contentSheet || _dashSheets[_dashSheets.length - 1];

    // Hide the to-do paper completely until the stack intro finishes — it then slides
    // out from behind the papers into its resting peeping position.
    const todo = document.getElementById('dash-todo-paper');
    if (todo) { todo.style.transition = 'none'; todo.style.transform = 'translateX(0) rotate(0deg)'; todo.style.opacity = '0'; }

    dashRenderAvatar();
    dashRenderStats();
    dashPlayOpenSequence();
    // Carry yesterday's unfinished tasks into today (once per day), THEN render the day.
    dashRolloverTodos().then(() => { if (_dashState.open) dashRenderDay(0); });
}

// Task carry-over: today's UNCOMPLETED to-dos roll forward from the last managed day;
// completed ones stay put (they belong to the day they were finished). Runs once per
// day, gated by a `todosRolloverDate` marker so clearing tasks won't re-pull them.
function _dashParseTodos(raw) {
    if (Array.isArray(raw)) return raw.filter(Boolean);
    if (raw && typeof raw === 'object') return Object.keys(raw).sort().map(k => raw[k]).filter(Boolean);
    return [];
}
function dashRolloverTodos() {
    return new Promise((resolve) => {
        if (dashReadOnly() || !gameState.userId) { resolve(); return; }
        const uid = gameState.userId;
        const today = _todayDateStr();
        get(ref(database, `dashboards/${uid}/todosRolloverDate`)).then((mk) => {
            const last = mk.val();
            if (last === today) { resolve(); return; }   // already rolled over today
            const y = new Date(); y.setDate(y.getDate() - 1);
            const yesterday = `${y.getFullYear()}-${String(y.getMonth() + 1).padStart(2, '0')}-${String(y.getDate()).padStart(2, '0')}`;
            const sourceDate = (last && last < today) ? last : yesterday;
            Promise.all([
                get(ref(database, `dashboards/${uid}/todos/${sourceDate}`)),
                get(ref(database, `dashboards/${uid}/todos/${today}`)),
            ]).then(([ps, ts]) => {
                const carried = _dashParseTodos(ps.val()).filter(t => !t.done).map(t => ({ text: t.text, done: false }));
                const merged = [];
                const seen = new Set();
                [..._dashParseTodos(ts.val()), ...carried].forEach((t) => {
                    const k = (t.text || '').trim();
                    if (!k || seen.has(k)) return;
                    seen.add(k);
                    merged.push({ text: t.text, done: !!t.done });
                });
                const updates = { [`dashboards/${uid}/todosRolloverDate`]: today };
                updates[`dashboards/${uid}/todos/${today}`] = merged.slice(0, DASH_MAX_TODOS);
                update(ref(database), updates).catch(_dashErr('rollover')).finally(resolve);
            }).catch(() => resolve());
        }).catch(() => resolve());
    });
}

// Opening: background sheets fly in one after another, then the main (active) sheet on
// top — and finally the to-do paper slides out from behind into its peep.
function dashPlayOpenSequence() {
    if (!_dashSheets.length) return;
    const bg = _dashSheets.filter(s => s !== _dashActiveSheet);
    const order = [...bg, _dashActiveSheet];   // backgrounds first, main last
    // Start them all off-screen up north.
    _dashSheets.forEach((s) => {
        s.style.transition = 'none';
        s.style.transform = 'translate(0, -165%) rotate(-2deg)';
        s.style.opacity = '0';
    });
    void _dashSheets[0].offsetWidth;   // commit the start frame
    order.forEach((s, i) => {
        setTimeout(() => { if (_dashState.open) _dashApplySheet(s, _dashSlotFor(s), true); }, 70 + i * 95);
    });
    // After the stack settles, reveal the to-do paper (slides from behind to its peep).
    const revealAt = 70 + order.length * 95 + 240;
    setTimeout(() => {
        if (!_dashState.open) return;
        const todo = document.getElementById('dash-todo-paper');
        if (todo) {
            todo.style.transition = 'transform 0.55s cubic-bezier(0.34,1.2,0.5,1), opacity 0.4s ease';
            todo.style.transform = '';   // hand back to the CSS resting (peep) position
            todo.style.opacity = '1';
        }
        dashMaybeShowSwipeHint();
    }, revealAt);
    // The invoice peep slides out from under the dashboard on the LEFT, just AFTER the
    // to-do paper has slid out on the right.
    setTimeout(() => { if (_dashState.open && !_invOpen) dashSlidePeepOut(); }, revealAt + 240);
}

function closeDashboard() {
    const ov = document.getElementById('dashboard-overlay');
    if (!ov || !_dashState.open) return;
    _dashState.open = false;
    dashResetInvoices();   // tear down the memories view if it was open
    dashSound('paperExit');
    document.body.classList.remove('dash-active');
    document.getElementById('dash-swipe-hint')?.classList.remove('show');
    // Closing: reverse the entrance — main sheet flies out first, then backgrounds one by one.
    const bg = _dashSheets.filter(s => s !== _dashActiveSheet);
    const order = [_dashActiveSheet, ...bg].filter(Boolean);
    order.forEach((s, i) => {
        setTimeout(() => {
            s.style.transition = 'transform 0.4s cubic-bezier(0.5,0,0.75,0), opacity 0.32s ease';
            s.style.transform = 'translate(0, -165%) rotate(-2deg)';
            s.style.opacity = '0';
        }, i * 75);
    });
    const tail = Math.max(280, order.length * 75 + 320);
    ov.classList.remove('active');
    setTimeout(() => { ov.classList.add('hidden'); }, tail);
}

function dashRenderDay(offset) {
    const info = _dashDateInfo(offset);
    const journalEl = document.getElementById('dash-journal');
    const tasksEl   = document.getElementById('dash-day-tasks');
    if (!journalEl || !tasksEl) return;
    setDashText('dash-day-rel', info.rel);
    setDashText('dash-day-rel-tag', info.rel);
    setDashText('dash-day-date', info.label);
    journalEl.value = ''; journalEl.disabled = true;
    journalEl.readOnly = dashReadOnly();
    tasksEl.innerHTML = '<div class="dash-empty">…</div>';

    // Journal for this day
    get(ref(database, `dashboards/${dashViewUid()}/days/${info.key}/journal`)).then(snap => {
        if (!_dashState.open) return;
        journalEl.value = snap.val() || '';
        journalEl.disabled = false;
        journalEl.dataset.dateKey = info.key;
        dashClampJournal(journalEl);   // refresh the word counter
    }).catch(() => { journalEl.disabled = false; });

    // To-dos for this day drive BOTH the to-do paper and "المهام المنجزة".
    dashLoadTodos(info.key);
    dashScheduleAlign();   // align dividers + journal lines to the grid (now + after font load)
}

// "المهام المنجزة" = the DONE items from this day's to-do list (no timer, just names).
function dashRenderCompleted() {
    const el = document.getElementById('dash-day-tasks');
    if (!el) return;
    const done = (_dashState.todos || []).filter(t => t && t.done && (t.text || '').trim());
    if (!done.length) {
        el.innerHTML = '<div class="dash-empty">لا مهام منجزة في هذا اليوم</div>';
        return;
    }
    el.innerHTML = done.map(t =>
        `<div class="dash-task-row dash-task-done"><span class="dash-task-check">✓</span>
            <span class="dash-task-name">${escapeDashHtml(t.text)}</span></div>`).join('');
}

// Day swap: pick a random background sheet, slide it "up north" (fading off its dark
// tint), raise its z-index above the stack, then settle it back down centred as the
// new active day. The previous active sheet recedes into the vacated background slot.
function dashAnimateDayChange(targetOffset) {
    const movers = _dashSheets.filter(s => s !== _dashActiveSheet);
    if (!movers.length) { dashRenderDay(targetOffset); return; }
    _dashState.animating = true;
    dashSound('paperDaysSwap');
    const mover = movers[Math.floor(Math.random() * movers.length)];
    const oldActive = _dashActiveSheet;
    const moverSlot = mover._slot || DASH_BG_SLOTS[0];
    const content = document.getElementById('dash-day-paper');

    // Phase A — a blank background sheet slides up north, out of bounds, gradually
    // brightening off its tint. The old page stays intact & in front the whole time.
    mover.style.transition = 'transform 0.42s cubic-bezier(0.45,0.02,0.25,1), opacity 0.3s, filter 0.5s ease';
    mover.style.transform = 'translate(0, -160%) rotate(-1.5deg)';
    mover.style.filter = 'brightness(1)';

    setTimeout(() => {
        if (!_dashState.open) { _dashState.animating = false; return; }
        // Phase B — the mover is now off-screen at the top: hand it the content + the
        // new day (rendered while hidden) and raise its z-index above the stack.
        if (content && content.parentElement !== mover) mover.appendChild(content);
        dashRenderDay(targetOffset);
        mover.style.zIndex = 60;
        // Phase C — slide it back down, landing cleanly on top as the new active day.
        _dashApplySheet(mover, DASH_ACTIVE_SLOT, true);
        mover.style.zIndex = 60;
        // The old active recedes into the mover's vacated background slot, darkening.
        _dashApplySheet(oldActive, moverSlot, true);
        _dashActiveSheet = mover;
        setTimeout(() => {
            mover.style.zIndex = DASH_ACTIVE_SLOT.z;   // normalise layering
            _dashState.animating = false;
        }, 480);
    }, 430);
}

function dashGoDay(delta) {
    if (_dashState.animating) return;
    const next = _dashState.dayOffset + delta;        // delta +1 = older day
    if (next < 0) return;                              // can't go into the future
    if (next > 365) return;
    _dashState.dayOffset = next;
    dashAnimateDayChange(next);
}

// User avatar in a "taped-on" paper cutout with a warm vintage tint.
function dashRenderAvatar() {
    const img = document.getElementById('dash-avatar-img');
    const txt = document.getElementById('dash-avatar-text');
    if (!img || !txt) return;
    const p = gameState.players[gameState.userId];
    const avatar = p && p.avatar;
    if (avatar) {
        img.src = avatar; img.style.display = 'block'; txt.style.display = 'none';
    } else {
        img.style.display = 'none'; txt.style.display = 'flex';
        txt.textContent = (p && p.username ? p.username.charAt(0) : '؟').toUpperCase();
    }
}

function escapeDashHtml(s) {
    return String(s).replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
}

function dashSaveJournal() {
    if (dashReadOnly()) return;
    const el = document.getElementById('dash-journal');
    const dateKey = el.dataset.dateKey;
    if (!dateKey) return;
    clearTimeout(_dashJournalSaveTimer);
    _dashJournalSaveTimer = setTimeout(() => {
        update(ref(database), { [`dashboards/${gameState.userId}/days/${dateKey}/journal`]: el.value }).catch(_dashErr('journal'));
    }, 700);
}

// Cap the journal to 200 words as the user types.
function dashClampJournal(el) {
    const words = el.value.trim().split(/\s+/).filter(Boolean);
    if (words.length > DASH_JOURNAL_MAX_WORDS) {
        el.value = words.slice(0, DASH_JOURNAL_MAX_WORDS).join(' ');
    }
    const wc = el.value.trim() ? el.value.trim().split(/\s+/).filter(Boolean).length : 0;
    const counter = document.getElementById('dash-journal-count');
    if (counter) counter.textContent = `${wc} / ${DASH_JOURNAL_MAX_WORDS} كلمة`;
}

// Run the grid-snap now AND again once Methlama has loaded — text metrics change when
// the real font swaps in, which shifts everything off-grid if we only aligned with the
// Rubik fallback (the reason it looked misaligned on a fresh open).
function dashScheduleAlign() {
    requestAnimationFrame(() => { if (_dashState.open) dashAlignGridLines(); });
    if (document.fonts && document.fonts.ready) {
        document.fonts.ready.then(() => { if (_dashState.open) requestAnimationFrame(dashAlignGridLines); });
    }
}

// Snap the WRITTEN text onto each paper's 34px texture grid so it reads like real handwriting on
// ruled paper. The ruled line is drawn at content-y ≡ 33.5 mod 34 (the colored 33→34 band). Arabic
// text must sit on that line by its ALPHABETIC BASELINE — the level of the connecting ـــ stroke —
// so descenders (و ي ن-tail) drop below the line and ا/ل/أ rise above it, never touching. Aligning
// by the box top or box bottom (the old bug) floated the text off the line. So we compute the true
// baseline offset inside each text block's first line (from real font metrics) and nudge the block
// via margin-top so that baseline lands on the ruled line. UI boxes (summary + high-score chips)
// are NOT writing — they're centred in the whitespace BETWEEN two ruled lines instead. Flex column
// on the content means margin-top actually moves things (no collapse); blocks are done top-to-bottom
// so each re-measures after the one above moved (no drift).
const DASH_GRID = 34, DASH_LINE_Y = 33.5;   // ruled line sits at y ≡ 33.5 mod 34

// Real baseline offset (px from a line box's top to its alphabetic baseline) for a given font.
// Uses canvas font metrics — cached per font-size+family. After document.fonts.ready the Methlama
// metrics are correct; before that we still return a sane estimate.
let _dashFmCanvas = null;
const _dashFmCache = {};
function _dashBaselineOffset(fontSizePx, fontFamily, lineHeightPx) {
    const key = fontSizePx + '|' + fontFamily;
    let m = _dashFmCache[key];
    if (!m) {
        _dashFmCanvas = _dashFmCanvas || document.createElement('canvas');
        const ctx = _dashFmCanvas.getContext('2d');
        ctx.font = `${fontSizePx}px ${fontFamily}`;
        const t = ctx.measureText('مبنىكلمة');
        let asc = t.fontBoundingBoxAscent, desc = t.fontBoundingBoxDescent;
        if (asc == null) { asc = t.actualBoundingBoxAscent || fontSizePx * 0.8; desc = t.actualBoundingBoxDescent || fontSizePx * 0.2; }
        m = _dashFmCache[key] = { asc, desc };
    }
    // Baseline within a line box = half-leading + ascent = lh/2 + (ascent - descent)/2.
    return lineHeightPx / 2 + (m.asc - m.desc) / 2;
}

function dashAlignGridLines() {
    // Measure `el`'s first-line baseline and nudge `moveEl` (default `el`) via margin-top so that
    // baseline lands on a ruled line. (moveEl differs when the writing lives in a child, e.g. a
    // to-do line inside a flex row — we measure the line but move the whole list.)
    const alignBaseline = (el, moveEl) => {
        if (!el) return;
        moveEl = moveEl || el;
        moveEl.style.marginTop = '';
        const cs = getComputedStyle(el);
        const fs = parseFloat(cs.fontSize) || 16;
        const lh = parseFloat(cs.lineHeight) || fs * 1.4;
        const padTop = parseFloat(cs.paddingTop) || 0;
        const baseline = el.offsetTop + padTop + _dashBaselineOffset(fs, cs.fontFamily, lh);
        let d = ((DASH_LINE_Y - baseline) % DASH_GRID + DASH_GRID) % DASH_GRID;   // 0..34
        if (d > DASH_GRID / 2) d -= DASH_GRID;                               // nearest ±17
        const mcs = getComputedStyle(moveEl);
        moveEl.style.marginTop = ((parseFloat(mcs.marginTop) || 0) + d) + 'px';
    };
    // Centre a UI box in the whitespace between two ruled lines (its centre → mid-gap ≡ 16.5).
    const centreInGap = (el) => {
        if (!el) return;
        el.style.marginTop = '';
        const cs = getComputedStyle(el);
        const centre = el.offsetTop + el.offsetHeight / 2;
        const gapMid = DASH_LINE_Y + DASH_GRID / 2;   // ≡ 16.5 mod 34
        let d = ((gapMid - centre) % DASH_GRID + DASH_GRID) % DASH_GRID;
        if (d > DASH_GRID / 2) d -= DASH_GRID;
        el.style.marginTop = ((parseFloat(cs.marginTop) || 0) + d) + 'px';
    };

    const content = document.getElementById('dash-day-paper');
    if (content) {
        const titles = [...content.querySelectorAll('.dash-section-title')];
        alignBaseline(document.getElementById('dash-day-date'));   // date → on a line
        if (titles[0]) alignBaseline(titles[0]);                   // ملخص عام
        centreInGap(content.querySelector('.dash-stats'));         // summary chips → between lines
        centreInGap(content.querySelector('.dash-highscores'));    // score chips  → between lines
        if (titles[1]) alignBaseline(titles[1]);                   // يوميات اليوم
        alignBaseline(document.getElementById('dash-journal'));    // journal first line → on a line
        if (titles[2]) alignBaseline(titles[2]);                   // المهام المنجزة
        const tasks = content.querySelector('.dash-day-tasks');    // completed tasks → on lines
        const firstTaskName = tasks && tasks.querySelector('.dash-task-name');
        if (firstTaskName) alignBaseline(firstTaskName, tasks);    // measure a task line, move the block
        else alignBaseline(tasks);
    }

    // To-do paper: nudge the list so each 34px row's writing baseline lands on a texture line.
    const list = document.getElementById('dash-todo-list');
    const firstLine = list && list.querySelector('.dash-todo-line');
    if (firstLine) alignBaseline(firstLine, list);   // measure the line, move the whole list
}

// ── Analytics summary (stats) ───────────────────────────────────────────────
function dashRenderStats() {
    get(ref(database, `dashboards/${dashViewUid()}/stats`)).then(snap => {
        if (!_dashState.open) return;
        const s = snap.val() || {};
        const totalMin = Math.round((s.totalWorkMs || 0) / 60000);
        setDashText('dash-stat-hours', formatDurationArabic(totalMin));
        setDashText('dash-stat-task', s.mostTask?.name || '—');
        const high = s.high || {};
        setDashText('dash-hs-laptop', high.laptop != null ? formatRaceTime(high.laptop) : '—');
        setDashText('dash-hs-race',   high.race   != null ? formatRaceTime(high.race)   : '—');
        setDashText('dash-hs-coffee', high.coffee != null ? `${high.coffee} نقطة` : '—');
    }).catch(() => {});
}
function setDashText(id, v) { const el = document.getElementById(id); if (el) el.textContent = v; }

// ── To-Do list (المهمات اليومية) — per selected day, max 5 ──────────────────
// Marking a to-do "done" is what populates "المهام المنجزة" for that same day.
function dashLoadTodos(dateKey) {
    dateKey = dateKey || _todayDateStr();
    _dashState.todosDate = dateKey;
    get(ref(database, `dashboards/${dashViewUid()}/todos/${dateKey}`)).then(snap => {
        if (!_dashState.open || _dashState.todosDate !== dateKey) return;   // day changed mid-fetch
        const raw = snap.val();
        let todos = [];
        if (Array.isArray(raw)) todos = raw.filter(Boolean);
        else if (raw && typeof raw === 'object') todos = Object.keys(raw).sort().map(k => raw[k]).filter(Boolean);
        _dashState.todos = todos.slice(0, DASH_MAX_TODOS);
        dashRenderTodos();
        dashRenderCompleted();
    }).catch(() => { _dashState.todos = []; dashRenderTodos(); dashRenderCompleted(); });
}

function dashSaveTodos() {
    if (dashReadOnly()) return;
    const key = _dashState.todosDate || _todayDateStr();
    clearTimeout(_dashTodoSaveTimer);
    _dashTodoSaveTimer = setTimeout(() => {
        update(ref(database), { [`dashboards/${gameState.userId}/todos/${key}`]: _dashState.todos }).catch(_dashErr('todos'));
    }, 350);
}

function _dashTodoRowHTML(t, i, fresh) {
    const ro = dashReadOnly();
    return `<div class="dash-todo-row ${t.done ? 'done' : ''} ${fresh ? 'dash-row-fresh' : ''}">
        <button class="dash-todo-check" data-i="${i}" ${ro ? 'disabled' : ''}>${t.done ? '✓' : ''}</button>
        <div class="dash-todo-line" contenteditable="${ro ? 'false' : 'true'}" data-i="${i}">${escapeDashHtml(t.text || '')}</div>
    </div>`;
}
function _dashEmptyRowHTML(fresh) {
    if (dashReadOnly()) return '';
    return `<div class="dash-todo-row empty ${fresh ? 'dash-row-fresh' : ''}">
        <button class="dash-todo-check" disabled></button>
        <div class="dash-todo-line dash-todo-new" contenteditable="true" data-i="new" data-placeholder="مهمة جديدة…"></div>
    </div>`;
}

// Full re-render (on load / structural change). Live typing uses the lighter path below.
function dashRenderTodos() {
    const list = document.getElementById('dash-todo-list');
    if (!list) return;
    const rows = _dashState.todos.slice(0, DASH_MAX_TODOS);
    let html = rows.map((t, i) => _dashTodoRowHTML(t, i, false)).join('');
    if (!dashReadOnly() && rows.length < DASH_MAX_TODOS) html += _dashEmptyRowHTML(false);
    list.innerHTML = html;
    dashScheduleAlign();   // keep the to-do rows on the texture grid
}

// Live generation: the instant the user types into the trailing empty row, promote it
// to a real to-do and spawn the next empty checkbox/line below with a snappy entrance —
// without stealing the caret from the row they're typing in. Cap enforced at 5.
function dashHandleTodoInput(line) {
    if (dashReadOnly()) return;
    const idx = line.dataset.i;
    const text = line.textContent;
    if (idx === 'new') {
        if (text.trim() === '') return;
        if (_dashState.todos.length >= DASH_MAX_TODOS) return;
        const newIndex = _dashState.todos.length;
        _dashState.todos.push({ text, done: false });
        // This row is now a real to-do — rebind it in place (keeps focus + caret).
        line.dataset.i = String(newIndex);
        line.classList.remove('dash-todo-new');
        line.removeAttribute('data-placeholder');
        const check = line.parentElement.querySelector('.dash-todo-check');
        if (check) { check.dataset.i = String(newIndex); check.disabled = false; }
        dashSaveTodos();
        // Spawn the next empty row beneath, with its fresh-entrance animation.
        if (_dashState.todos.length < DASH_MAX_TODOS) {
            const list = document.getElementById('dash-todo-list');
            line.closest('.dash-todo-row').insertAdjacentHTML('afterend', _dashEmptyRowHTML(true));
        }
    } else {
        const i = Number(idx);
        if (_dashState.todos[i]) { _dashState.todos[i].text = text; dashSaveTodos(); }
    }
}

// Deleting all text in a committed row removes it (handled on blur to avoid mid-type churn).
function dashHandleTodoBlur(line) {
    if (dashReadOnly()) return;
    const idx = line.dataset.i;
    if (idx === 'new') return;
    const i = Number(idx);
    if (_dashState.todos[i] && line.textContent.trim() === '') {
        _dashState.todos.splice(i, 1);
        dashSaveTodos();
        dashRenderTodos();
        dashRenderCompleted();
    }
}

function dashToggleTodo(i) {
    if (dashReadOnly() || !_dashState.todos[i]) return;
    _dashState.todos[i].done = !_dashState.todos[i].done;
    if (_dashState.todos[i].done) dashSound('paperTaskComplete');   // success chime on completing
    dashSaveTodos();
    dashRenderTodos();
    dashRenderCompleted();   // done to-dos appear in "المهام المنجزة" for this day
}

function dashSetSide(side) {
    const stage = document.getElementById('dash-stage');
    if (!stage || _dashState.side === side) return;
    _dashState.side = side;
    dashSound('paperSwipe');
    stage.classList.toggle('side-todo', side === 'todo');
    stage.classList.toggle('side-main', side === 'main');
    dashDismissSwipeHint();   // they've learned the gesture
}

// First-time mobile hint: a small arrow nudging right to teach the side-swap.
function dashMaybeShowSwipeHint() {
    if (!isMobile()) return;
    try { if (localStorage.getItem('mdwnh_dash_swipe_hint') === '1') return; } catch (_) {}
    const hint = document.getElementById('dash-swipe-hint');
    if (!hint) return;
    hint.classList.add('show');
    clearTimeout(hint._t);
    hint._t = setTimeout(dashDismissSwipeHint, 7000);
}
function dashDismissSwipeHint() {
    const hint = document.getElementById('dash-swipe-hint');
    if (hint) hint.classList.remove('show');
    try { localStorage.setItem('mdwnh_dash_swipe_hint', '1'); } catch (_) {}
}

// ── UI wiring (called from startGame) ───────────────────────────────────────
function setupDashboardUI() {
    const ovEl = document.getElementById('dashboard-overlay');
    document.getElementById('dash-close')?.addEventListener('click', closeDashboard);
    document.getElementById('dash-prev-day')?.addEventListener('click', () => dashGoDay(1));   // older
    document.getElementById('dash-next-day')?.addEventListener('click', () => dashGoDay(-1));  // newer

    const journal = document.getElementById('dash-journal');
    journal?.addEventListener('input', () => { dashClampJournal(journal); dashSaveJournal(); });
    // Tapping the يوميات typebox while the to-do paper is in front swaps back to the main
    // paper (the overlay click handler skips textareas, so handle it here on pointerdown —
    // fires before focus so the swap happens, then the user can type normally).
    journal?.addEventListener('pointerdown', () => { if (_dashState.side === 'todo') dashSetSide('main'); });

    // To-Do interactions (delegated). The checkbox toggles "done" and STOPS the click
    // from bubbling, so tapping a checkbox never triggers the paper side-swap.
    const todoList = document.getElementById('dash-todo-list');
    todoList?.addEventListener('click', (e) => {
        const check = e.target.closest('.dash-todo-check');
        if (check && check.dataset.i != null && check.dataset.i !== '') {
            e.stopPropagation();
            dashToggleTodo(Number(check.dataset.i));
        }
    });
    // Live generation of the next line the instant any character is typed.
    todoList?.addEventListener('input', (e) => {
        const line = e.target.closest('.dash-todo-line');
        if (line) dashHandleTodoInput(line);
    });
    todoList?.addEventListener('keydown', (e) => {
        const line = e.target.closest('.dash-todo-line');
        if (!line) return;
        if (e.key === 'Enter') {   // Enter jumps to the trailing empty line
            e.preventDefault();
            const nl = todoList.querySelector('.dash-todo-new');
            if (nl && nl !== line) nl.focus();
            else line.blur();
        }
    });
    todoList?.addEventListener('blur', (e) => {
        const line = e.target.closest('.dash-todo-line');
        if (line) dashHandleTodoBlur(line);
    }, true);

    // ── Unified, swipe-aware click handling ─────────────────────────────────
    // A single click handler (not mousedown — mousedown fired on touch swipes and
    // closed the panel by itself). After a swipe we swallow the trailing synthetic
    // click so it can't double-fire (the old code's "can't swap / exits by itself").
    let _dashSuppressClickUntil = 0;
    ovEl?.addEventListener('click', (e) => {
        if (Date.now() < _dashSuppressClickUntil) return;
        if (e.target.closest('.dash-todo-check, button, textarea, input, [contenteditable="true"]')) return;
        // ── Work-memories (invoices) ────────────────────────────────────────
        if (_invOpen) {
            // Clicking the peeping dashboard edge / back chevron / scrim returns.
            if (e.target.closest('#dash-invoice-grid')) return;   // let the grid scroll
            if (e.target.closest('.dash-stage') || e.target.closest('#dash-invoice-back') || e.target === ovEl) dashCloseInvoices();
            return;
        }
        if (e.target.closest('#dash-invoice-peep')) { dashOpenInvoices(); return; }   // peep → open
        if (e.target === ovEl) { closeDashboard(); return; }                 // scrim → close
        if (e.target.closest('#dash-todo-paper') && _dashState.side === 'main') { dashSetSide('todo'); return; }
        if (e.target.closest('#dash-main-stack') && _dashState.side === 'todo') { dashSetSide('main'); return; }
    });

    // Invoice card delete: tiny ✕ → per-card confirm → delete from Firebase.
    document.getElementById('dash-invoice-grid')?.addEventListener('click', (e) => {
        const del = e.target.closest('.inv-del');
        if (del) { e.stopPropagation(); del.closest('.inv-card')?.classList.add('confirming'); return; }
        const no = e.target.closest('.inv-confirm-no');
        if (no) { e.stopPropagation(); no.closest('.inv-card')?.classList.remove('confirming'); return; }
        const yes = e.target.closest('.inv-confirm-yes');
        if (yes) { e.stopPropagation(); dashDeleteInvoice(yes.dataset.fm, yes.closest('.inv-card')); return; }
    });

    // Horizontal swipe flips between the dashboard and the to-do paper. Tracks
    // movement so a tap on a checkbox/field never counts as a swipe.
    let _g = null;
    ovEl?.addEventListener('touchstart', (e) => {
        if (e.target.closest('textarea, input, [contenteditable="true"], button, .dash-todo-check')) { _g = null; return; }
        const t = e.touches[0]; _g = { x: t.clientX, y: t.clientY };
    }, { passive: true });
    ovEl?.addEventListener('touchend', (e) => {
        if (!_g) return;
        const g = _g; _g = null;
        const t = e.changedTouches[0];
        const dx = t.clientX - g.x, dy = t.clientY - g.y;
        if (Math.abs(dx) < 45 || Math.abs(dx) < Math.abs(dy) * 1.2) return;   // mostly-horizontal only
        _dashSuppressClickUntil = Date.now() + 600;     // swallow the trailing synthetic click
        dashDismissSwipeHint();
        // Horizontal strip: [invoices] ← [main] ← [to-do]. Swipe-right moves "back"
        // toward invoices; swipe-left moves "forward" toward the to-do paper.
        if (_invOpen) { if (dx < 0) dashCloseInvoices(); return; }     // swipe-left → return
        if (_dashState.side === 'main') {
            if (dx > 0) dashOpenInvoices();                            // swipe-right → invoices
            else dashSetSide('todo');                                 // swipe-left → to-do
        } else if (_dashState.side === 'todo') {
            if (dx > 0) dashSetSide('main');                          // swipe-right → back to main
        }
    }, { passive: true });

    // Long-free confirm modal buttons
    const lf = document.getElementById('dash-longfree-modal');
    document.getElementById('dash-lf-h-up')?.addEventListener('click', () => lf._adj && lf._adj('h', 1));
    document.getElementById('dash-lf-h-down')?.addEventListener('click', () => lf._adj && lf._adj('h', -1));
    document.getElementById('dash-lf-m-up')?.addEventListener('click', () => lf._adj && lf._adj('m', 1));
    document.getElementById('dash-lf-m-down')?.addEventListener('click', () => lf._adj && lf._adj('m', -1));
    document.getElementById('dash-lf-confirm')?.addEventListener('click', () => lf._confirm && lf._confirm());
    document.getElementById('dash-lf-discard')?.addEventListener('click', () => lf._discard && lf._discard());

    // Methlama font fallback notice (spec): if the OTFs can't load we silently fall
    // back to Rubik via the CSS stack — log a clear, actionable explanation.
    if (dashboardAllowed() && document.fonts && document.fonts.load) {
        document.fonts.load('700 16px Methlama').then(() => {
            if (!document.fonts.check('700 16px Methlama')) {
                console.warn('[dashboard] Methlama OTF did not load — falling back to Rubik. ' +
                    'Check that Fonts/KOMethlama-*.otf are served (correct path/case) and that the server allows .otf. ' +
                    'To re-enable: confirm the @font-face src paths in style.css resolve from the site root.');
            }
        }).catch(() => console.warn('[dashboard] Methlama font load error — using Rubik fallback.'));
    }

    // Mock/seed data is no longer injected. If a previous build left seeded test data
    // (marked by the `_seed` key), wipe it once so the dashboard starts from real data.
    if (dashboardAllowed()) dashClearSeedData();

    // A Siraj test ghost builds its OWN throwaway dashboard node — remove it from
    // Firebase the moment it disconnects so it never lingers as orphaned test data.
    if (gameState.isSirajGhost && gameState.userId) {
        try { onDisconnect(ref(database, `dashboards/${gameState.userId}`)).remove(); } catch (_) {}
        // Seed a batch of mock invoices into the ghost's throwaway node so the work-
        // memories grid + virtualization can be tested without affecting real data.
        dashSeedMockInvoices();
    }
}

// One-time cleanup of leftover seeded mock data (the old "temp stats"). Only fires if
// the `_seed` marker is present, so it never touches genuinely-entered data.
function dashClearSeedData() {
    const uid = DASH_TARGET_UID;
    get(ref(database, `dashboards/${uid}/_seed`)).then(snap => {
        if (!snap.exists()) return;
        update(ref(database), { [`dashboards/${uid}`]: null })
            .then(() => console.log('[dashboard] cleared leftover seeded test data'))
            .catch(_dashErr('clear-seed'));
    }).catch(() => {});
}

// ============================================================================
//  End-of-session card: drag-drop image → 1:1 crop (pan/zoom) → taped-on photo
//  The photo is purely local/visual (for the screenshot the user sends) — never
//  persisted. Reset each time the card opens.
// ============================================================================
const _crop = { srcImg: null, baseScale: 1, scale: 1, x: 0, y: 0, fw: 280, fh: 210, natW: 0, natH: 0, dragging: false, lastX: 0, lastY: 0 };

// Photo slot has three states: 'drop' (add zone shown), 'photo' (taped photo + ✕),
// 'removed' (slot fully collapsed → card shrinks, "اضافة صورة" text shows under it).
function successPhotoState(state) {
    const wrap  = document.getElementById('success-photo-wrap');
    const drop  = document.getElementById('success-photo-drop');
    const taped = document.getElementById('success-photo-taped');
    const img   = document.getElementById('success-photo-img');
    const addBtn = document.getElementById('success-add-photo');
    if (!wrap) return;
    if (state !== 'photo' && img) img.src = '';
    wrap.style.display  = (state === 'removed') ? 'none' : 'flex';
    if (drop)  drop.style.display  = (state === 'drop')  ? 'flex'  : 'none';
    if (taped) taped.style.display = (state === 'photo') ? 'block' : 'none';
    if (addBtn) addBtn.style.display = (state === 'removed') ? 'block' : 'none';
}

// Reset to the default (add zone) state — called each time the card opens.
function clearSuccessPhoto() {
    successPhotoState('drop');
}

function _cropApply() {
    const cropImg = document.getElementById('crop-img');
    if (!cropImg) return;
    cropImg.style.width  = (_crop.natW * _crop.scale) + 'px';
    cropImg.style.height = (_crop.natH * _crop.scale) + 'px';
    cropImg.style.transform = `translate(-50%, -50%) translate(${_crop.x}px, ${_crop.y}px)`;
}
function _cropClamp() {
    const dw = _crop.natW * _crop.scale, dh = _crop.natH * _crop.scale;
    const maxX = Math.max(0, (dw - _crop.fw) / 2), maxY = Math.max(0, (dh - _crop.fh) / 2);
    _crop.x = Math.max(-maxX, Math.min(maxX, _crop.x));
    _crop.y = Math.max(-maxY, Math.min(maxY, _crop.y));
}

function loadCropImage(file) {
    if (!file || !file.type || !file.type.startsWith('image/')) return;
    const reader = new FileReader();
    reader.onload = () => {
        const img = new Image();
        img.onload = () => {
            const frame = document.getElementById('crop-frame');
            const cropImg = document.getElementById('crop-img');
            const zoom = document.getElementById('crop-zoom');
            if (!frame || !cropImg) return;
            document.getElementById('crop-modal').classList.add('active');   // active first → frame has size
            const fr = frame.getBoundingClientRect();
            _crop.fw = fr.width || 280; _crop.fh = fr.height || 210;
            _crop.srcImg = img; _crop.natW = img.naturalWidth; _crop.natH = img.naturalHeight;
            _crop.baseScale = Math.max(_crop.fw / img.naturalWidth, _crop.fh / img.naturalHeight);
            _crop.scale = _crop.baseScale; _crop.x = 0; _crop.y = 0;
            if (zoom) zoom.value = 1;
            cropImg.src = img.src;
            _cropApply();
        };
        img.src = reader.result;
    };
    reader.readAsDataURL(file);
}

function confirmCrop() {
    if (!_crop.srcImg) { document.getElementById('crop-modal').classList.remove('active'); return; }
    const OUTW = 480, OUTH = 360;              // 4:3 output
    const scale = _crop.scale;                 // displayed px per natural px
    const cropNatW = _crop.fw / scale, cropNatH = _crop.fh / scale;   // natural region in the frame
    const cxNat = _crop.natW / 2 - _crop.x / scale;
    const cyNat = _crop.natH / 2 - _crop.y / scale;
    const sx = cxNat - cropNatW / 2, sy = cyNat - cropNatH / 2;
    const canvas = document.createElement('canvas');
    canvas.width = OUTW; canvas.height = OUTH;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(_crop.srcImg, sx, sy, cropNatW, cropNatH, 0, 0, OUTW, OUTH);
    let dataUrl; try { dataUrl = canvas.toDataURL('image/jpeg', 0.9); } catch (_) { dataUrl = ''; }
    if (dataUrl) {
        document.getElementById('success-photo-img').src = dataUrl;
        successPhotoState('photo');
    }
    document.getElementById('crop-modal').classList.remove('active');
}

function setupSuccessCardUI() {
    const drop  = document.getElementById('success-photo-drop');
    const wrap  = document.getElementById('success-photo-wrap');
    const input = document.getElementById('success-photo-input');
    const card  = document.getElementById('success-card');
    if (!drop || !wrap || !input || !card) return;

    drop.addEventListener('click', () => input.click());
    input.addEventListener('change', () => { if (input.files && input.files[0]) loadCropImage(input.files[0]); input.value = ''; });
    // ✕ removes the photo completely (card shrinks) and reveals the "اضافة صورة" text.
    document.getElementById('success-photo-remove')?.addEventListener('click', () => successPhotoState('removed'));
    // "اضافة صورة" brings back the add-zone and hides itself.
    document.getElementById('success-add-photo')?.addEventListener('click', () => successPhotoState('drop'));

    // Drag & drop anywhere on the card.
    let _dragDepth = 0;
    card.addEventListener('dragenter', (e) => { e.preventDefault(); _dragDepth++; wrap.classList.add('dragover'); });
    card.addEventListener('dragover',  (e) => { e.preventDefault(); });
    card.addEventListener('dragleave', (e) => { e.preventDefault(); if (--_dragDepth <= 0) { _dragDepth = 0; wrap.classList.remove('dragover'); } });
    card.addEventListener('drop', (e) => {
        e.preventDefault(); _dragDepth = 0; wrap.classList.remove('dragover');
        const f = e.dataTransfer && e.dataTransfer.files && e.dataTransfer.files[0];
        if (f) loadCropImage(f);
    });

    // Crop modal controls.
    const frame = document.getElementById('crop-frame');
    const zoom  = document.getElementById('crop-zoom');
    zoom?.addEventListener('input', () => { _crop.scale = _crop.baseScale * parseFloat(zoom.value); _cropClamp(); _cropApply(); });
    document.getElementById('crop-cancel')?.addEventListener('click', () => document.getElementById('crop-modal').classList.remove('active'));
    document.getElementById('crop-confirm')?.addEventListener('click', confirmCrop);

    // Pan (mouse + touch) and wheel-zoom.
    const down = (cx, cy) => { _crop.dragging = true; _crop.lastX = cx; _crop.lastY = cy; };
    const move = (cx, cy) => { if (!_crop.dragging) return; _crop.x += cx - _crop.lastX; _crop.y += cy - _crop.lastY; _crop.lastX = cx; _crop.lastY = cy; _cropClamp(); _cropApply(); };
    const up = () => { _crop.dragging = false; };
    frame?.addEventListener('mousedown', (e) => { e.preventDefault(); down(e.clientX, e.clientY); });
    window.addEventListener('mousemove', (e) => move(e.clientX, e.clientY));
    window.addEventListener('mouseup', up);
    frame?.addEventListener('touchstart', (e) => down(e.touches[0].clientX, e.touches[0].clientY), { passive: true });
    frame?.addEventListener('touchmove',  (e) => move(e.touches[0].clientX, e.touches[0].clientY), { passive: true });
    frame?.addEventListener('touchend', up, { passive: true });
    frame?.addEventListener('wheel', (e) => {
        e.preventDefault();
        const z = Math.max(1, Math.min(3, parseFloat(zoom.value) - e.deltaY * 0.001));
        zoom.value = z; _crop.scale = _crop.baseScale * z; _cropClamp(); _cropApply();
    }, { passive: false });

    // حفظ runs the save sequence (archives to Firebase, then rip + stamp + fly away).
    document.getElementById('success-save')?.addEventListener('click', runSaveSequence);

    // تجاهل الجلسة — small link under حفظ. Click swaps it for an inline yes/no
    // confirm (mirrors the .inv-del confirm pattern); confirming fades the whole
    // card out and skips saveInvoice() entirely, so nothing reaches Firebase.
    const discardLink = document.getElementById('success-discard');
    const discardConfirm = document.getElementById('success-discard-confirm');
    let discardConfirmTimer = null;
    const resetDiscardConfirm = () => {
        clearTimeout(discardConfirmTimer);
        if (discardConfirm) discardConfirm.style.display = 'none';
        if (discardLink) discardLink.style.display = '';
    };
    discardLink?.addEventListener('click', () => {
        if (_saveSeqRunning) return;
        discardLink.style.display = 'none';
        if (discardConfirm) discardConfirm.style.display = 'inline-flex';
        clearTimeout(discardConfirmTimer);
        discardConfirmTimer = setTimeout(resetDiscardConfirm, 5000);
    });
    document.getElementById('success-discard-no')?.addEventListener('click', resetDiscardConfirm);
    document.getElementById('success-discard-yes')?.addEventListener('click', () => {
        clearTimeout(discardConfirmTimer);
        discardSuccessCard();
    });
}

// Fully discards the current session without saving it anywhere — just fades
// the card out. Called from the تجاهل الجلسة confirm.
function discardSuccessCard() {
    _pendingInvoice = null;   // never persisted, so saveInvoice() has nothing to write
    clearPendingEndCard();
    const modal = document.getElementById('success-modal');
    if (!modal) return;
    modal.classList.add('success-fading');
    setTimeout(() => modal.classList.remove('active', 'success-fading'), 850);
}

// ── End-card appear + حفظ (save) sequence ───────────────────────────────────
let _saveSeqRunning = false;
let _saveBtnTimer = null;

// Called each time the card opens: clear any leftover sequence state and slide the
// حفظ button in once the card's appear animation has settled.
function _successCardOnShow() {
    const card = document.getElementById('success-card');
    const top = document.getElementById('success-cut-top');
    const saveBtn = document.getElementById('success-save');
    const modal = document.getElementById('success-modal');
    if (!card) return;
    _saveSeqRunning = false;
    card.classList.remove('tearing', 'cut-collapsed');
    modal?.classList.remove('success-fading');
    // Force the dark overlay to FADE in (display+opacity flip in one frame otherwise
    // snaps to full dark). Start transparent, then ease to full next frames.
    if (modal) {
        modal.style.opacity = '0';
        modal.style.overflow = '';   // restore the CSS overflow-y:auto (clipping is only for the leave)
        requestAnimationFrame(() => requestAnimationFrame(() => { modal.style.opacity = ''; }));
    }
    card.querySelectorAll('.success-cut-line').forEach(n => n.remove());
    card.style.cssText = '';        // drop the inline animation/transform from a prior sequence
    if (top) top.style.cssText = '';
    const bodyEl = document.getElementById('success-cut-body');
    if (bodyEl) bodyEl.style.cssText = '';   // clear the recenter transform from a prior save
    card.querySelectorAll('.success-stamp, .success-stamp-imprint, .success-star').forEach(n => n.remove());
    // (the "اضافة صورة" button visibility is managed by clearSuccessPhoto on open)
    if (saveBtn) {
        saveBtn.style.display = '';
        saveBtn.classList.remove('show', 'gone');
        clearTimeout(_saveBtnTimer);
        _saveBtnTimer = setTimeout(() => saveBtn.classList.add('show'), 840);   // after appear settles
    }
}

function runSaveSequence() {
    if (_saveSeqRunning) return;
    const modal = document.getElementById('success-modal');
    const card  = document.getElementById('success-card');
    const body  = document.getElementById('success-cut-body');
    const saveBtn = document.getElementById('success-save');
    const addBtn  = document.getElementById('success-add-photo');
    if (!modal || !card || !body) return;
    _saveSeqRunning = true;
    clearTimeout(_saveBtnTimer);
    gameState.focusAudioEngine?.playEffect('invoiceCardSave');   // حفظ pressed → save chime

    // Clip the overlay for the rest of the sequence: the top falls to +115vh and the
    // card leaves to -120vh — without clipping those off-screen transforms spawn a
    // scrollbar (Chrome) and the resulting reflow snaps the backdrop to black (Safari).
    modal.style.overflow = 'hidden';

    saveInvoice();   // persist BEFORE tearing the card apart (reads the photo from the DOM)
    clearPendingEndCard();   // saved — no longer needs to reopen on a reload

    if (saveBtn) { saveBtn.classList.remove('show'); saveBtn.classList.add('gone'); }   // slide down (stays in layout → no snap)
    if (addBtn) addBtn.style.display = 'none';

    card.style.animation = 'none';   // freeze the appear animation so we drive transforms

    // 1) a cut line is drawn left→right across the dashed line (the tear).
    const topEl = document.getElementById('success-cut-top');
    const topH  = topEl ? topEl.offsetHeight : 0;
    const line = document.createElement('div');
    line.className = 'success-cut-line';
    line.style.top = body.offsetTop + 'px';
    card.appendChild(line);
    requestAnimationFrame(() => { line.style.transform = 'scaleX(1)'; });
    // 2) once cut, the whole top piece (its own white paper + text) drops off-screen as
    //    ONE element, and AT THE SAME TIME the body glides up by half the top's height so
    //    the remaining receipt ends centred — one continuous motion, no separate collapse.
    setTimeout(() => {
        card.classList.add('tearing');
        body.style.transition = 'transform 0.9s cubic-bezier(0.5, 0, 0.2, 1)';
        body.style.transform  = `translateY(${-topH / 2}px)`;
        // the cut line fades out as the torn top piece starts dropping (no hard pop-off)
        line.style.transition = 'opacity 0.4s ease';
        line.style.opacity = '0';
    }, 470);
    setTimeout(() => { line.remove(); }, 1330);
    // Once it's off-screen, fully HIDE the fallen top piece — otherwise the final
    // leave (card flies up -120vh) would drag it back onto the screen.
    setTimeout(() => { if (topEl) topEl.style.visibility = 'hidden'; }, 1380);
    // 4) stamp; 5) brief hold; 6) leave with anticipation → slide up → slow fade.
    setTimeout(() => {
        _successRunStamp(body, () => {
            setTimeout(() => {
                // anticipation: a slight, smooth dip down with a tiny rotation…
                card.style.transition = 'transform 0.28s cubic-bezier(0.4, 0, 0.55, 1)';
                card.style.transform  = 'translateY(15px) rotate(1.5deg)';
                setTimeout(() => {
                    // …then smoothly slide up and away with fade + rotation
                    card.style.transition = 'transform 0.8s cubic-bezier(0.5, 0, 0.7, 0.25), opacity 0.72s ease-in';
                    card.style.transform  = 'translateY(-120vh) rotate(-8deg)';
                    card.style.opacity    = '0';
                    // screen darkness + blur fade out slowly, a touch after the card launches
                    setTimeout(() => modal.classList.add('success-fading'), 260);
                    setTimeout(() => { modal.classList.remove('active', 'success-fading'); _saveSeqRunning = false; }, 1100);
                }, 320);
            }, 650);   // brief hold to read the stamped invoice, then leave
        });
    }, 1650);
}

// A wooden stamp tool (Stamp.svg) descends + presses the bottom-left; on impact it
// leaves the logo ink mark (the PNG), bursts stars, then lifts and slides away.
const STAMP_LOGO = 'مدونة ستوديو - شعار ختم.png';
function _successRunStamp(body, done) {
    if (!body) { done && done(); return; }
    const imprint = document.createElement('img');
    imprint.src = STAMP_LOGO; imprint.alt = ''; imprint.className = 'success-stamp-imprint';
    body.appendChild(imprint);
    const stamp = document.createElement('img');
    stamp.src = 'Stamp.svg'; stamp.alt = ''; stamp.className = 'success-stamp';
    body.appendChild(stamp);
    requestAnimationFrame(() => stamp.classList.add('run'));
    setTimeout(() => {                       // impact: ink mark sets in + stars burst
        imprint.classList.add('show');
        _successSpawnStars(body);
    }, 580);
    setTimeout(() => { stamp.remove(); done && done(); }, 1500);
}

// Star particles bursting from the stamp point (bottom-left of the invoice).
function _successSpawnStars(body) {
    const cxL = 8 + 32, cyB = 8 + 32;   // centre of the 64px imprint at left:8 bottom:8
    const N = 14;
    for (let i = 0; i < N; i++) {
        const s = document.createElement('span');
        s.className = 'success-star';
        s.textContent = '✦';
        s.style.left = cxL + 'px';
        s.style.bottom = cyB + 'px';
        const ang = (Math.PI * 2 * i / N) + Math.random() * 0.5;
        const dist = 38 + Math.random() * 56;
        s.style.setProperty('--tx', (Math.cos(ang) * dist).toFixed(1) + 'px');
        s.style.setProperty('--ty', (Math.sin(ang) * dist).toFixed(1) + 'px');
        s.style.setProperty('--rot', Math.floor(Math.random() * 360) + 'deg');
        s.style.fontSize = (11 + Math.random() * 8).toFixed(1) + 'px';
        body.appendChild(s);
        requestAnimationFrame(() => s.classList.add('run'));
        setTimeout(() => s.remove(), 860);
    }
}

// ── Invoice archive: save each end-card (stats + optional photo) to Firebase ──
// Cost-friendly RTDB layout (no live listeners; one-shot get()s only):
//   dashboards/{uid}/invoices/{finishMs}      = { mode, task, minutes, finishMs, hasPhoto }  ← light, listed
//   dashboards/{uid}/invoicePhotos/{finishMs} = "<small JPEG dataURL>"                         ← heavy, lazy-loaded
let _pendingInvoice = null;
const INVOICE_LIMIT = 60;   // browser shows the most-recent N

// Downscale + recompress the card photo to a small 4:3 thumbnail for storage.
function _makeThumb(dataUrl, cb) {
    const img = new Image();
    img.onload = () => {
        try {
            const W = 320, H = 240;
            const cv = document.createElement('canvas'); cv.width = W; cv.height = H;
            cv.getContext('2d').drawImage(img, 0, 0, W, H);
            cb(cv.toDataURL('image/jpeg', 0.55));
        } catch (_) { cb(null); }
    };
    img.onerror = () => cb(null);
    img.src = dataUrl;
}

function saveInvoice() {
    if (!dashTrackingEnabled() || !_pendingInvoice) return;
    const inv = _pendingInvoice; _pendingInvoice = null;
    if ((inv.minutes || 0) * 60000 < DASH_MIN_SESSION_MS) return;   // 10-min floor — never archive short sessions
    const uid = gameState.userId;
    const taped = document.getElementById('success-photo-taped');
    const imgEl = document.getElementById('success-photo-img');
    const hasPhoto = taped && taped.style.display !== 'none' && imgEl && (imgEl.src || '').startsWith('data:');
    const meta = { mode: inv.mode, task: inv.task || null, minutes: inv.minutes, finishMs: inv.finishMs, hasPhoto: !!hasPhoto };
    if (!hasPhoto) {
        update(ref(database), { [`dashboards/${uid}/invoices/${inv.finishMs}`]: meta }).catch(_dashErr('invoice'));
        return;
    }
    _makeThumb(imgEl.src, (thumb) => {
        const updates = {};
        if (thumb) updates[`dashboards/${uid}/invoicePhotos/${inv.finishMs}`] = thumb;
        else meta.hasPhoto = false;
        updates[`dashboards/${uid}/invoices/${inv.finishMs}`] = meta;
        update(ref(database), updates).catch(_dashErr('invoice'));
    });
}

// ── Work-memories view (invoices) — lives inside the dashboard overlay ───────
// Entry: a temp card peeps from the LEFT; clicking it (or swipe-right) slides the
// dashboard off to the right and scatters/flips the real invoice cards into a grid.
let _invOpen = false;     // is the invoices view showing?
let _invBusy = false;     // mid-animation guard (ignore re-clicks)
let _invAnimTimer = null; // cleanup timer for the scatter/flip classes

// Flip cascade pitch: each flipping card plays Paper_Invoice_Flip as its animation STARTS,
// stepping UP in pitch (heavy first → fast last), off a per-reveal randomised base — same
// house style as the UI cascade blip.
let _invFlipBase = 0.72;
let _invFlipCount = 0;    // index passed to the final peep→last flip
function _invPlayFlip(idx) {
    const fe = gameState.focusAudioEngine;
    if (!fe) return;
    const rate = _invFlipBase + Math.min(idx, 14) * 0.05;
    if (!fe.playPitched('paperInvoiceFlip', rate, 0.7)) fe.playEffect('paperInvoiceFlip');
}

function dashOpenInvoices() {
    if (_invOpen || _invBusy || !_dashState.open) return;
    const ov = document.getElementById('dashboard-overlay');
    const view = document.getElementById('dash-invoice-view');
    if (!ov || !view) return;
    _invOpen = true; _invBusy = true;
    dashSound('paperInvoiceIntro');
    // Phase A — smoothly slide the dashboard + to-do away (anticipation easing) while
    // the clicked invoice glides to dead-centre and resets its rotation (CSS handles
    // both via the `.invoices-open` class).
    ov.classList.add('invoices-open');
    view.style.display = 'flex';
    // Build the grid now (cards hidden) so slot positions are measurable.
    dashBuildInvoiceGrid().then((vp) => {
        if (!_invOpen) { _invBusy = false; return; }
        requestAnimationFrame(() => view.classList.add('show'));
        // Phase B — after Phase A settles, deal the cards out one-by-one (each flips in),
        // and finally the clicked peep itself flips into the LAST slot.
        const PHASE_A = 560;
        setTimeout(() => { if (_invOpen) dashRunRevealSequence(vp); }, PHASE_A);
        setTimeout(() => { _invBusy = false; }, PHASE_A + vp.length * 90 + 700);
    });
}

// Build the grid with every card hidden; below-the-fold cards just appear at rest
// (virtualization). Returns the in-viewport cards in order (these get the animation).
function dashBuildInvoiceGrid() {
    return new Promise((resolve) => {
        const grid = document.getElementById('dash-invoice-grid');
        if (!grid) { resolve([]); return; }
        grid.innerHTML = '<div class="inv-empty">…</div>';
        get(ref(database, `dashboards/${dashViewUid()}/invoices`)).then(snap => {
            const raw = snap.val() || {};
            const list = Object.values(raw).filter(Boolean).sort((a, b) => b.finishMs - a.finishMs).slice(0, INVOICE_LIMIT);
            if (!list.length) { grid.innerHTML = '<div class="inv-empty">لا توجد ذكريات عمل محفوظة بعد</div>'; resolve([]); return; }
            grid.innerHTML = list.map(renderInvoiceCard).join('');
            const cards = Array.from(grid.querySelectorAll('.inv-card'));
            const cx = window.innerWidth / 2, cy = window.innerHeight / 2;   // peep centre
            const vp = [];
            cards.forEach((card) => {
                card.classList.add('inv-hidden');
                const r = card.getBoundingClientRect();
                if (r.top < window.innerHeight + 40) {
                    // offset so the card STARTS at the peep's centre, then deals out to its slot
                    card.style.setProperty('--dx', (cx - (r.left + r.width / 2)) + 'px');
                    card.style.setProperty('--dy', (cy - (r.top + r.height / 2)) + 'px');
                    vp.push(card);
                }
            });
            cards.forEach((card) => { if (vp.indexOf(card) === -1) card.classList.remove('inv-hidden'); });
            _lazyLoadInvoicePhotos();
            resolve(vp);
        }).catch(() => { grid.innerHTML = '<div class="inv-empty">تعذّر التحميل</div>'; resolve([]); });
    });
}

// Deal the in-viewport cards out one-by-one (each 3D-flips in), and finally the clicked
// peep itself flips into the LAST slot — "it becomes the last one in order", like the
// top of a stack settling into place once everything below it is sorted out.
function dashRunRevealSequence(vp) {
    const peep = document.getElementById('dash-invoice-peep');
    if (!vp || !vp.length) { if (peep) peep.style.opacity = '0'; return; }
    const STAG = 78;
    const last = vp[vp.length - 1];
    const others = vp.slice(0, -1);
    _invFlipBase = 0.70 + Math.random() * 0.12;   // fresh deep start for this cascade
    _invFlipCount = others.length;                 // the peep→last flip is the highest pitch
    others.forEach((card, i) => setTimeout(() => {
        if (!_invOpen) return;
        card.classList.remove('inv-hidden');
        card.classList.add('inv-flipin');
        _invPlayFlip(i);
    }, i * STAG));
    setTimeout(() => { if (_invOpen) dashPeepBecomeLast(peep, last); }, others.length * STAG + 40);
}

// The peep travels from centre to the last slot and squashes away; the real last card
// flips into its place — so the clickable invoice visually becomes that final card.
function dashPeepBecomeLast(peep, lastCard) {
    if (!lastCard) return;
    if (!peep) { lastCard.classList.remove('inv-hidden'); lastCard.classList.add('inv-flipin'); _invPlayFlip(_invFlipCount); return; }
    const pr = peep.getBoundingClientRect();
    const lr = lastCard.getBoundingClientRect();
    peep.style.setProperty('--tx', ((lr.left + lr.width / 2) - (pr.left + pr.width / 2)) + 'px');
    peep.style.setProperty('--ty', ((lr.top + lr.height / 2) - (pr.top + pr.height / 2)) + 'px');
    peep.classList.add('inv-peep-deliver');
    setTimeout(() => {
        if (!_invOpen) return;   // closed mid-animation — leave the peep for the reset
        peep.style.opacity = '0';
        // The peep already squashed flat; the real card does only the SECOND half of the
        // spin (0→1) so the handoff reads as exactly ONE flip, not two.
        lastCard.classList.remove('inv-hidden');
        lastCard.classList.add('inv-flipin-last');
        _invPlayFlip(_invFlipCount);   // final flip = highest pitch in the sweep
    }, 300);
}

function dashCloseInvoices(instant) {
    const ov = document.getElementById('dashboard-overlay');
    const view = document.getElementById('dash-invoice-view');
    const grid = document.getElementById('dash-invoice-grid');
    if (!ov || !_invOpen) return;
    _invOpen = false;
    if (_invPhotoObserver) { _invPhotoObserver.disconnect(); _invPhotoObserver = null; }
    _invResetPeep();
    if (instant) { ov.classList.remove('invoices-open'); if (view) { view.classList.remove('show'); view.style.display = 'none'; } if (grid) grid.innerHTML = ''; _invBusy = false; return; }
    _invBusy = true;
    dashSound('paperInvoiceExit');
    _invPeepUnderDashboard();                  // keep the peep hidden under the returning dashboard
    ov.classList.remove('invoices-open');      // dashboard + to-do slide back in
    if (view) view.classList.remove('show');   // fade the grid out as the dashboard returns
    setTimeout(() => {
        if (view) view.style.display = 'none';
        if (grid) grid.innerHTML = '';
    }, 520);
    // Once the dashboard has settled back, the invoice peep slides out from under it again.
    setTimeout(() => { if (_dashState.open && !_invOpen) dashSlidePeepOut(); _invBusy = false; }, 640);
}

// Reset the peep back to a clean (visible, no-deliver, no inline transform) state.
function _invResetPeep() {
    const peep = document.getElementById('dash-invoice-peep');
    if (!peep) return;
    peep.classList.remove('inv-peep-deliver');
    peep.style.opacity = '';
    peep.style.transition = '';
    peep.style.transform = '';
    peep.style.removeProperty('--tx');
    peep.style.removeProperty('--ty');
}

// Park the peep hidden (opacity 0) under the dashboard (centred, behind the main paper)
// with no transition. It stays invisible during the dashboard's own intro/return so you
// never glimpse it before its slide-out begins.
function _invPeepUnderDashboard() {
    const peep = document.getElementById('dash-invoice-peep');
    if (!peep) return;
    peep.style.transition = 'none';
    peep.style.transform = 'translate(-50%, -50%) rotate(0deg)';
    peep.style.opacity = '0';
    void peep.offsetWidth;   // commit the start frame
}

// Slide the peep out from under the dashboard to its resting left peek. It becomes
// visible instantly (still hidden behind the dashboard paper), then slides into view.
function dashSlidePeepOut() {
    const peep = document.getElementById('dash-invoice-peep');
    if (!peep) return;
    peep.style.opacity = '1';     // appear instantly while still behind the dashboard
    void peep.offsetWidth;
    peep.style.transition = '';   // back to the .inv-peep CSS transition
    peep.style.transform = '';    // → the side-main peek position (slides out from under)
}

// Hard reset (no animation) — used when the dashboard itself opens/closes.
function dashResetInvoices() {
    _invOpen = false; _invBusy = false;
    clearTimeout(_invAnimTimer);
    if (_invPhotoObserver) { _invPhotoObserver.disconnect(); _invPhotoObserver = null; }
    const ov = document.getElementById('dashboard-overlay');
    const view = document.getElementById('dash-invoice-view');
    const grid = document.getElementById('dash-invoice-grid');
    ov?.classList.remove('invoices-open');
    _invResetPeep();
    if (view) { view.classList.remove('show'); view.style.display = 'none'; }
    if (grid) grid.innerHTML = '';
}

// Delete one saved memory (metadata + photo) after the per-card confirm.
function dashDeleteInvoice(fm, card) {
    if (!fm || dashReadOnly() || !gameState.userId) return;
    const uid = gameState.userId;
    update(ref(database), {
        [`dashboards/${uid}/invoices/${fm}`]: null,
        [`dashboards/${uid}/invoicePhotos/${fm}`]: null,
    }).catch(_dashErr('invoice-del'));
    dashSound('paperExit');
    if (card) {
        card.style.transition = 'transform 0.3s ease, opacity 0.3s ease';
        card.style.transform = 'scale(0.6)'; card.style.opacity = '0';
        setTimeout(() => card.remove(), 300);
    }
}

// The memory cards are the end-of-session receipt CROPPED at the dashed line under
// "جزيتم خيرًا" — so no avatar / أحسنتم / جزيتم خيرًا; the card starts at the photo,
// then stats, note, date, barcode. A dashed line sits at the very top as the crop edge.
// `data` null → blank template (the clickable peep): placeholder photo + scribble text.
function _invReceiptHTML(data) {
    const ph = !data;
    const photo = ph
        ? `<div class="inv-r-photo inv-r-photo-blank"><span class="inv-r-photo-ico">📷</span></div>`
        : (data.photoHtml || `<div class="inv-r-photo inv-r-photo-blank"><span class="inv-r-photo-ico">📷</span></div>`);
    const valHtml  = ph ? `<span class="inv-scrib" style="width:62%"></span>` : escapeDashHtml(data.time);
    const subHtml  = ph ? `<span class="inv-scrib" style="width:38%"></span>` : escapeDashHtml(data.tag);
    const noteHtml = ph ? `<span class="inv-scrib" style="width:70%"></span>` : (data.task ? escapeDashHtml(data.task) : 'جلسة عمل');
    const dateHtml = ph ? '' : escapeDashHtml(data.dateStr);
    // same ink-mark logo + opacity + corner as the end-of-session stamp (STAMP_LOGO,
    // .success-stamp-imprint) so a saved memory card matches the invoice it came from.
    const logoHtml = ph ? '' : `<img src="${STAMP_LOGO}" alt="" class="inv-r-logo">`;
    return `<div class="inv-receipt">
        <div class="inv-r-crop"></div>
        ${photo}
        <div class="inv-r-stats">
            <div class="inv-r-stats-label">إجمالي وقت العمل</div>
            <div class="inv-r-stats-value">${valHtml}</div>
            <div class="inv-r-stats-sub">${subHtml}</div>
        </div>
        <div class="inv-r-note">${noteHtml}</div>
        <div class="inv-r-date">${dateHtml}</div>
        <div class="inv-r-barcode"><div class="inv-r-bars"></div><div class="inv-r-num">MDWNH · 1445</div></div>
        ${logoHtml}
    </div>`;
}

function renderInvoiceCard(inv) {
    const d = new Date(inv.finishMs);
    let dateStr; try { dateStr = d.toLocaleDateString('ar-EG', { day: 'numeric', month: 'long', year: 'numeric' }); }
    catch (_) { dateStr = ''; }
    const time = formatDurationArabic(inv.minutes || 0);
    const tag = inv.mode === 'free' ? 'وضع حر' : 'بومودورو';
    const photoHtml = inv.hasPhoto
        ? `<div class="inv-r-photo" data-fm="${inv.finishMs}"><div class="inv-spin"></div></div>`
        : `<div class="inv-r-photo inv-r-photo-blank"><span class="inv-r-photo-ico">📋</span></div>`;
    const back = _invReceiptHTML({ time, tag, task: inv.task, dateStr, photoHtml });
    const front = _invReceiptHTML(null);
    const fm = inv.finishMs;
    return `<div class="inv-card">
        <div class="inv-flip">
            <div class="inv-face inv-front">${front}</div>
            <div class="inv-face inv-back">${back}</div>
        </div>
        <button class="inv-del" data-fm="${fm}" aria-label="حذف الذكرى">✕</button>
        <div class="inv-confirm">
            <div class="inv-confirm-q">حذف هذه الذكرى؟</div>
            <div class="inv-confirm-row">
                <button class="inv-confirm-yes" data-fm="${fm}">حذف</button>
                <button class="inv-confirm-no">إلغاء</button>
            </div>
        </div>
    </div>`;
}

// Fill the peep with a blank (placeholder) cropped receipt — identical in size/look to
// a grid memory card, but with a placeholder photo + scribble text instead of data.
function dashRenderInvoicePeep() {
    const peep = document.getElementById('dash-invoice-peep');
    if (peep) peep.innerHTML = _invReceiptHTML(null);
}

// Lazy-load each card's photo only when it scrolls into view (keeps downloads minimal).
// One observer is kept alive across opens (`_invPhotoObserver`) — cards below the fold
// never scroll into view and were never unobserved/disconnected, so every open/close of
// the memories view (a normal, frequent action) leaked a whole new IntersectionObserver
// still pinned to the previous grid's (by-then-detached) nodes.
let _invPhotoObserver = null;
function _lazyLoadInvoicePhotos() {
    const root = document.getElementById('dash-invoice-grid');
    const slots = document.querySelectorAll('#dash-invoice-grid .inv-r-photo[data-fm]');
    const load = (slot) => {
        const fm = slot.dataset.fm; if (!fm) return;
        slot.removeAttribute('data-fm');
        get(ref(database, `dashboards/${dashViewUid()}/invoicePhotos/${fm}`)).then(s => {
            const url = s.val();
            if (url) { slot.innerHTML = `<img src="${url}" alt="">`; }
            else { slot.classList.add('inv-r-photo-blank'); slot.innerHTML = '<span class="inv-r-photo-ico">📋</span>'; }
        }).catch(() => { slot.classList.add('inv-r-photo-blank'); slot.innerHTML = '<span class="inv-r-photo-ico">📋</span>'; });
    };
    if (_invPhotoObserver) { _invPhotoObserver.disconnect(); _invPhotoObserver = null; }
    if ('IntersectionObserver' in window) {
        const io = new IntersectionObserver((entries, obs) => {
            entries.forEach(en => { if (en.isIntersecting) { load(en.target); obs.unobserve(en.target); } });
        }, { root, rootMargin: '200px' });
        slots.forEach(s => io.observe(s));
        _invPhotoObserver = io;
    } else {
        slots.forEach(load);
    }
}

// Inject a batch of mock invoices for testing the grid/virtualization. Restricted to
// Siraj test ghosts (their dashboard node is ephemeral — removed on disconnect), so it
// never pollutes the owner's real work memories. Run once per ghost session.
const DASH_MOCK_INVOICE_COUNT = 80;
function _mockInvoicePhoto(i) {
    try {
        const cv = document.createElement('canvas'); cv.width = 80; cv.height = 60;
        const g = cv.getContext('2d').createLinearGradient(0, 0, 80, 60);
        const hue = (i * 47) % 360;
        g.addColorStop(0, `hsl(${hue},55%,55%)`); g.addColorStop(1, `hsl(${(hue + 60) % 360},55%,40%)`);
        const ctx2 = cv.getContext('2d'); ctx2.fillStyle = g; ctx2.fillRect(0, 0, 80, 60);
        return cv.toDataURL('image/jpeg', 0.5);
    } catch (_) { return null; }
}
function dashSeedMockInvoices() {
    if (!gameState.isSirajGhost || !gameState.userId) return;
    const uid = gameState.userId;
    const tasks = ['مراجعة الكود', 'قراءة كتاب', 'حفظ القرآن', 'حل تمارين الرياضيات', 'كتابة المقال',
        'تصميم الواجهة', 'مذاكرة الفيزياء', 'تنظيم المهام', 'بحث علمي', 'تعلّم لغة جديدة', 'مراجعة عامة'];
    const updates = {};
    const now = Date.now();
    for (let i = 0; i < DASH_MOCK_INVOICE_COUNT; i++) {
        const fm = now - (i + 1) * 3600000 * (2 + (i % 6));
        const mode = i % 3 === 0 ? 'free' : 'pomodoro';
        const minutes = 15 + ((i * 13) % 170);
        const hasPhoto = i % 4 === 0;
        updates[`dashboards/${uid}/invoices/${fm}`] = { mode, task: tasks[i % tasks.length], minutes, finishMs: fm, hasPhoto };
        if (hasPhoto) { const ph = _mockInvoicePhoto(i); if (ph) updates[`dashboards/${uid}/invoicePhotos/${fm}`] = ph; }
    }
    update(ref(database), updates).catch(_dashErr('mock-invoices'));
}


// ═══════════════════════════════════════════════════════════════════════════════
//  BOOK COVERS — procedurally drawn 3D book art (inline SVG)
//
//  Every book the user adds is drawn, never uploaded: a style id + the book's name
//  are all we store. `bookCoverSVG(styleId, name)` returns a self-contained <svg>
//  string — one two-point-perspective book (spine face on the left, front cover
//  facing the viewer) with a gradient cover, a per-style decoration, a hinge
//  groove, a diagonal sheen and the title typed on top.
//
//  It must be injected as INLINE svg (innerHTML), never as an <img src="data:…">:
//  an <img>-hosted SVG can't reach the page's fonts, so the Arabic title would
//  fall back to a system font (or not shape at all).
//
//  Geometry lives in a single helper: _bkP(u, t) maps a cover-relative coordinate
//  (u = 0 spine edge → 1 fore edge, t = 0 top → 1 bottom) to the perspective-
//  projected point. Every decoration is built from it, so nothing has to hand-
//  compute the slanted edges.
// ═══════════════════════════════════════════════════════════════════════════════

function _bkP(u, t) {
    return [74 + 140 * u, (22 + 30 * u) + t * (282 - 60 * u)];
}
function _bkPts(list) {
    return list.map(([u, t]) => _bkP(u, t).map(n => n.toFixed(1)).join(',')).join(' ');
}
const _BK_SPINE_U = -30 / 140;   // spine face depth, in cover-width units

function _bkEsc(s) {
    return String(s).replace(/[&<>"']/g, c => (
        { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]
    ));
}

// `text` is checked against `cover` for contrast; `halo` is the paint-order stroke
// behind the title, always the opposite lightness of `text`, so the name stays
// readable no matter what the decoration paints underneath it.
const BOOK_STYLES = [
    { id: 'emerald',  label: 'زمرد',    cover: '#125c3d', cover2: '#0a3524', spine: '#082a1c', accent: '#d4af58', text: '#f6e3a8', halo: '#06251a', deco: 'leaves' },
    { id: 'crimson',  label: 'قرمزي',   cover: '#8e1c26', cover2: '#5a0f16', spine: '#4a0c12', accent: '#e0b45c', text: '#f8e6c4', halo: '#3c080d', deco: 'bands' },
    { id: 'midnight', label: 'ليل',     cover: '#16234d', cover2: '#0a1130', spine: '#080d24', accent: '#c9bd6e', text: '#e8dfa6', halo: '#050a1c', deco: 'stars' },
    { id: 'sand',     label: 'رمل',     cover: '#e2cfa6', cover2: '#c9ac74', spine: '#a98b55', accent: '#8a6a34', text: '#4a3417', halo: '#f6ecd5', deco: 'arabesque' },
    { id: 'plum',     label: 'بنفسج',   cover: '#4a2160', cover2: '#2b0f3c', spine: '#240c33', accent: '#b98ad6', text: '#f0dcff', halo: '#1c0828', deco: 'diagonals' },
    { id: 'ocean',    label: 'محيط',    cover: '#126b78', cover2: '#083c46', spine: '#06303a', accent: '#7fd8e4', text: '#e6fbff', halo: '#04252c', deco: 'waves' },
    { id: 'charcoal', label: 'فحم',     cover: '#26262b', cover2: '#131317', spine: '#0d0d10', accent: '#8f8f9c', text: '#e6e6ea', halo: '#0a0a0d', deco: 'grid' },
    { id: 'amber',    label: 'كهرمان',  cover: '#d99521', cover2: '#a86a10', spine: '#8a540b', accent: '#5c3a08', text: '#3a2405', halo: '#f6d99a', deco: 'dots' },
    { id: 'rose',     label: 'ورد',     cover: '#c98a9a', cover2: '#a45f74', spine: '#8b4a5e', accent: '#f4dfe6', text: '#3d1220', halo: '#f6e4ea', deco: 'floral' },
    { id: 'forest',   label: 'زيتون',   cover: '#4a5a24', cover2: '#2e3a13', spine: '#242e0e', accent: '#cfd8a0', text: '#f4f0dc', halo: '#1a2109', deco: 'stripes' },
];

function bookStyleById(id) {
    return BOOK_STYLES.find(s => s.id === id) || BOOK_STYLES[0];
}
// Books saved before covers existed have no style — give them a stable one derived
// from the name so the same book always looks the same.
function bookStyleForName(name) {
    let h = 0;
    const s = String(name || '');
    for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) >>> 0;
    return BOOK_STYLES[h % BOOK_STYLES.length].id;
}

function _bkDeco(kind, s, id) {
    const A = s.accent;
    if (kind === 'leaves') {
        const stem = (u0, t0, u1, t1, u2, t2) => {
            const a = _bkP(u0, t0), b = _bkP(u1, t1), c = _bkP(u2, t2);
            return `<path d="M${a[0].toFixed(1)},${a[1].toFixed(1)} Q${b[0].toFixed(1)},${b[1].toFixed(1)} ${c[0].toFixed(1)},${c[1].toFixed(1)}" fill="none" stroke="${A}" stroke-width="1.4" opacity="0.6"/>`;
        };
        const leaf = (u, t, r, rot) => {
            const [x, y] = _bkP(u, t), X = x.toFixed(1), Y = y.toFixed(1);
            return `<ellipse cx="${X}" cy="${Y}" rx="${r}" ry="${(r * 0.4).toFixed(1)}" fill="${A}" opacity="0.55" transform="rotate(${rot} ${X} ${Y})"/>`;
        };
        return `<polygon points="${_bkPts([[0.08, 0.04], [0.92, 0.04], [0.92, 0.96], [0.08, 0.96]])}" fill="none" stroke="${A}" stroke-width="1.5" opacity="0.5"/>`
            + stem(0.16, 0.94, 0.34, 0.72, 0.28, 0.52) + leaf(0.22, 0.86, 8, -30) + leaf(0.32, 0.76, 7, 20) + leaf(0.26, 0.62, 6, -45)
            + stem(0.84, 0.06, 0.66, 0.28, 0.72, 0.48) + leaf(0.78, 0.14, 8, 150) + leaf(0.68, 0.24, 7, 200) + leaf(0.74, 0.38, 6, 135);
    }
    if (kind === 'bands') {
        const band = (t0, t1, o) => `<polygon points="${_bkPts([[0, t0], [1, t0], [1, t1], [0, t1]])}" fill="${A}" opacity="${o}"/>`;
        return band(0.10, 0.145, 0.85) + band(0.162, 0.177, 0.5)
             + band(0.823, 0.838, 0.5) + band(0.855, 0.9, 0.85);
    }
    if (kind === 'stars') {
        const star = (u, t, r, o) => {
            const [x, y] = _bkP(u, t), q = r * 0.18;
            return `<path d="M${x.toFixed(1)} ${(y - r).toFixed(1)} Q${(x + q).toFixed(1)} ${(y - q).toFixed(1)} ${(x + r).toFixed(1)} ${y.toFixed(1)} Q${(x + q).toFixed(1)} ${(y + q).toFixed(1)} ${x.toFixed(1)} ${(y + r).toFixed(1)} Q${(x - q).toFixed(1)} ${(y + q).toFixed(1)} ${(x - r).toFixed(1)} ${y.toFixed(1)} Q${(x - q).toFixed(1)} ${(y - q).toFixed(1)} ${x.toFixed(1)} ${(y - r).toFixed(1)}Z" fill="${A}" opacity="${o}"/>`;
        };
        const [cx, cy] = _bkP(0.5, 0.17);
        // Crescent = a disc with an offset disc punched out of it. Done with a mask
        // rather than two arcs in one path: an arc whose radius is smaller than half
        // its chord gets silently scaled UP to fit by the SVG spec, which turned the
        // obvious two-arc version into a plain filled circle.
        const cres = `<mask id="${id}m">`
            + `<circle cx="${cx.toFixed(1)}" cy="${cy.toFixed(1)}" r="12" fill="#ffffff"/>`
            + `<circle cx="${(cx + 5.5).toFixed(1)}" cy="${(cy - 1.5).toFixed(1)}" r="10" fill="#000000"/></mask>`
            + `<circle cx="${cx.toFixed(1)}" cy="${cy.toFixed(1)}" r="12" fill="${A}" opacity="0.8" mask="url(#${id}m)"/>`;
        return cres + star(0.20, 0.10, 5, 0.7) + star(0.80, 0.20, 4, 0.55) + star(0.30, 0.86, 4.5, 0.6)
             + star(0.72, 0.92, 3.5, 0.5) + star(0.14, 0.44, 3, 0.4) + star(0.88, 0.62, 4, 0.5) + star(0.5, 0.66, 2.5, 0.3);
    }
    if (kind === 'arabesque') {
        return `<polygon points="${_bkPts([[0.08, 0.04], [0.92, 0.04], [0.92, 0.96], [0.08, 0.96]])}" fill="none" stroke="${A}" stroke-width="1.8" opacity="0.5"/>`
             + `<polygon points="${_bkPts([[0.12, 0.07], [0.88, 0.07], [0.88, 0.93], [0.12, 0.93]])}" fill="none" stroke="${A}" stroke-width="0.8" opacity="0.4"/>`
             + `<polygon points="${_bkPts([[0.5, 0.13], [0.86, 0.5], [0.5, 0.87], [0.14, 0.5]])}" fill="none" stroke="${A}" stroke-width="1.2" opacity="0.32"/>`
             + `<polygon points="${_bkPts([[0.5, 0.23], [0.74, 0.5], [0.5, 0.77], [0.26, 0.5]])}" fill="none" stroke="${A}" stroke-width="1" opacity="0.24"/>`;
    }
    if (kind === 'diagonals') {
        let out = '';
        for (let i = -6; i <= 12; i++) {
            const u0 = i * 0.14, u1 = u0 + 0.07;
            out += `<polygon points="${_bkPts([[u0, 0], [u1, 0], [u1 + 0.5, 1], [u0 + 0.5, 1]])}" fill="${A}" opacity="0.16"/>`;
        }
        return out;
    }
    if (kind === 'waves') {
        let out = '';
        for (let i = 0; i < 5; i++) {
            const t = 0.14 + i * 0.18, p = [];
            for (let k = 0; k <= 8; k++) {
                const [x, y] = _bkP(k / 8, t + Math.sin(k * 0.9 + i) * 0.022);
                p.push(`${x.toFixed(1)},${y.toFixed(1)}`);
            }
            out += `<polyline points="${p.join(' ')}" fill="none" stroke="${A}" stroke-width="2" opacity="0.38" stroke-linecap="round"/>`;
        }
        return out;
    }
    if (kind === 'grid') {
        let out = '';
        for (let i = 1; i < 5; i++) out += `<polygon points="${_bkPts([[i / 5, 0], [i / 5 + 0.006, 0], [i / 5 + 0.006, 1], [i / 5, 1]])}" fill="${A}" opacity="0.18"/>`;
        for (let j = 1; j < 7; j++) out += `<polygon points="${_bkPts([[0, j / 7], [1, j / 7], [1, j / 7 + 0.005], [0, j / 7 + 0.005]])}" fill="${A}" opacity="0.18"/>`;
        out += `<polyline points="${_bkPts([[0.08, 0.14], [0.08, 0.04], [0.24, 0.04]])}" fill="none" stroke="${A}" stroke-width="2" opacity="0.7"/>`;
        out += `<polyline points="${_bkPts([[0.92, 0.86], [0.92, 0.96], [0.76, 0.96]])}" fill="none" stroke="${A}" stroke-width="2" opacity="0.7"/>`;
        return out;
    }
    if (kind === 'dots') {
        // Deterministic LCG — the same book must scatter its dots identically on
        // every render (the carousel rebuilds these constantly).
        let seed = 7, out = '';
        const rnd = () => { seed = (seed * 1103515245 + 12345) & 0x7fffffff; return seed / 0x7fffffff; };
        for (let i = 0; i < 34; i++) {
            const [x, y] = _bkP(rnd(), rnd()), r = 1 + rnd() * 3.2;
            out += `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${r.toFixed(1)}" fill="${A}" opacity="${(0.18 + rnd() * 0.3).toFixed(2)}"/>`;
        }
        return out;
    }
    if (kind === 'floral') {
        const flower = (u, t, r, o) => {
            const [x, y] = _bkP(u, t);
            let g = '';
            for (let k = 0; k < 5; k++) {
                const a = k * Math.PI * 2 / 5;
                g += `<circle cx="${(x + Math.cos(a) * r).toFixed(1)}" cy="${(y + Math.sin(a) * r).toFixed(1)}" r="${(r * 0.62).toFixed(1)}" fill="${A}" opacity="${o}"/>`;
            }
            return g + `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${(r * 0.42).toFixed(1)}" fill="${A}" opacity="${Math.min(1, o + 0.2)}"/>`;
        };
        return flower(0.20, 0.12, 6, 0.4) + flower(0.82, 0.28, 5, 0.32) + flower(0.28, 0.88, 5.5, 0.36)
             + flower(0.76, 0.80, 4.5, 0.3) + flower(0.12, 0.60, 4, 0.26) + flower(0.9, 0.94, 3.5, 0.24);
    }
    if (kind === 'stripes') {
        let out = '';
        for (let i = 0; i < 6; i++) {
            const u0 = 0.06 + i * 0.16;
            out += `<polygon points="${_bkPts([[u0, 0], [u0 + 0.055, 0], [u0 + 0.055, 1], [u0, 1]])}" fill="${A}" opacity="0.14"/>`;
        }
        // Dark title band across the middle — the stripes would otherwise run
        // straight through the name.
        out += `<polygon points="${_bkPts([[0, 0.34], [1, 0.34], [1, 0.66], [0, 0.66]])}" fill="${s.cover2}" opacity="0.9"/>`;
        return out;
    }
    return '';
}

// Greedy word wrap for the cover title. Long single words are hard-cut rather than
// allowed to overflow the cover.
function _bkWrap(name, maxChars, maxLines) {
    const words = String(name || '').trim().split(/\s+/).filter(Boolean);
    if (!words.length) return ['كتاب'];
    const lines = [];
    let cur = '';
    for (let w of words) {
        while (w.length > maxChars) {
            if (cur) { lines.push(cur); cur = ''; }
            lines.push(w.slice(0, maxChars));
            w = w.slice(maxChars);
        }
        const next = cur ? cur + ' ' + w : w;
        if (next.length > maxChars && cur) { lines.push(cur); cur = w; }
        else cur = next;
    }
    if (cur) lines.push(cur);
    if (lines.length > maxLines) {
        lines.length = maxLines;
        lines[maxLines - 1] = lines[maxLines - 1].slice(0, maxChars - 1) + '…';
    }
    return lines;
}

let _bkUid = 0;
// opts.noText — cover art only (used for the style swatches, where the label sits
// under the book rather than on it).
function bookCoverSVG(styleId, name, opts) {
    const s = bookStyleById(styleId);
    const o = opts || {};
    const id = 'bk' + (++_bkUid);
    const coverPts = _bkPts([[0, 0], [1, 0], [1, 1], [0, 1]]);
    const spinePts = _bkPts([[_BK_SPINE_U, 0], [0, 0], [0, 1], [_BK_SPINE_U, 1]]);

    let title = '';
    if (!o.noText) {
        const lines = _bkWrap(name, 13, 3);
        const fs = lines.length >= 3 ? 17 : (lines.length === 2 ? 20 : 23);
        const lh = fs * 1.28;
        // A real book's title is a HEADER: up near the top of the cover, and lying
        // flat along the cover rather than raked across it. The old version sat dead
        // centre at a fixed 12.1° — the tilt of the cover's TOP edge — which read as
        // wildly slanted, because the projection only tilts horizontals near the top:
        // at t = 0.5 a horizontal line on this cover is exactly level, so a 12.1°
        // title fought the shape it sat on.
        //
        // Fix both at once: park the block around t = TT (upper third) and rotate it
        // by the tilt of the cover's own horizontal AT that t. From _bkP, the line at
        // t runs (74, 22 + 282t) → (214, 52 + 222t), i.e. rise (30 − 60t) over run 140.
        const TT = 0.19;
        const [tx, ty] = _bkP(0.5, TT);
        const angle = Math.atan2(30 - 60 * TT, 140) * 180 / Math.PI;   // ≈ 7.6°
        const y0 = ty - ((lines.length - 1) * lh) / 2 + fs * 0.34;   // manual baseline centring:
        //   dominant-baseline on <tspan> is unreliable in Safari, so nudge by hand.
        const tspans = lines.map((ln, i) =>
            `<tspan x="${tx.toFixed(1)}" y="${(y0 + i * lh).toFixed(1)}">${_bkEsc(ln)}</tspan>`).join('');
        title = `<text text-anchor="middle" direction="rtl" font-family="Rubik, sans-serif" font-weight="800"`
              + ` font-size="${fs}" fill="${s.text}" stroke="${s.halo}" stroke-width="3.4" stroke-linejoin="round"`
              + ` paint-order="stroke" transform="rotate(${angle.toFixed(2)} ${tx.toFixed(1)} ${ty.toFixed(1)})">${tspans}</text>`;
    }

    return `<svg viewBox="0 0 250 332" xmlns="http://www.w3.org/2000/svg" class="book-svg" role="img" aria-label="${_bkEsc(name || 'كتاب')}">
  <defs>
    <linearGradient id="${id}c" x1="0" y1="0" x2="1" y2="0.35">
      <stop offset="0" stop-color="${s.cover}"/><stop offset="0.6" stop-color="${s.cover}"/><stop offset="1" stop-color="${s.cover2}"/>
    </linearGradient>
    <linearGradient id="${id}s" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0" stop-color="${s.cover2}"/><stop offset="1" stop-color="${s.spine}"/>
    </linearGradient>
    <linearGradient id="${id}g" x1="0.05" y1="0" x2="0.95" y2="1">
      <stop offset="0" stop-color="#ffffff" stop-opacity="0.20"/>
      <stop offset="0.45" stop-color="#ffffff" stop-opacity="0.05"/>
      <stop offset="1" stop-color="#000000" stop-opacity="0.18"/>
    </linearGradient>
    <clipPath id="${id}k"><polygon points="${coverPts}"/></clipPath>
  </defs>
  <ellipse cx="129" cy="318" rx="86" ry="11" fill="#000000" opacity="0.30"/>
  <polygon points="${spinePts}" fill="url(#${id}s)"/>
  <polygon points="${coverPts}" fill="url(#${id}c)"/>
  <g clip-path="url(#${id}k)">
    ${_bkDeco(s.deco, s, id)}
    <polygon points="${_bkPts([[0, 0], [0.05, 0], [0.05, 1], [0, 1]])}" fill="#000000" opacity="0.3"/>
    <polygon points="${coverPts}" fill="url(#${id}g)"/>
  </g>
  <polygon points="${coverPts}" fill="none" stroke="#000000" stroke-opacity="0.35" stroke-width="1"/>
  ${title}
</svg>`;
}

// ═══════════════════════════════════════════════════════════════════════════════
//  READING SESSION FEATURE
// ═══════════════════════════════════════════════════════════════════════════════

const READING_BOOK_LIMIT = 24;   // shelf cap — also what we prune to on add

function setupReadingUI() {
    const timeOptions = document.getElementById('reading-time-options');
    const customTimeInput = document.getElementById('reading-custom-time');

    // Time preset buttons
    if (timeOptions) {
        timeOptions.querySelectorAll('.opt-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                timeOptions.querySelectorAll('.opt-btn').forEach(b => b.classList.remove('active'));
                btn.classList.add('active');
                if (customTimeInput) customTimeInput.value = '';
            });
        });
    }

    if (customTimeInput) {
        customTimeInput.addEventListener('input', () => {
            if (customTimeInput.value) {
                timeOptions.querySelectorAll('.opt-btn').forEach(b => b.classList.remove('active'));
            } else {
                timeOptions.querySelector('.opt-btn[data-val="30"]')?.classList.add('active');
            }
        });
    }

    document.getElementById('reading-confirm')?.addEventListener('click', () => {
        let mins = 30;
        const activeBtn = timeOptions?.querySelector('.opt-btn.active');
        if (customTimeInput && customTimeInput.value) {
            mins = parseInt(customTimeInput.value, 10);
            if (isNaN(mins) || mins < 5) mins = 5;
            if (mins > 120) mins = 120;
        } else if (activeBtn) {
            mins = parseInt(activeBtn.getAttribute('data-val'), 10);
        }

        const book = gameState._readingSelectedBook;
        if (!book) { openNewBookModal(); return; }   // nothing on the shelf yet
        startReadingSession(mins, book.name, book.style);
    });

    document.getElementById('reading-cancel')?.addEventListener('click', closeReadingPopup);

    // Click the backdrop itself (not the card) to dismiss, same pattern as the
    // other click-outside-closes modals.
    document.getElementById('reading-modal')?.addEventListener('click', (e) => {
        if (e.target === e.currentTarget) closeReadingPopup();
    });

    // Shelf: the card nearest the track's centre is the selection. Recompute on
    // scroll (rAF-coalesced — the scroll event fires far faster than we can care).
    const track = document.getElementById('reading-shelf-track');
    if (track) {
        let raf = 0;
        track.addEventListener('scroll', () => {
            if (raf) return;
            raf = requestAnimationFrame(() => { raf = 0; _readingSyncShelfSelection(); });
        }, { passive: true });
    }

    // ── New-book modal ──
    document.getElementById('reading-newbook-cancel')?.addEventListener('click', closeNewBookModal);
    document.getElementById('reading-newbook-modal')?.addEventListener('click', (e) => {
        if (e.target === e.currentTarget) closeNewBookModal();
    });
    const nbName = document.getElementById('reading-newbook-name');
    nbName?.addEventListener('input', _renderNewBookPreview);
    nbName?.addEventListener('keydown', (e) => { if (e.key === 'Enter') confirmNewBook(); });
    document.getElementById('reading-newbook-add')?.addEventListener('click', confirmNewBook);

    // ── Delete confirm ──
    document.getElementById('reading-delete-yes')?.addEventListener('click', () => {
        document.getElementById('reading-delete-modal')?.classList.remove('active');
        const slug = gameState._readingDeleteSlug;
        if (!slug) return;
        remove(ref(database, `dashboards/${gameState.userId}/reading/books/${slug}`)).catch(() => {});
        if (gameState._readingBooks) delete gameState._readingBooks[slug];
        gameState._readingDeleteSlug = null;
        renderReadingShelf();
    });
    document.getElementById('reading-delete-no')?.addEventListener('click', () => {
        document.getElementById('reading-delete-modal')?.classList.remove('active');
        gameState._readingDeleteSlug = null;
    });

    // ── Exit bindings ──
    const attemptExit = () => document.getElementById('reading-exit-modal')?.classList.add('active');
    document.getElementById('reading-exit-btn')?.addEventListener('click', attemptExit);
    document.getElementById('reading-mobile-exit-btn')?.addEventListener('click', attemptExit);

    document.getElementById('reading-exit-no')?.addEventListener('click', () => {
        document.getElementById('reading-exit-modal')?.classList.remove('active');
    });
    document.getElementById('reading-exit-yes')?.addEventListener('click', () => {
        document.getElementById('reading-exit-modal')?.classList.remove('active');
        endReadingSession(true);
    });

    // Mobile drawer handle — bidirectional drag (open from the collapsed peek OR
    // close from open), Instagram-comments style: a quick flick wins outright
    // regardless of distance, a slow drag only needs a small pull, and a plain tap
    // toggles. No separate `click` listener — it fired AFTER pointerup and had
    // already un-done whatever pointerup had just decided.
    const drawer = document.getElementById('reading-drawer');
    const handle = drawer?.querySelector('.mobile-drawer-handle');
    if (handle && drawer) {
        let dragStartY = 0, dragStartTranslate = 0, currentTranslate = 0, isDragging = false;
        let lastMoveY = 0, lastMoveT = 0, velocity = 0; // px/ms, +down / -up
        const PEEK = 48; // px visible when collapsed (matches .reading-drawer's resting transform)
        const DIST_FRACTION = 0.22;
        const FLICK_VELOCITY = 0.5;
        const getCollapsedTranslate = () => drawer.offsetHeight - PEEK;

        handle.addEventListener('pointerdown', e => {
            isDragging = true;
            dragStartY = e.clientY;
            dragStartTranslate = drawer.classList.contains('drawer-open') ? 0 : getCollapsedTranslate();
            currentTranslate = dragStartTranslate;
            lastMoveY = dragStartY;
            lastMoveT = performance.now();
            velocity = 0;
            drawer.style.transition = 'none';
        });
        window.addEventListener('pointermove', e => {
            if (!isDragging) return;
            const y = e.clientY;
            const now = performance.now();
            const dt = now - lastMoveT;
            if (dt > 0) velocity = (y - lastMoveY) / dt;
            lastMoveY = y; lastMoveT = now;
            const collapsed = getCollapsedTranslate();
            currentTranslate = Math.max(0, Math.min(collapsed, dragStartTranslate + (y - dragStartY)));
            drawer.style.transform = `translateY(${currentTranslate}px)`;
        });
        window.addEventListener('pointerup', () => {
            if (!isDragging) return;
            isDragging = false;
            drawer.style.transition = 'transform 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94)';
            const collapsed = getCollapsedTranslate();
            let openIt;
            if (Math.abs(currentTranslate - dragStartTranslate) < 6) {
                openIt = dragStartTranslate > 0; // plain tap — toggle from whatever it was
            } else if (Math.abs(velocity) > FLICK_VELOCITY) {
                openIt = velocity < 0;
            } else {
                openIt = currentTranslate < collapsed * DIST_FRACTION;
            }
            drawer.classList.toggle('drawer-open', openIt);
            drawer.style.transform = '';
        });
    }

    // Register animation for sequence cascade
    _JUICE_IN_ANIMS.add('readingRowIn');
}

function openReadingPopup() {
    if (gameState.reading.active || gameState.isLockedIn) return;
    const modal = document.getElementById('reading-modal');
    if (!modal) return;
    // Lock movement while the popup is open, same as every other modal.
    gameState.isLockedIn = true;
    modal.classList.add('active');
    _uiSeqReset();   // start the row cascade's pitch sweep fresh (deep → high)

    // Reset defaults
    document.getElementById('reading-custom-time').value = '';
    const timeOptions = document.getElementById('reading-time-options');
    timeOptions.querySelectorAll('.opt-btn').forEach(b => b.classList.remove('active'));
    timeOptions.querySelector('.opt-btn[data-val="30"]')?.classList.add('active');

    // Render whatever we already have (instant shelf on a re-open), then refresh.
    renderReadingShelf();

    get(ref(database, `dashboards/${gameState.userId}/reading`)).then(snap => {
        const data = snap.exists() ? (snap.val() || {}) : {};
        gameState._readingBooks = data.books || {};
        gameState._readingLastBook = data.lastBook || null;
        renderReadingShelf();
    }).catch(() => {});
}

// Formats a duration in ms as "X ساعة و Y دقيقة" (drops the hours part when zero).
function _formatReadingDuration(ms) {
    const hrs = Math.floor(ms / 3600000);
    const mins = Math.floor((ms % 3600000) / 60000);
    return hrs > 0 ? `${hrs} ساعة و ${mins} دقيقة` : `${mins} دقيقة`;
}

// Shelf order = newest first (leftmost), oldest to the right. Books saved before
// `addedAt` existed fall back to their reading time so they still sort stably.
function _readingBookList() {
    const books = gameState._readingBooks || {};
    return Object.entries(books)
        .filter(([, b]) => b && b.name)
        .map(([slug, b]) => ({
            slug,
            name: b.name,
            style: b.style || bookStyleForName(b.name),
            totalMs: b.totalMs || 0,
            addedAt: b.addedAt || 0,
        }))
        .sort((a, b) => (b.addedAt - a.addedAt) || (b.totalMs - a.totalMs));
}

function renderReadingShelf() {
    const track = document.getElementById('reading-shelf-track');
    if (!track) return;
    const list = _readingBookList();
    track.innerHTML = '';

    // "Add a new book" always sits at the left end, before the newest book.
    const add = document.createElement('button');
    add.type = 'button';
    add.className = 'reading-book-card reading-book-add';
    add.innerHTML = `<div class="reading-add-inner"><span class="reading-add-plus">+</span><span class="reading-add-label">كتاب جديد</span></div>`;
    add.addEventListener('click', () => {
        // A click on an off-centre card centres it first; only the centred add-card
        // opens the modal (otherwise a scroll-tap would fire it by accident).
        if (add.classList.contains('is-selected')) openNewBookModal();
        else _readingScrollToCard(add);
    });
    track.appendChild(add);

    list.forEach(b => {
        const card = document.createElement('div');
        card.className = 'reading-book-card';
        card.dataset.slug = b.slug;
        card.innerHTML = `<div class="reading-book-art">${bookCoverSVG(b.style, b.name)}</div>
            <button type="button" class="reading-book-del" aria-label="حذف">✕</button>`;
        card.addEventListener('click', (e) => {
            if (e.target.closest('.reading-book-del')) return;
            _readingScrollToCard(card);
        });
        card.querySelector('.reading-book-del').addEventListener('click', (e) => {
            e.stopPropagation();
            gameState._readingDeleteSlug = b.slug;
            document.getElementById('reading-delete-modal')?.classList.add('active');
        });
        track.appendChild(card);
    });

    // Land on the last-read book if it's still on the shelf, else the newest one.
    let target = null;
    if (gameState._readingLastBook) {
        const i = list.findIndex(b => b.name === gameState._readingLastBook);
        if (i >= 0) target = track.children[i + 1];
    }
    if (!target) target = track.children[list.length ? 1 : 0];
    requestAnimationFrame(() => {
        _readingScrollToCard(target, true);
        _readingSyncShelfSelection();
    });
}

function _readingScrollToCard(card, instant) {
    const track = document.getElementById('reading-shelf-track');
    if (!track || !card) return;
    const left = card.offsetLeft - (track.clientWidth - card.offsetWidth) / 2;
    track.scrollTo({ left, behavior: instant ? 'auto' : 'smooth' });
}

// Marks the card nearest the track centre as selected and mirrors it into
// gameState._readingSelectedBook (what "أنا لها" actually starts).
function _readingSyncShelfSelection() {
    const track = document.getElementById('reading-shelf-track');
    if (!track) return;
    const mid = track.scrollLeft + track.clientWidth / 2;
    let best = null, bestD = Infinity;
    for (const card of track.children) {
        const c = card.offsetLeft + card.offsetWidth / 2;
        const d = Math.abs(c - mid);
        if (d < bestD) { bestD = d; best = card; }
    }
    for (const card of track.children) card.classList.toggle('is-selected', card === best);

    const label = document.getElementById('reading-shelf-label');
    const confirm = document.getElementById('reading-confirm');
    // Lock "أنا لها" with a CLASS, never the `disabled` attribute — on iOS a
    // disabled button leaks its touches through to whatever sits underneath (see
    // CLAUDE.md / the azkar انتهيت lock).
    if (!best || best.classList.contains('reading-book-add')) {
        gameState._readingSelectedBook = null;
        if (label) label.innerHTML = `<span class="reading-shelf-name">أضف كتابًا جديدًا</span>`;
        if (confirm) confirm.classList.add('is-disabled');
        return;
    }
    const b = _readingBookList().find(x => x.slug === best.dataset.slug);
    gameState._readingSelectedBook = b || null;
    if (label && b) {
        label.innerHTML = `<span class="reading-shelf-name">${_bkEsc(b.name)}</span>`
            + `<span class="reading-shelf-time">${_formatReadingDuration(b.totalMs)}</span>`;
    }
    if (confirm) confirm.classList.remove('is-disabled');
}

// ── Add-a-new-book modal (name + one of the 10 premade covers, live preview) ──

function openNewBookModal() {
    const modal = document.getElementById('reading-newbook-modal');
    if (!modal) return;
    gameState._newBookStyle = BOOK_STYLES[Math.floor(Math.random() * BOOK_STYLES.length)].id;
    const nameEl = document.getElementById('reading-newbook-name');
    if (nameEl) nameEl.value = '';
    _renderNewBookStyles();
    _renderNewBookPreview();
    modal.classList.add('active');
    _uiSeqReset();
    setTimeout(() => nameEl?.focus(), 260);
}

function closeNewBookModal() {
    document.getElementById('reading-newbook-modal')?.classList.remove('active');
}

function _renderNewBookStyles() {
    const box = document.getElementById('reading-newbook-styles');
    if (!box) return;
    box.innerHTML = '';
    BOOK_STYLES.forEach(s => {
        const b = document.createElement('button');
        b.type = 'button';
        b.className = 'reading-style-swatch' + (s.id === gameState._newBookStyle ? ' is-active' : '');
        b.dataset.style = s.id;
        b.innerHTML = `<div class="reading-style-art">${bookCoverSVG(s.id, '', { noText: true })}</div>`
            + `<span class="reading-style-label">${_bkEsc(s.label)}</span>`;
        b.addEventListener('click', () => {
            gameState._newBookStyle = s.id;
            box.querySelectorAll('.reading-style-swatch').forEach(el =>
                el.classList.toggle('is-active', el.dataset.style === s.id));
            _renderNewBookPreview();
        });
        box.appendChild(b);
    });
}

function _renderNewBookPreview() {
    const prev = document.getElementById('reading-newbook-preview');
    if (!prev) return;
    const name = (document.getElementById('reading-newbook-name')?.value || '').trim();
    prev.innerHTML = bookCoverSVG(gameState._newBookStyle, name || 'اسم الكتاب');
    prev.classList.toggle('is-placeholder', !name);
}

function _readingSlug(name) {
    return String(name).replace(/[.#$[\]/]/g, '_');
}

function confirmNewBook() {
    const nameEl = document.getElementById('reading-newbook-name');
    const name = (nameEl?.value || '').trim();
    if (!name) { nameEl?.focus(); return; }
    const style = gameState._newBookStyle || BOOK_STYLES[0].id;
    const slug = _readingSlug(name);

    if (!gameState._readingBooks) gameState._readingBooks = {};
    const existing = gameState._readingBooks[slug];
    const entry = {
        name,
        style,
        totalMs: existing ? (existing.totalMs || 0) : 0,
        // Re-adding an existing book bumps it back to the front of the shelf.
        addedAt: Date.now(),
    };
    gameState._readingBooks[slug] = entry;
    update(ref(database), {
        [`dashboards/${gameState.userId}/reading/books/${slug}/name`]: name,
        [`dashboards/${gameState.userId}/reading/books/${slug}/style`]: style,
        [`dashboards/${gameState.userId}/reading/books/${slug}/addedAt`]: entry.addedAt,
    }).catch(() => {});

    // Keep the shelf bounded — drop the oldest beyond the cap.
    const list = _readingBookList();
    if (list.length > READING_BOOK_LIMIT) {
        list.slice(READING_BOOK_LIMIT).forEach(b => {
            delete gameState._readingBooks[b.slug];
            remove(ref(database, `dashboards/${gameState.userId}/reading/books/${b.slug}`)).catch(() => {});
        });
    }

    closeNewBookModal();
    gameState._readingLastBook = name;
    renderReadingShelf();
}

function closeReadingPopup() {
    document.getElementById('reading-modal')?.classList.remove('active');
    closeNewBookModal();
    // Only release the lock if we're not proceeding straight into a session —
    // startReadingSession calls this first, then re-locks for the session itself.
    if (!gameState.reading.active) gameState.isLockedIn = false;
}

// The reading ghost-cleanup is armed/cancelled PER FIELD, never on the `users/{uid}`
// parent. `onDisconnect(parent).cancel()` cancels the queued ops of that location AND
// all its children — so cancelling at the parent silently wiped the presence handlers
// (`activeInGame` → false, `activeSession` → null) armed at login, and the reader then
// stayed visible to everyone forever after closing the tab.
const READING_DISCONNECT_FIELDS = {
    isReading: false, readingBook: null, readingEnd: null, booksSofa: null,
};

function armReadingDisconnect() {
    for (const [field, value] of Object.entries(READING_DISCONNECT_FIELDS)) {
        onDisconnect(ref(database, `users/${gameState.userId}/${field}`)).set(value);
    }
}

function cancelReadingDisconnect() {
    for (const field of Object.keys(READING_DISCONNECT_FIELDS)) {
        onDisconnect(ref(database, `users/${gameState.userId}/${field}`)).cancel();
    }
}

function startReadingSession(durationMin, bookName, bookStyle) {
    closeReadingPopup();

    // Pick a RANDOM free sofa spot, not the closest — the walk over is part of the
    // ritual, and always landing on the same seat made the room feel static.
    const free = SOFA2_SPOTS.filter(spot => _sofa2SpotFree(spot.id, gameState.userId));
    const best = free.length ? free[Math.floor(Math.random() * free.length)] : null;
    const sofaIdx = best ? best.id : null;

    const now = serverNow();
    const style = bookStyle || bookStyleForName(bookName);
    gameState.reading = {
        active: true,
        bookName,
        bookStyle: style,
        durationMs: durationMin * 60000,
        startTime: now,
        endTime: now + (durationMin * 60000),
        sofaIdx,
        totalBookMs: 0,
        leaderboardData: [],
        _cameraPhase: 'intro',
        _cameraStartTime: Date.now(),
        // The camera tween interpolates from a captured start, and the exit tween
        // restores exactly the zoom the player had before the session.
        _fromX: gameState.camera.x,
        _fromY: gameState.camera.y,
        _fromZoom: gameState.zoom,
        _zoomBefore: gameState.zoom,
        _panelVisible: false,
        _exitConfirmOpen: false,
    };

    // Lock player input, set sitting
    gameState.isLockedIn = true;
    if (sofaIdx) startSitAnimation(sofaIdx, best.x, best.y);

    // Save to Firebase (dashboards + users presence)
    const slug = _readingSlug(bookName);
    const updates = {};
    updates[`dashboards/${gameState.userId}/reading/lastBook`] = bookName;
    updates[`users/${gameState.userId}/isReading`] = true;
    updates[`users/${gameState.userId}/readingBook`] = bookName;
    updates[`users/${gameState.userId}/readingEnd`] = gameState.reading.endTime;
    updates[`users/${gameState.userId}/booksSofa`] = sofaIdx;

    // Load existing total for this book
    get(ref(database, `dashboards/${gameState.userId}/reading/books/${slug}/totalMs`)).then(snap => {
        if (snap.exists() && gameState.reading.active) {
            gameState.reading.totalBookMs = snap.val() || 0;
        }
    }).catch(() => {});

    fetchReadingLeaderboard();

    update(ref(database), updates).catch(() => {});

    // Ghost-cleanup: never leave a "يتم قراءة" badge floating for others if the tab
    // closes mid-session (same rule as every other session type — see CLAUDE.md
    // "ghost laptop" lesson). Siraj ghosts already wipe their whole user node.
    if (!gameState.isSirajGhost) armReadingDisconnect();

    // Stop player
    const me = gameState.players[gameState.userId];
    if (me) {
        me.isMoving = false;
        me.isSprinting = false;
        sendPositionWS(me.x, me.y, true);
    }

    // Mobile: hide the joystick + user-card (name/photo), same as any other focus session.
    setMobileFocusMode(true);
}

const _easeInOutCubic = (x) => x < 0.5 ? 4 * x * x * x : 1 - Math.pow(-2 * x + 2, 3) / 2;

const READING_ZOOM = 2.2;
const READING_INTRO_MS = 1900;     // zoom-in + slide-left, ONE continuous tween
const READING_PANEL_AT = 0.62;     // fraction of the intro at which the panel flies in
const READING_EXIT_MS = 900;
const READING_EXIT_MAX_MS = 1600;  // hard stop — never let the exit tween own the camera

// How far left of centre the player sits during a session, so the panel has the
// left third to itself. In world units at READING_ZOOM.
const READING_SLIDE_PX = 250;

function updateReadingCamera() {
    const r = gameState.reading;
    // Keep running through the 'exiting' phase even after r.active flips false —
    // otherwise the zoom-out/camera-return on session end never plays a single frame.
    if (!r.active && r._cameraPhase !== 'exiting') return;
    const player = gameState.players[gameState.userId];
    if (!player) return;

    const { x: px, y: py } = getPlayerRenderPos(player);
    const elapsed = Date.now() - r._cameraStartTime;

    if (r._cameraPhase === 'intro') {
        // ONE eased tween for the whole cinematic. The old code ran a raw
        // exponential lerp to zoom in, then handed over to a separate eased slide —
        // and because the lerp still had speed when the slide's ease-in-out started
        // from zero velocity, the hand-off read as a stutter. A single
        // progress-based easeInOutCubic across zoom AND pan has no seam.
        const targetX = -px + (isMobile() ? 0 : READING_SLIDE_PX / READING_ZOOM);
        const targetY = -py;
        const t = Math.min(1, elapsed / READING_INTRO_MS);
        const e = _easeInOutCubic(t);
        gameState.camera.x = r._fromX + (targetX - r._fromX) * e;
        gameState.camera.y = r._fromY + (targetY - r._fromY) * e;
        gameState.zoom = r._fromZoom + (READING_ZOOM - r._fromZoom) * e;

        if (!r._panelVisible && t >= READING_PANEL_AT) showReadingPanel();
        if (t >= 1) r._cameraPhase = 'active';
    } else if (r._cameraPhase === 'active') {
        // Hold. Re-asserts the zoom every frame in case anything else nudges it.
        const targetX = -px + (isMobile() ? 0 : READING_SLIDE_PX / READING_ZOOM);
        const targetY = -py;
        const ease = 1 - Math.pow(0.9, gameState.dtFactor);
        gameState.camera.x += (targetX - gameState.camera.x) * ease;
        gameState.camera.y += (targetY - gameState.camera.y) * ease;
        gameState.zoom += (READING_ZOOM - gameState.zoom) * ease;
    } else if (r._cameraPhase === 'exiting') {
        // Eased return to the pre-session framing. Progress-based with a hard
        // deadline: the old version lerped until zoom converged on a target the
        // user could still fight with the scroll wheel, so a stray scroll here
        // left the phase stuck 'exiting' forever — updateCamera() early-returns
        // while that's set, so the camera rubber-banded back every frame for the
        // rest of the session. Bounded time + abortReadingCamera() kill both.
        const t = Math.min(1, elapsed / READING_EXIT_MS);
        const e = _easeInOutCubic(t);
        gameState.camera.x = r._fromX + (-px - r._fromX) * e;
        gameState.camera.y = r._fromY + (-py - r._fromY) * e;
        gameState.zoom = r._fromZoom + (r._zoomBefore - r._fromZoom) * e;
        if (t >= 1 || elapsed > READING_EXIT_MAX_MS) abortReadingCamera();
    }
}

// Hands the camera straight back to updateCamera(). Safe to call at any time —
// this is what the zoom handlers call so a user gesture always wins.
function abortReadingCamera() {
    if (gameState.reading) gameState.reading._cameraPhase = null;
}

function updateReadingSession() {
    if (!gameState.reading.active) return;
    const r = gameState.reading;
    const now = serverNow();

    if (now >= r.endTime) {
        endReadingSession(false);
        return;
    }

    if (r._panelVisible) {
        const remaining = Math.max(0, r.endTime - now);
        const mins = String(Math.floor(remaining / 60000)).padStart(2, '0');
        const secs = String(Math.floor((remaining % 60000) / 1000)).padStart(2, '0');
        const timeStr = `${mins}:${secs}`;

        // The displayed values only change once a second — skip the per-frame DOM
        // writes (innerText replaces the text node and re-lays-out even when the
        // string is identical, 60×/sec for the whole session).
        if (timeStr === r._lastPanelTimeStr) return;
        r._lastPanelTimeStr = timeStr;

        const sessionMs = now - r.startTime;
        const totalStr = _formatReadingDuration(r.totalBookMs + sessionMs);
        const pct = Math.max(0, Math.min(100, (sessionMs / r.durationMs) * 100));

        const pre = isMobile() ? 'reading-mobile' : 'reading-panel';
        const tm = document.getElementById(`${pre}-timer`);
        const tot = document.getElementById(`${pre}-total`);
        const fill = document.getElementById(`${pre}-progress-fill`);
        if (tm) tm.innerText = timeStr;
        if (tot) tot.innerText = totalStr;
        if (fill) fill.style.width = `${pct.toFixed(2)}%`;
    }
}

// Slides an element up from fully off-screen into its normal resting transform
// (see .rd-slide-init in style.css) instead of the instant display:none→flex
// pop the hidden-class toggle gave it before.
function _rdSlideIn(el) {
    if (!el) return;
    el.classList.remove('hidden');
    el.classList.add('rd-slide-init');
    void el.offsetWidth;
    requestAnimationFrame(() => el.classList.remove('rd-slide-init'));
}

function showReadingPanel() {
    const r = gameState.reading;
    r._panelVisible = true;
    r._lastPanelTimeStr = null;   // force the first panel write of the new session
    const cover = bookCoverSVG(r.bookStyle, r.bookName);
    const durStr = _formatReadingDuration(r.durationMs);

    if (isMobile()) {
        const header = document.getElementById('reading-mobile-header');
        const drawer = document.getElementById('reading-drawer');
        const exitBtn = document.getElementById('reading-mobile-exit-btn');
        if (header) {
            header.classList.remove('hidden');
            document.getElementById('reading-mobile-book').innerText = r.bookName;
            const c = document.getElementById('reading-mobile-cover');
            if (c) c.innerHTML = cover;
            const d = document.getElementById('reading-mobile-duration');
            if (d) d.innerText = durStr;
        }
        _rdSlideIn(drawer);
        _rdSlideIn(exitBtn);
        renderReadingLeaderboard();
        return;
    }

    const panel = document.getElementById('reading-panel');
    if (!panel) return;
    panel.classList.remove('hidden');
    document.getElementById('reading-panel-book').innerText = r.bookName;
    const c = document.getElementById('reading-panel-cover');
    if (c) c.innerHTML = cover;
    const d = document.getElementById('reading-panel-duration');
    if (d) d.innerText = durStr;
    renderReadingLeaderboard();

    // Cascade the rows in with the house pitch-sweep blip (deep → high).
    const kids = Array.from(panel.children);
    _uiSeqReset();
    kids.forEach((el, i) => {
        el.style.opacity = '0';
        // The "يتم قراءة <book name>" header (first row) gets a much stronger
        // deceleration — nearly all its motion happens immediately, then it eases
        // out for a long, slow tail — instead of the gentler cascade easing the
        // other rows use.
        const strongEase = i === 0;
        el.style.animation = strongEase
            ? `readingRowIn 0.6s cubic-bezier(0.05, 0.9, 0.1, 1) forwards`
            : `readingRowIn 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards`;
        el.style.animationDelay = `${0.1 + i * 0.08}s`;
    });
}

function endReadingSession(manual) {
    if (!gameState.reading.active) return;

    const r = gameState.reading;
    // CLAMP, don't trust the wall clock. The natural end fires from
    // updateReadingSession, which runs on rAF — a backgrounded tab throttles that to
    // a stop, so the session ends whenever the user comes BACK, and a raw
    // `serverNow() - startTime` banked the entire away period (start a 25-min
    // session, background the tab for five hours, come back to +5h of reading).
    // The session can never legitimately be worth more than its own duration.
    const sessionMs = Math.max(0, Math.min(serverNow() - r.startTime, r.durationMs));

    // Save to Firebase
    const slug = _readingSlug(r.bookName);

    // 1. Clear active state for others
    const updates = {};
    updates[`users/${gameState.userId}/isReading`] = null;
    updates[`users/${gameState.userId}/readingBook`] = null;
    updates[`users/${gameState.userId}/readingEnd`] = null;
    updates[`users/${gameState.userId}/booksSofa`] = null;

    // 2. Increment the user's private book time + keep its display name/cover current
    //    (the slug alone isn't guaranteed to render back as the exact book name).
    const bookTotalRef = ref(database, `dashboards/${gameState.userId}/reading/books/${slug}/totalMs`);
    runTransaction(bookTotalRef, (curr) => (curr || 0) + sessionMs).catch(() => {});
    update(ref(database), {
        [`dashboards/${gameState.userId}/reading/books/${slug}/name`]: r.bookName,
        [`dashboards/${gameState.userId}/reading/books/${slug}/style`]: r.bookStyle,
    }).catch(() => {});

    // Disarm the disconnect ghost-cleanup — we're clearing these fields right now.
    if (!gameState.isSirajGhost) cancelReadingDisconnect();

    // 3. Increment the user's global reading time (for the leaderboard). Siraj test
    //    ghosts are ephemeral and must never appear in المتصدرين, so they skip this
    //    write entirely — their reading sessions are for testing, not competing.
    if (!gameState.isSirajGhost) {
        const lbRef = ref(database, `${lobbyPath('readingLeaderboard')}/${gameState.userId}/totalMs`);
        runTransaction(lbRef, (curr) => (curr || 0) + sessionMs).catch(() => {});
        // Refresh name/avatar in case this is their first entry. (gameState.currentUser
        // is just the username STRING, not an object — pull name/avatar from the
        // player entity like everywhere else in the codebase.)
        const meP = gameState.players[gameState.userId] || {};
        updates[`${lobbyPath('readingLeaderboard')}/${gameState.userId}/name`] = meP.username || 'قارئ';
        updates[`${lobbyPath('readingLeaderboard')}/${gameState.userId}/avatar`] = meP.avatar || '';
    }
    update(ref(database), updates).catch(() => {});

    // Keep the local shelf in sync so re-opening the popup shows the new total
    // without waiting on a round trip.
    if (gameState._readingBooks && gameState._readingBooks[slug]) {
        gameState._readingBooks[slug].totalMs = (gameState._readingBooks[slug].totalMs || 0) + sessionMs;
    }

    // UI Cleanup
    r.active = false;
    r._cameraPhase = 'exiting';
    r._cameraStartTime = Date.now();
    r._fromX = gameState.camera.x;
    r._fromY = gameState.camera.y;
    r._fromZoom = gameState.zoom;
    gameState.isLockedIn = false;
    setMobileFocusMode(false);

    if (isMobile()) {
        document.getElementById('reading-mobile-header')?.classList.add('hidden');
        document.getElementById('reading-drawer')?.classList.add('hidden');
        document.getElementById('reading-drawer')?.classList.remove('drawer-open');
        document.getElementById('reading-mobile-exit-btn')?.classList.add('hidden');
    } else {
        document.getElementById('reading-panel')?.classList.add('hidden');
    }

    // Stand up in front of the seat just read at (facing away from it), not
    // wherever the player stood before sitting down — walking back to a spot
    // behind them across the room felt wrong. The book-reading seats are always
    // SOFA2_SPOTS; dir tells us which way is "away from the sofa".
    const rp = gameState.players[gameState.userId];
    const seatSpot = rp && SOFA2_SPOTS.find(s => s.id === rp.sitSeatId);
    if (seatSpot) {
        const faceOffset = 105; // clear of the sofa's collision footprint (was 62 — too close, landed player inside the couch mask and stuck them)
        gameState.sitReturnPos = {
            x: seatSpot.x,
            y: seatSpot.y + (seatSpot.dir === 'down' ? faceOffset : -faceOffset),
        };
    }
    setTimeout(() => {
        standUp();
    }, 800);
}

// ─── The book prop (Art/Book.png) ────────────────────────────────────────────
// Slides out from UNDER the seated reader to in front of them — no fade, pure
// position, so the player sprite itself is what hides it on the way out. Which way
// it travels comes from the sofa spot's `dir`: the upper Books_Sofas face down (the
// book slides down, toward the viewer), the lower ones face up.
// Sized so the book's half-diagonal (~38px) tucks just inside the avatar's ring
// radius (~39px) — that's what keeps it invisible at slide 0.
const BOOK_PROP_W = PLAYER_SIZE * 0.80;                 // "slightly less" than the player
const BOOK_PROP_H = BOOK_PROP_W * (933 / 1004);         // Art/Book.png content aspect
// Travel leaves a small deliberate overlap with the avatar at full extension — it
// should read as a book held in the lap, not one floating away from them.
const BOOK_PROP_TRAVEL = PLAYER_SIZE * 0.62;
const BOOK_PROP_SPEED = 1 / 2.5;                        // slide units/sec (0→1) — 2.5s full slide
// On session end the book must be fully tucked away before the stand-up/couch-jump
// fires (800ms after endReadingSession) — much faster than the normal slide, and
// timed to finish alongside the camera's zoom-out (READING_EXIT_MS ≈ 900ms).
const BOOK_PROP_EXIT_SPEED = 1 / 0.5;
// Art/Book.png is a 2048² canvas with the book floating in the middle — draw only
// the painted region so the sprite isn't 75% empty space.
const BOOK_SRC = { x: 515, y: 423, w: 1004, h: 933 };
// Fast start, slow finish — distinct from the symmetric _easeInOutCubic used by
// the reading camera tween.
const _easeOutQuint = (x) => 1 - Math.pow(1 - x, 5);

function _bookSlideDir(seatId) {
    const spot = SOFA2_SPOTS.find(s => s.id === seatId);
    return spot ? spot.dir : 'down';
}

// Per-player 0→1 slide, eased and reversible: it retracts under the player on
// session end exactly the way it came out.
function _updateBookProp(player, isLocal) {
    // The `!sitAnim.active` half matters on BOTH sides: the seat's Firebase write
    // lands as the hop starts, so without it the book would start sliding out from
    // under a player who's still mid-air. Remotes read their own relayed hop.
    const seated = isLocal
        ? (gameState.reading.active && gameState.isSitting && !gameState.sitAnim.active)
        : !!(player.isReading && player.sitSeatId && !(player._sitAnim && player._sitAnim.active));
    const target = seated ? 1 : 0;
    const cur = player._bookSlide || 0;
    // Retract fast (in sync with the camera zoom-out) while this player's own
    // reading session is exiting — otherwise the normal slow slide is still
    // mid-way when the couch-jump fires.
    const exiting = isLocal && gameState.reading._cameraPhase === 'exiting';
    const speed = (target < cur && exiting) ? BOOK_PROP_EXIT_SPEED : BOOK_PROP_SPEED;
    const step = speed * (gameState.dtFactor / 60);
    player._bookSlide = target > cur ? Math.min(target, cur + step) : Math.max(target, cur - step);
    return player._bookSlide;
}

function drawBookProp(player, isLocal, screenX, groundY, rScale, alpha) {
    const img = gameState.assets.book;
    const t = _updateBookProp(player, isLocal);
    if (t <= 0.001 || !img || !img.complete || !img.naturalWidth) return;

    const seatId = isLocal ? (player.sitSeatId || gameState.reading.sofaIdx) : player.sitSeatId;
    const sign = _bookSlideDir(seatId) === 'down' ? 1 : -1;
    const e = _easeOutQuint(t);
    const w = BOOK_PROP_W * rScale, h = BOOK_PROP_H * rScale;
    const y = groundY + sign * BOOK_PROP_TRAVEL * rScale * e;

    const ctx = gameState.ctx;
    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.drawImage(img, BOOK_SRC.x, BOOK_SRC.y, BOOK_SRC.w, BOOK_SRC.h,
        screenX - w / 2, y - h / 2, w, h);
    ctx.restore();
}

// Same plain-text bobbing style as drawSeatPrompt/drawGameZonePrompt — no pill/
// button background. It's a proximity hint, not a clickable widget on its own;
// pressing anywhere near the library (like walking up to a laptop) opens the popup.
const _booksLibraryPrompt = { alpha: 0, pop: 0, x: 0, y: 0, shownKey: null };
function drawBooksLibraryPrompt() {
    const key = gameState.nearBooksLibrary ? 'books' : null;
    if (!_updatePromptCrossfade(_booksLibraryPrompt, key, BOOKS_LIBRARY_POS.x, BOOKS_LIBRARY_POS.y)) return;
    const ctx = gameState.ctx;
    const a = _booksLibraryPrompt.alpha;
    const bob = Math.sin(Date.now() * 0.004) * 2.5;
    const pop = 0.82 + 0.18 * easeOutBack(Math.min(1, _booksLibraryPrompt.pop));
    ctx.save();
    ctx.translate(_booksLibraryPrompt.x, _booksLibraryPrompt.y - 70 - (1 - a) * 10 + bob);
    ctx.scale(pop, pop);
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.shadowBlur = 4; ctx.shadowColor = `rgba(0,0,0,${0.65 * a})`;
    ctx.fillStyle = `rgba(255,255,255,${a})`;
    ctx.font = 'bold 16px Rubik';
    ctx.fillText('اضغط لبدء القراءة', 0, 0);
    ctx.shadowBlur = 0;
    ctx.restore();
}

// The `name`/`avatar` on a leaderboard row are a SNAPSHOT — written only when that
// user finishes a reading session — so anyone who changes their Discord avatar keeps
// showing the old one to everyone else until their next session ends. `users/{uid}`
// is the live copy (every login refreshes it from Discord), so resolve from there
// instead. One-shot `get()`s, never a listener, memoised for the session (same rule
// as the fireplace avatars) — and skipped entirely for anyone already online, whose
// player entity is fresher than any read.
const _readingProfiles = {};
function _readingProfileFor(entry) {
    const live = gameState.players[entry.uid];
    const cached = _readingProfiles[entry.uid];
    return {
        avatar: live?.avatar   || cached?.avatar   || entry.avatar || '',
        name:   live?.username || cached?.username || entry.name   || 'قارئ',
    };
}

function _refreshReadingProfiles(arr) {
    const need = arr.filter(e => !gameState.players[e.uid] && !_readingProfiles[e.uid]);
    if (!need.length) return;
    Promise.all(need.map(e =>
        Promise.all([
            get(ref(database, `users/${e.uid}/avatar`)),
            get(ref(database, `users/${e.uid}/username`)),
        ]).then(([av, un]) => {
            _readingProfiles[e.uid] = { avatar: av.val() || '', username: un.val() || '' };
        }).catch(() => { _readingProfiles[e.uid] = {}; })
    )).then(() => renderReadingLeaderboard());
}

function fetchReadingLeaderboard() {
    const lbRef = ref(database, lobbyPath('readingLeaderboard'));
    get(lbRef).then(snap => {
        const data = snap.exists() ? snap.val() : {};
        const arr = [];
        for (const [uid, p] of Object.entries(data)) {
            // Siraj test ghosts never compete — they don't write here any more, but
            // filter on read too so any row left over from before stays hidden.
            if (uid.startsWith('siraj_')) continue;
            if (p.totalMs > 0) arr.push({ uid, name: p.name, avatar: p.avatar, totalMs: p.totalMs });
        }
        arr.sort((a, b) => b.totalMs - a.totalMs);
        gameState.reading.leaderboardData = arr;
        renderReadingLeaderboard();
        _refreshReadingProfiles(arr);
    }).catch(() => {});
}

function renderReadingLeaderboard() {
    const data = gameState.reading.leaderboardData || [];
    const containerId = isMobile() ? 'reading-drawer-leaderboard' : 'reading-leaderboard';
    const container = document.getElementById(containerId);
    if (!container) return;

    container.innerHTML = '';

    if (data.length === 0) {
        container.innerHTML = '<div class="reading-lb-empty">لا يوجد قرّاء بعد. كن أول من يتصدّر!</div>';
        return;
    }

    data.forEach((entry, i) => {
        const row = document.createElement('div');
        row.className = `reading-lb-row rank-${i + 1}`;
        if (entry.uid === gameState.userId) row.classList.add('highlight');

        const totalHrs = Math.floor(entry.totalMs / 3600000);
        const totalMins = Math.floor((entry.totalMs % 3600000) / 60000);
        let timeStr = '';
        if (totalHrs > 0) timeStr += `${totalHrs} س `;
        if (totalMins > 0 || totalHrs === 0) timeStr += `${totalMins} د`;

        const prof = _readingProfileFor(entry);
        row.innerHTML = `
            <div class="reading-lb-rank">${i + 1}</div>
            <div class="reading-lb-avatar" style="background-image: url('${prof.avatar || 'placeholder.png'}')"></div>
            <div class="reading-lb-info">
                <div class="reading-lb-name">${_bkEsc(prof.name)}</div>
                <div class="reading-lb-time">${timeStr}</div>
            </div>
        `;
        container.appendChild(row);
    });
}

// EOF

// ═══════════════════════════════════════════════════════════════════════════════
//  CHARACTER CUSTOMIZATION  (تخصيص الشخصية)
//
//  Two things a player owns and everyone else sees: the ring colour around their
//  avatar, and a hat placed on top of it.
//
//  Firebase — both live under `users/{uid}` (NOT `dashboards`, despite the private-
//  data rule): every client must READ them to draw the avatar, and they're written
//  only when the user presses حفظ (a handful of times ever), so the fan-out is
//  negligible:
//      users/{uid}/ringColor = '#rrggbb'
//      users/{uid}/hat       = { id, x, y, scale, rot }   // null = no hat
//  `id` is the file name inside Hats/. x/y are offsets in PLAYER_SIZE units and
//  scale is a multiple of PLAYER_SIZE, so the placement is resolution-independent
//  and survives the second-floor scale-up unchanged.
// ═══════════════════════════════════════════════════════════════════════════════

const HAT_DEFAULT = { x: 0, y: -0.55, scale: 0.80, rot: 0 };
const HAT_MANIFEST_URL = 'Hats/hats.json';

// ── Colour helpers ────────────────────────────────────────────────────────────
function _validHex(v) {
    return (typeof v === 'string' && /^#[0-9a-fA-F]{6}$/.test(v)) ? v : null;
}
function _hexToRgbStr(hex, fallback) {
    const h = _validHex(hex);
    if (!h) return fallback;
    return `${parseInt(h.slice(1, 3), 16)}, ${parseInt(h.slice(3, 5), 16)}, ${parseInt(h.slice(5, 7), 16)}`;
}
function _hsvToHex(h, s, v) {
    const f = n => {
        const k = (n + h / 60) % 6;
        const c = v - v * s * Math.max(0, Math.min(k, 4 - k, 1));
        return Math.round(c * 255).toString(16).padStart(2, '0');
    };
    return `#${f(5)}${f(3)}${f(1)}`;
}
function _hexToHsv(hex) {
    const h = _validHex(hex) || '#086fb6';
    const r = parseInt(h.slice(1, 3), 16) / 255,
          g = parseInt(h.slice(3, 5), 16) / 255,
          b = parseInt(h.slice(5, 7), 16) / 255;
    const mx = Math.max(r, g, b), mn = Math.min(r, g, b), d = mx - mn;
    let hh = 0;
    if (d) {
        if (mx === r)      hh = 60 * (((g - b) / d) % 6);
        else if (mx === g) hh = 60 * ((b - r) / d + 2);
        else               hh = 60 * ((r - g) / d + 4);
    }
    if (hh < 0) hh += 360;
    return { h: hh, s: mx ? d / mx : 0, v: mx };
}

// ── Hat assets ────────────────────────────────────────────────────────────────
// `_hats.list` is the discovered file list; `_hats.cache[id]` holds the loaded
// image plus its ALPHA-CROPPED canvas. The source PNGs are 1000×1000 with the hat
// floating in the middle, so both the previews and the in-world draw use the crop —
// otherwise the empty margin would dominate the preview and make every offset and
// scale meaningless.
const _hats = { list: [], cache: Object.create(null), loadedAt: 0, loading: null };

function hatUrl(id) { return 'Hats/' + encodeURIComponent(id); }

// Discovery. The site is statically hosted, so a directory can't be listed in
// production — `Hats/hats.json` (regenerated by the pre-commit hook) is the source
// of truth there. On localhost/LAN the dev server DOES serve a directory index, so
// we parse that first: dropping a new PNG into Hats/ then shows up on reload with
// no manifest step. AppleDouble sidecars (`._name.png`) are filtered out.
async function _fetchHatDirListing() {
    const host = location.hostname;
    const isLocal = host === 'localhost' || host === '127.0.0.1' || /^\d+\.\d+\.\d+\.\d+$/.test(host);
    if (!isLocal) return null;
    try {
        const res = await fetch('Hats/', { cache: 'no-store' });
        if (!res.ok) return null;
        const html = await res.text();
        const found = [];
        const re = /href="([^"]+\.(?:png|webp))"/gi;
        let m;
        while ((m = re.exec(html))) {
            const name = decodeURIComponent(m[1].split('/').pop());
            if (!name.startsWith('.') && !found.includes(name)) found.push(name);
        }
        return found.length ? found.sort() : null;
    } catch (e) { return null; }
}

async function loadHatManifest(force) {
    if (!force && _hats.list.length) return _hats.list;
    if (_hats.loading) return _hats.loading;
    _hats.loading = (async () => {
        let list = await _fetchHatDirListing();
        if (!list) {
            try {
                const res = await fetch(HAT_MANIFEST_URL, { cache: 'no-store' });
                if (res.ok) {
                    const json = await res.json();
                    if (Array.isArray(json)) list = json;
                }
            } catch (e) { /* offline / missing manifest → no hats, never a crash */ }
        }
        _hats.list = (list || []).filter(n => typeof n === 'string' && !n.startsWith('.'));
        _hats.loadedAt = Date.now();
        _hats.loading = null;
        return _hats.list;
    })();
    return _hats.loading;
}

// Crop the transparent margin off a loaded hat, returning a tight canvas. Falls
// back to the full image if the alpha scan can't run (a tainted canvas can't
// happen here — Hats/ is same-origin — but stay defensive).
function _cropHatImage(img) {
    const w = img.naturalWidth, h = img.naturalHeight;
    try {
        // Find the bbox on a SMALL proxy (≤128px), not the full 1000×1000 source —
        // the full-res alpha scan was ~4M array reads per hat, and with every hat
        // decoding at once it was the visible freeze when the customization menu
        // opened. The proxy bbox is scaled back up with a safety pad; the actual
        // crop still copies from the full-res image, so quality is untouched.
        const scale = Math.min(1, 128 / Math.max(w, h));
        const sw = Math.max(1, Math.round(w * scale)), sh = Math.max(1, Math.round(h * scale));
        const c = document.createElement('canvas');
        c.width = sw; c.height = sh;
        const cx = c.getContext('2d', { willReadFrequently: true });
        cx.drawImage(img, 0, 0, sw, sh);
        const data = cx.getImageData(0, 0, sw, sh).data;
        let x0 = sw, y0 = sh, x1 = -1, y1 = -1;
        for (let y = 0; y < sh; y++) {
            for (let x = 0; x < sw; x++) {
                if (data[(y * sw + x) * 4 + 3] > 8) {
                    if (x < x0) x0 = x;
                    if (x > x1) x1 = x;
                    if (y < y0) y0 = y;
                    if (y > y1) y1 = y;
                }
            }
        }
        if (x1 < x0 || y1 < y0) return null;
        // Map proxy px → source px, padded by one proxy cell each side so soft
        // anti-aliased edges the downscale blurred away are never cut off.
        const inv = 1 / scale;
        const fx0 = Math.max(0, Math.floor((x0 - 1) * inv));
        const fy0 = Math.max(0, Math.floor((y0 - 1) * inv));
        const fx1 = Math.min(w - 1, Math.ceil((x1 + 1) * inv));
        const fy1 = Math.min(h - 1, Math.ceil((y1 + 1) * inv));
        const cw = fx1 - fx0 + 1, ch = fy1 - fy0 + 1;
        const out = document.createElement('canvas');
        out.width = cw; out.height = ch;
        out.getContext('2d').drawImage(img, fx0, fy0, cw, ch, 0, 0, cw, ch);
        return out;
    } catch (e) { return null; }
}

// Idempotent: returns the cache entry, kicking the load on first ask. Entries are
// `{ img, canvas, url, ready }` — draw code just checks `.ready`.
function ensureHatAsset(id) {
    if (!id) return null;
    let entry = _hats.cache[id];
    if (entry) return entry;
    entry = _hats.cache[id] = { img: null, canvas: null, url: null, ready: false, failed: false };
    const img = new Image();
    img.decoding = 'async';
    img.onload = () => {
        entry.img = img;
        entry.canvas = _cropHatImage(img) || img;
        // The preview URL used to come from a synchronous toDataURL('image/png') —
        // a full PNG encode on the main thread, per hat, all in the same beat the
        // picker opened. toBlob encodes off the critical path and hands back an
        // object URL instead. `ready` only flips once the URL exists, so the
        // picker/preview polling keeps working unchanged.
        const done = (url) => { entry.url = url; entry.ready = true; };
        if (entry.canvas.toBlob) {
            entry.canvas.toBlob((blob) => {
                done(blob ? URL.createObjectURL(blob) : hatUrl(id));
            }, 'image/png');
        } else {
            done(entry.canvas.toDataURL ? entry.canvas.toDataURL('image/png') : hatUrl(id));
        }
    };
    img.onerror = () => { entry.failed = true; };
    img.src = hatUrl(id);
    return entry;
}

// Normalise whatever Firebase handed us into a safe hat descriptor (or null).
function sanitizeHat(raw) {
    if (!raw || typeof raw !== 'object' || typeof raw.id !== 'string' || !raw.id) return null;
    const num = (v, d, lo, hi) => {
        const n = Number(v);
        return Number.isFinite(n) ? Math.min(hi, Math.max(lo, n)) : d;
    };
    return {
        id:    raw.id,
        x:     num(raw.x,     HAT_DEFAULT.x,     -1.5, 1.5),
        y:     num(raw.y,     HAT_DEFAULT.y,     -2.0, 1.0),
        scale: num(raw.scale, HAT_DEFAULT.scale,  0.2, 2.0),
        rot:   num(raw.rot,   HAT_DEFAULT.rot,   -Math.PI, Math.PI),
    };
}

// ── Hat physics: pinned position, overshooting ROTATION only ─────────────────
// The hat's position is welded to the avatar's centre anchor every frame — no
// positional lag, so it never looks like it's floating behind the player. All the
// "object with mass" feel instead comes from a rotation spring: the anchor's
// sudden velocity changes (stopping after a run, the kidnap yank, the sit-down
// jump) impart torque, and the hat's rotation overshoots past level before
// settling — a small flop, not a chase. Per-player state, so remote players'
// hats flop too (their render position drives the same spring).
const _HAT_ROT_K   = 0.10;   // stiffness — how hard rotation is pulled back to level
const _HAT_ROT_D   = 0.90;   // damping (<1 ⇒ light overshoot before settling)
const _HAT_TORQUE  = 0.0026; // how much anchor acceleration turns into angular kick
const _HAT_ROT_MAX = 0.30;   // rad — hard cap so a teleport/kidnap yank can't spin it silly

function _updateHatSpring(player, tx, ty) {
    let h = player._hatSpring;
    if (!h) {
        h = player._hatSpring = { x: tx, y: ty, vx: 0, vy: 0, rot: 0, rotVel: 0 };
        return h;
    }
    // Position is always pinned to the anchor — no lag.
    const dt = Math.min(2, gameState.dtFactor || 1);
    const rawVx = (tx - h.x) / Math.max(dt, 0.001);
    const rawVy = (ty - h.y) / Math.max(dt, 0.001);
    h.x = tx; h.y = ty;

    if (gameState._pipPass) return h;   // PiP draws the spring, never advances it

    // A teleport/kidnap jump: re-anchor the rotation spring instead of imparting
    // a giant one-frame torque (which would look like a spin, not a flop).
    const jumped = Math.abs(rawVx - h.vx) > 40 || Math.abs(rawVy - h.vy) > 40;
    const ax = jumped ? 0 : (rawVx - h.vx);
    h.vx = rawVx; h.vy = rawVy;

    // Torque from the horizontal deceleration/acceleration impulse — this alone
    // covers "stop after running", the kidnap pull, and the sit-down jump, with
    // no special-casing needed: any sudden anchor-velocity change flops the hat.
    h.rotVel += -ax * _HAT_TORQUE * dt;
    h.rotVel = (h.rotVel - h.rot * _HAT_ROT_K * dt) * Math.pow(_HAT_ROT_D, dt);
    h.rot += h.rotVel * dt;
    h.rot = Math.max(-_HAT_ROT_MAX, Math.min(_HAT_ROT_MAX, h.rot));
    return h;
}

// Draw a player's hat pinned to the avatar's centre anchor. Called from drawPlayers
// AFTER the avatar's transform is restored, with the anchor the avatar was drawn at.
function drawPlayerHat(player, anchorX, anchorY, rScale, alpha) {
    const hat = player.hat;
    if (!hat || alpha < 0.02) { player._hatSpring = null; return; }
    const entry = ensureHatAsset(hat.id);
    if (!entry || !entry.ready) return;

    const spr = _updateHatSpring(player, anchorX, anchorY);
    const src = entry.canvas;
    const w = PLAYER_SIZE * hat.scale * rScale;
    const h = w * (src.height / src.width);

    const ctx = gameState.ctx;
    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.translate(spr.x, spr.y);
    ctx.translate(hat.x * PLAYER_SIZE * rScale, hat.y * PLAYER_SIZE * rScale);
    ctx.rotate(hat.rot + spr.rot);
    ctx.drawImage(src, -w / 2, -h / 2, w, h);
    ctx.restore();
}

// ── The customization scene (overlay) ─────────────────────────────────────────
// A "3D space": the backdrop fades in, the character DROPS from above and lands
// with a squash-and-stretch bounce onto its own contact shadow, and the panel
// slides in from the left. حفظ writes to Firebase and everything fades back out.
const _cc = {
    open: false,
    color: COLORS.blue,
    hat: null,            // working copy — only committed to Firebase on حفظ
    hsv: { h: 205, s: 1, v: 0.71 },
    raf: null,
    drag: null,
    wheelDrawn: false,
};

// Mirror the live player doc into the editor's "last saved" baseline, so opening
// the panel always starts from what everyone else currently sees.
function ccSyncFromPlayer(player) {
    if (_cc.open) return;   // never stomp an in-progress edit
    _cc.color = _validHex(player.ringColor) || COLORS.blue;
    _cc.hat   = player.hat ? { ...player.hat } : null;
}

function _ccEl(id) { return document.getElementById(id); }

// The character's drop + bounce. One rAF tween: fall (accelerating, stretched),
// then a damped squash oscillation on impact. The contact shadow tightens as the
// character nears the floor, which is what gives the scene its depth.
const _CC_FALL_MS = 380;
const _CC_SETTLE_MS = 560;
function _ccPlayDrop() {
    const char = _ccEl('cc-char'), shadow = _ccEl('cc-shadow');
    if (!char) return;
    if (_cc.raf) cancelAnimationFrame(_cc.raf);
    const t0 = performance.now();
    const dropFrom = -Math.max(320, window.innerHeight * 0.62);

    const frame = (now) => {
        const t = now - t0;
        let y, sx, sy, shA = 0, shS = 0.4;
        if (t < _CC_FALL_MS) {
            const p = t / _CC_FALL_MS;
            const e = p * p;                       // easeInQuad — real gravity feel
            y = dropFrom * (1 - e);
            const stretch = 0.10 + 0.34 * e;       // stretches as it speeds up
            sx = 1 - stretch * 0.55;
            sy = 1 + stretch;
            shA = e * 0.85;
            shS = 0.36 + e * 0.64;
        } else {
            const p = Math.min(1, (t - _CC_FALL_MS) / _CC_SETTLE_MS);
            // Damped oscillation around 1 — starts lightly squashed, settles fast.
            const decay = Math.exp(-8.5 * p);
            const osc = Math.cos(p * Math.PI * 3.1) * decay;
            sx = 1 + 0.14 * osc;
            sy = 1 - 0.14 * osc;
            y = 0;   // pivot is at the feet now (transform-origin), so no manual foot-plant hack needed
            shA = 0.85 + 0.15 * (1 - decay);
            shS = 1 + 0.14 * osc;
            if (p >= 1) {
                char.style.transform = 'translateY(0) scale(1,1)';
                if (shadow) { shadow.style.opacity = '1'; shadow.style.transform = 'scale(1)'; }
                _cc.raf = null;
                return;
            }
        }
        char.style.transform = `translateY(${y.toFixed(2)}px) scale(${sx.toFixed(3)}, ${sy.toFixed(3)})`;
        if (shadow) {
            shadow.style.opacity = shA.toFixed(3);
            shadow.style.transform = `scale(${shS.toFixed(3)})`;
        }
        _cc.raf = requestAnimationFrame(frame);
    };
    char.style.transform = `translateY(${dropFrom}px) scale(0.9, 1.1)`;
    if (shadow) { shadow.style.opacity = '0'; shadow.style.transform = 'scale(0.4)'; }
    _cc.raf = requestAnimationFrame(frame);
}

// Paint the HSV wheel once (hue around, saturation outward). Value comes from the
// الإضاءة slider and is applied as a dimming layer, so one canvas covers the space.
function _ccDrawWheel() {
    const cv = _ccEl('cc-wheel');
    if (!cv || _cc.wheelDrawn) return;
    const ctx = cv.getContext('2d');
    const W = cv.width, H = cv.height, R = W / 2;
    const img = ctx.createImageData(W, H);
    for (let y = 0; y < H; y++) {
        for (let x = 0; x < W; x++) {
            const dx = x - R, dy = y - R;
            const d = Math.hypot(dx, dy);
            const i = (y * W + x) * 4;
            if (d > R) { img.data[i + 3] = 0; continue; }
            let hue = Math.atan2(dy, dx) * 180 / Math.PI;
            if (hue < 0) hue += 360;
            const hex = _hsvToHex(hue, Math.min(1, d / R), 1);
            img.data[i]     = parseInt(hex.slice(1, 3), 16);
            img.data[i + 1] = parseInt(hex.slice(3, 5), 16);
            img.data[i + 2] = parseInt(hex.slice(5, 7), 16);
            img.data[i + 3] = d > R - 1.5 ? Math.round(255 * (R - d) / 1.5) : 255;   // soft edge
        }
    }
    ctx.putImageData(img, 0, 0);
    _cc.wheelDrawn = true;
}

// Push _cc.color / _cc.hat into the preview character + the controls.
function _ccReflect() {
    const overlay = _ccEl('char-custom-overlay');
    if (overlay) overlay.style.setProperty('--cc-ring', _cc.color);
    const hex = _ccEl('cc-hex');
    if (hex && document.activeElement !== hex) hex.value = _cc.color.toUpperCase();

    // Wheel marker: hue = angle, saturation = radius.
    const dot = _ccEl('cc-wheel-dot'), wrap = _ccEl('cc-wheel');
    if (dot && wrap) {
        const R = wrap.clientWidth / 2;
        const a = _cc.hsv.h * Math.PI / 180;
        dot.style.left = (R + Math.cos(a) * _cc.hsv.s * R) + 'px';
        dot.style.top  = (R + Math.sin(a) * _cc.hsv.s * R) + 'px';
        dot.style.background = _cc.color;
    }
    const light = _ccEl('cc-light');
    if (light && document.activeElement !== light) light.value = Math.round(_cc.hsv.v * 100);

    // Hat preview — mirrors drawPlayerHat's maths against the preview's own size, so
    // what you place here is exactly what lands in the world.
    const hatEl = _ccEl('cc-hat'), charEl = _ccEl('cc-char');
    const tools = _ccEl('cc-hat-tools');
    if (tools) tools.classList.toggle('cc-unlocked', !!_cc.hat);
    if (hatEl && charEl) {
        if (!_cc.hat) { hatEl.classList.remove('cc-hat-on'); hatEl.removeAttribute('src'); }
        else {
            const entry = ensureHatAsset(_cc.hat.id);
            // Not decoded yet (a saved hat on first open): re-reflect when it lands.
            if (entry && !entry.ready && !entry.failed && !_cc._awaitHat) {
                _cc._awaitHat = true;
                const wait = () => {
                    if (!_cc.open) { _cc._awaitHat = false; return; }
                    if (entry.ready || entry.failed) { _cc._awaitHat = false; _ccReflect(); }
                    else setTimeout(wait, 90);
                };
                setTimeout(wait, 90);
            }
            if (entry && entry.ready) {
                if (hatEl.dataset.hatId !== _cc.hat.id) {
                    hatEl.dataset.hatId = _cc.hat.id;
                    hatEl.src = entry.url;
                }
                const S = charEl.clientWidth || 160;   // preview size stands in for PLAYER_SIZE
                const w = S * _cc.hat.scale;
                const h = w * (entry.canvas.height / entry.canvas.width);
                hatEl.style.width = w + 'px';
                hatEl.style.height = h + 'px';
                hatEl.style.transform =
                    `translate(${(-w / 2 + _cc.hat.x * S).toFixed(1)}px, ${(-h / 2 + _cc.hat.y * S).toFixed(1)}px) rotate(${_cc.hat.rot}rad)`;
                hatEl.classList.add('cc-hat-on');
            }
        }
    }
    ['cc-hat-scale', 'cc-hat-rot', 'cc-hat-x', 'cc-hat-y'].forEach(id => {
        const el = _ccEl(id);
        if (!el || !_cc.hat || document.activeElement === el) return;
        if (id === 'cc-hat-scale') el.value = Math.round(_cc.hat.scale * 100);
        if (id === 'cc-hat-rot')   el.value = Math.round(_cc.hat.rot * 180 / Math.PI);
        if (id === 'cc-hat-x')     el.value = Math.round(_cc.hat.x * 100);
        if (id === 'cc-hat-y')     el.value = Math.round(_cc.hat.y * 100);
    });
    document.querySelectorAll('#cc-hats .cc-hat-card').forEach(card => {
        card.classList.toggle('selected', (card.dataset.hatId || '') === (_cc.hat ? _cc.hat.id : ''));
    });
}

// Build the hat picker. Previews are the CROPPED canvases, so each card shows the
// hat filling its box instead of a speck in an ocean of transparent pixels.
async function _ccBuildHats() {
    const box = _ccEl('cc-hats');
    if (!box) return;
    const list = await loadHatManifest(true);   // re-read every open → new files appear
    box.innerHTML = '';

    const none = document.createElement('div');
    none.className = 'cc-hat-card';
    none.dataset.hatId = '';
    none.innerHTML = '<span class="cc-hat-none">بدون</span>';
    none.addEventListener('click', () => { _cc.hat = null; _ccReflect(); });
    box.appendChild(none);

    if (!list.length) {
        const empty = document.createElement('div');
        empty.className = 'cc-hats-empty';
        empty.style.gridColumn = '1 / -1';
        empty.textContent = 'لا توجد قبعات متاحة حاليًا';
        box.appendChild(empty);
    }

    for (const id of list) {
        const card = document.createElement('div');
        card.className = 'cc-hat-card';
        card.dataset.hatId = id;
        const img = document.createElement('img');
        img.alt = id.replace(/\.(png|webp)$/i, '');
        card.appendChild(img);
        card.addEventListener('click', () => {
            // Re-picking the same hat keeps its placement; a new hat starts at the default.
            if (!_cc.hat || _cc.hat.id !== id) _cc.hat = { id, ...HAT_DEFAULT };
            _ccReflect();
        });
        box.appendChild(card);

        const entry = ensureHatAsset(id);
        const paint = () => {
            if (entry.ready) { img.src = entry.url; _ccReflect(); }
            else if (!entry.failed) setTimeout(paint, 90);
            else card.remove();
        };
        paint();
    }
    _ccReflect();
}

function _ccSetColor(hex, fromWheel) {
    const v = _validHex(hex);
    if (!v) return;
    _cc.color = v.toLowerCase();
    if (!fromWheel) _cc.hsv = _hexToHsv(_cc.color);
    _ccReflect();
}

function openCharCustom() {
    const overlay = _ccEl('char-custom-overlay');
    if (!overlay || _cc.open) return;
    _cc.open = true;

    // Start from what's live right now.
    const me = gameState.players[gameState.userId];
    _cc.color = _validHex(me && me.ringColor) || COLORS.blue;
    _cc.hat   = (me && me.hat) ? { ...me.hat } : null;
    _cc.hsv   = _hexToHsv(_cc.color);

    // The avatar in the scene.
    const av = _ccEl('cc-avatar'), ini = _ccEl('cc-initial'), charEl = _ccEl('cc-char');
    const img = gameState.avatarCache[gameState.userId];
    if (img && img !== 'failed' && img.src) {
        av.src = img.src; av.hidden = false;
        charEl.classList.remove('no-avatar');
    } else {
        av.hidden = true;
        charEl.classList.add('no-avatar');
        ini.textContent = ((me && me.username) || '?').charAt(0).toUpperCase();
    }

    overlay.classList.remove('hidden');
    overlay.setAttribute('aria-hidden', 'false');
    document.body.classList.add('cc-active');
    // Force a reflow so removing .hidden and adding .cc-in are two separate styles —
    // otherwise the browser coalesces them and the fade never runs.
    void overlay.offsetWidth;
    overlay.classList.add('cc-in');

    _ccDrawWheel();
    _ccBuildHats();
    _ccReflect();
    _ccPlayDrop();
}

function closeCharCustom() {
    const overlay = _ccEl('char-custom-overlay');
    if (!overlay || !_cc.open) return;
    _cc.open = false;
    if (_cc.raf) { cancelAnimationFrame(_cc.raf); _cc.raf = null; }
    overlay.classList.remove('cc-in');
    overlay.setAttribute('aria-hidden', 'true');
    document.body.classList.remove('cc-active');
    setTimeout(() => { if (!_cc.open) overlay.classList.add('hidden'); }, 460);
}

// حفظ — one small multi-path write, then close. Both fields are read by every
// client's users listener, which is what makes the change visible to everyone.
function saveCharCustom() {
    const uid = gameState.userId;
    if (uid) {
        const payload = {
            [`users/${uid}/ringColor`]: _cc.color,
            [`users/${uid}/hat`]: _cc.hat ? sanitizeHat(_cc.hat) : null,
        };
        update(ref(database), payload).catch(e => console.warn('[custom] save failed', e));
    }
    // Apply locally right away — don't wait for the round-trip.
    const me = gameState.players[uid];
    if (me) {
        me.ringColor = _cc.color;
        me.hat = _cc.hat ? sanitizeHat(_cc.hat) : null;
    }
    closeCharCustom();
}

function setupCharCustomUI() {
    const overlay = _ccEl('char-custom-overlay');
    if (!overlay) return;

    _ccEl('settings-custom-btn')?.addEventListener('click', (e) => {
        e.stopPropagation();
        _closeSettingsPanel?.();   // the scene owns the screen — don't leave the panel floating
        openCharCustom();
    });
    _ccEl('cc-close')?.addEventListener('click', closeCharCustom);
    _ccEl('cc-save')?.addEventListener('click', saveCharCustom);
    _ccEl('cc-reset-color')?.addEventListener('click', () => _ccSetColor(COLORS.blue));
    _ccEl('cc-presets')?.addEventListener('click', (e) => {
        const btn = e.target.closest('.cc-preset');
        if (btn) _ccSetColor(btn.dataset.color);
    });
    _ccEl('cc-reset-hat')?.addEventListener('click', () => {
        if (!_cc.hat) return;
        _cc.hat = { id: _cc.hat.id, ...HAT_DEFAULT };
        _ccReflect();
    });

    // Escape closes; typing must never bleed into player movement while open.
    window.addEventListener('keydown', (e) => {
        if (_cc.open && e.key === 'Escape') { e.preventDefault(); closeCharCustom(); }
    });

    // ── Colour wheel picking (pointer = mouse + touch in one path) ────────────
    const wheel = _ccEl('cc-wheel');
    if (wheel) {
        const pick = (ev) => {
            const r = wheel.getBoundingClientRect();
            const R = r.width / 2;
            const dx = ev.clientX - r.left - R, dy = ev.clientY - r.top - R;
            let hue = Math.atan2(dy, dx) * 180 / Math.PI;
            if (hue < 0) hue += 360;
            _cc.hsv.h = hue;
            _cc.hsv.s = Math.min(1, Math.hypot(dx, dy) / R);
            _ccSetColor(_hsvToHex(_cc.hsv.h, _cc.hsv.s, _cc.hsv.v), true);
        };
        wheel.addEventListener('pointerdown', (e) => {
            wheel.setPointerCapture(e.pointerId);
            _cc.drag = 'wheel';
            pick(e);
        });
        wheel.addEventListener('pointermove', (e) => { if (_cc.drag === 'wheel') pick(e); });
        const end = () => { if (_cc.drag === 'wheel') _cc.drag = null; };
        wheel.addEventListener('pointerup', end);
        wheel.addEventListener('pointercancel', end);
    }

    _ccEl('cc-light')?.addEventListener('input', (e) => {
        _cc.hsv.v = Math.max(0.12, Number(e.target.value) / 100);
        _ccSetColor(_hsvToHex(_cc.hsv.h, _cc.hsv.s, _cc.hsv.v), true);
    });
    _ccEl('cc-hex')?.addEventListener('input', (e) => {
        let v = e.target.value.trim();
        if (v && v[0] !== '#') v = '#' + v;
        if (_validHex(v)) _ccSetColor(v);
    });

    // ── Hat transform sliders ────────────────────────────────────────────────
    // snapZero: a magnetic 0 — get within _CC_SNAP_TOL of centre and the value
    // (and the visible thumb) snap dead to 0, so restoring "no rotation / no
    // offset" doesn't need pixel-perfect dragging.
    const _CC_SNAP_TOL = 4;
    const bind = (id, apply, snapZero) => {
        const el = _ccEl(id);
        el?.addEventListener('input', (e) => {
            if (!_cc.hat) return;
            let v = Number(e.target.value);
            if (snapZero && Math.abs(v) <= _CC_SNAP_TOL) { v = 0; e.target.value = '0'; }
            apply(v);
            _ccReflect();
        });
    };
    bind('cc-hat-scale', v => { _cc.hat.scale = v / 100; });
    bind('cc-hat-rot',   v => { _cc.hat.rot   = v * Math.PI / 180; }, true);
    bind('cc-hat-x',     v => { _cc.hat.x     = v / 100; }, true);
    bind('cc-hat-y',     v => { _cc.hat.y     = v / 100; }, true);

    // ── Drag the hat directly on the character ───────────────────────────────
    const hatEl = _ccEl('cc-hat'), charEl = _ccEl('cc-char');
    if (hatEl && charEl) {
        let start = null;
        hatEl.addEventListener('pointerdown', (e) => {
            if (!_cc.hat) return;
            e.preventDefault();
            hatEl.setPointerCapture(e.pointerId);
            hatEl.classList.add('cc-dragging');
            start = { px: e.clientX, py: e.clientY, hx: _cc.hat.x, hy: _cc.hat.y };
        });
        hatEl.addEventListener('pointermove', (e) => {
            if (!start || !_cc.hat) return;
            const S = charEl.clientWidth || 160;
            _cc.hat.x = Math.max(-1.5, Math.min(1.5, start.hx + (e.clientX - start.px) / S));
            _cc.hat.y = Math.max(-2.0, Math.min(1.0, start.hy + (e.clientY - start.py) / S));
            _ccReflect();
        });
        const stop = () => { start = null; hatEl.classList.remove('cc-dragging'); };
        hatEl.addEventListener('pointerup', stop);
        hatEl.addEventListener('pointercancel', stop);
    }
}

function charCustomIsOpen() { return !!_cc.open; }

// ═══════════════════════════════════════════════════════════════════════════════
//  المدفئة — أعضاء الشهر (Fireplace / members of the month)
// ═══════════════════════════════════════════════════════════════════════════════
// Walk up to the fireplace on floor 1 → "انقر للنظر الى المدفئة" → a full-screen
// view of the fireplace art with the month's top 3 point-scorers framed on it.
//
// Where the data comes from (two DIFFERENT Firebase projects):
//   • Points live in the SEPARATE `mdwnhpoints` project, keyed by ARABIC NAME
//     (`players/{name}/totalPoints`) — no UIDs there at all. Read with a single
//     one-shot `get()` when the view opens; never a live listener (see the cost
//     rules — it's a foreign DB we don't control the size of).
//   • Avatars live in OUR main DB (`users/{uid}/avatar`), keyed by UID.
// So the join is: points name → normalise → FIRE_NAME_TO_UID → avatar. The two
// databases were never designed to line up, which is why the name map below is
// hand-maintained: add a member here when they're added to the points bot.

// Arabic name normalisation — the points DB and our UID list disagree on hamza
// (`ابو مزاحم` vs `أبو مزاحم`), so compare on a folded form: strip diacritics +
// tatweel and collapse the alef/ya/ta-marbuta variants.
function _fireNormName(s) {
    return String(s || '')
        .replace(/[ً-ْـ]/g, '')   // harakat + tatweel
        .replace(/[أإآٱ]/g, 'ا')
        .replace(/ى/g, 'ي')
        .replace(/ة/g, 'ه')
        .replace(/[ؤ]/g, 'و')
        .replace(/[ئ]/g, 'ي')
        .replace(/\s+/g, ' ')
        .trim();
}

// name (as written in the points DB) → Discord UID (for the avatar in our DB).
// Keys are normalised at build time, so any hamza spelling matches. `مجود` is
// spelled `نجود` in the points DB (a real different letter, not a hamza variant —
// normalisation can't fix it), so BOTH spellings map to the same UID.
const FIRE_NAME_TO_UID = (() => {
    const raw = {
        'الشعيرة': '1019357346641739806',
        'عمر': '1069103376807243806',
        'مايتو': '1111718176875630664',
        'علي مجدي': '1172932407926718515',
        'محمد سمير': '1216106201570349156',
        'عاصم': '1248232143445037178',
        'شفق': '1285679602349375564',
        'سحاب': '1357911505479270400',
        'ورقاء': '1466854105363255459',
        'رجب': '1526564826527174779',
        'نواف': '292276027823095829',
        'يوسف': '567266235163738112',
        'جمانة': '622102915439525898',
        'أبو مزاحم': '627439005495197726',
        'شارد': '653303368973942794',
        'خالد حسن': '716650621373251685',
        'فرات': '717209634020130866',
        'منة': '720663992657510472',
        'أبو بندر': '722125498859258048',
        'مجود': '734601933427441704',
        'نجود': '734601933427441704',   // how the points DB spells مجود
        'مصطفى': '792080177177690143',
        'طه': '793489473861189642',
        'ملك': '810388695311056896',
        'مورو': '823261298292293632',
        'خالد': '983037873991319613',
    };
    const out = {};
    for (const [name, uid] of Object.entries(raw)) out[_fireNormName(name)] = uid;
    return out;
})();

// Names in the points DB that are never real members (the Siraj test account has
// tens of thousands of points and would permanently own first place).
const FIRE_EXCLUDE_NAMES = new Set(['سراج'].map(_fireNormName));

// The three frames painted into `Art/Fireplace.png`, as fractions of that image
// (1500×1920) — measured off the reference overlay. Middle = 1st place, right =
// 2nd, left = 3rd (RTL podium). CSS positions each slot from these, so they stay
// glued to the art at any screen size. Tweak here if a frame looks off.
const FIRE_SLOTS = [
    { rank: 1, x: 0.4227, y: 0.2135, w: 0.1667, h: 0.1188 },   // middle
    { rank: 2, x: 0.6587, y: 0.2135, w: 0.1680, h: 0.1188 },   // right
    { rank: 3, x: 0.1813, y: 0.2135, w: 0.1700, h: 0.1188 },   // left
];

const _fire = { open: false, loading: false, top3: null, avatars: {}, camFrozen: null };
function fireplaceIsOpen() { return !!_fire.open; }

// ── The flame — a 29-frame PNG sequence cut from Art/Fireplace Fire.png ──────────
// The source spritesheet is a 4×8 grid of 1500×1920 cells (29 painted, 3 blank) and
// stays local-only, gitignored like the Lemo masters. Each shipped frame is cropped to
// the flame's own bounding box, downscaled to 512×525 and saved 255-colour: the art is
// flat cel shading, so the palette is lossless to the eye and the whole set is ~890 KB.
// The crop is also what keeps it off Safari's OOM cliff — the full cells would decode to
// ~340 MB, the exact pressure documented for the world art layers (The World → Perf).
// The PNGs keep their real alpha, so unlike the MP4 this replaced there's no black
// background and no `mix-blend-mode: screen` washing out the dark log.
const FIRE_FRAME_COUNT = 29;
const FIRE_FPS = 12;
const _flame = { frames: null, loading: null, raf: 0, i: 0, last: 0 };

// Resolves once every frame has settled. A frame that fails to load resolves anyway —
// one gap in the flicker beats no flame at all.
function _fireEnsureFrames() {
    if (_flame.frames) return Promise.resolve(_flame.frames);
    if (_flame.loading) return _flame.loading;
    _flame.loading = Promise.all(
        Array.from({ length: FIRE_FRAME_COUNT }, (_, i) => new Promise(resolve => {
            const img = new Image();
            img.decoding = 'async';
            img.onload = img.onerror = () => resolve(img);
            img.src = `Art/Fire/fire_${String(i).padStart(2, '0')}.png`;
        }))
    ).then(imgs => (_flame.frames = imgs));
    return _flame.loading;
}

// Swapping `src` between preloaded, decoded frames doesn't flash, so this needs no
// stacked layers. `_flame.i` is never reset, so the flicker picks up where it left off
// instead of restarting on the same frame every open.
async function _fireStartFlame() {
    const el = document.querySelector('#fireplace-overlay .fp-fire');
    if (!el) return;
    const frames = await _fireEnsureFrames();
    if (!_fire.open || _flame.raf) return;    // closed again, or already running
    const step = (t) => {
        _flame.raf = requestAnimationFrame(step);
        if (t - _flame.last < 1000 / FIRE_FPS) return;
        _flame.last = t;
        _flame.i = (_flame.i + 1) % FIRE_FRAME_COUNT;
        el.src = frames[_flame.i].src;
    };
    el.src = frames[_flame.i].src;            // something to look at on frame one
    _flame.last = performance.now();
    _flame.raf = requestAnimationFrame(step);
}

function _fireStopFlame() {
    if (_flame.raf) cancelAnimationFrame(_flame.raf);
    _flame.raf = 0;
}

const _firePrompt = { alpha: 0, pop: 0, x: 0, y: 0, shownKey: null };
function drawFireplacePrompt() {
    const key = gameState.nearFireplace ? 'fire' : null;
    if (!_updatePromptCrossfade(_firePrompt, key, FIRE_X, FIRE_Y)) return;
    const ctx = gameState.ctx;
    const a = _firePrompt.alpha;
    const bob = Math.sin(Date.now() * 0.004) * 2.5;
    const pop = 0.82 + 0.18 * easeOutBack(Math.min(1, _firePrompt.pop));
    ctx.save();
    ctx.translate(_firePrompt.x, _firePrompt.y - 70 - (1 - a) * 10 + bob);
    ctx.scale(pop, pop);
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.shadowBlur = 4; ctx.shadowColor = `rgba(0,0,0,${0.65 * a})`;
    ctx.fillStyle = `rgba(255,255,255,${a})`;
    ctx.font = 'bold 16px Rubik';
    ctx.fillText('انقر للنظر الى المدفئة', 0, 0);
    ctx.shadowBlur = 0;
    ctx.restore();
}

// One-shot read of the foreign points DB → the top 3 real members, richest first.
async function fetchFireTop3() {
    const snap = await get(ref(pointsDatabase, 'players'));
    if (!snap.exists()) return [];
    const arr = [];
    for (const [name, p] of Object.entries(snap.val() || {})) {
        const norm = _fireNormName(name);
        if (FIRE_EXCLUDE_NAMES.has(norm)) continue;
        const pts = Number(p && p.totalPoints) || 0;
        if (pts <= 0) continue;
        arr.push({ name, norm, points: pts, uid: FIRE_NAME_TO_UID[norm] || null });
    }
    arr.sort((a, b) => b.points - a.points);
    return arr.slice(0, 3);
}

// Avatars come from OUR DB, one `get()` per UID, memoised for the session.
async function fireAvatarFor(uid) {
    if (!uid) return '';
    if (_fire.avatars[uid] !== undefined) return _fire.avatars[uid];
    try {
        const snap = await get(ref(database, `users/${uid}/avatar`));
        _fire.avatars[uid] = snap.exists() ? (snap.val() || '') : '';
    } catch { _fire.avatars[uid] = ''; }
    return _fire.avatars[uid];
}

function _fireRenderSlots(top3) {
    for (const slot of FIRE_SLOTS) {
        const el = document.getElementById(`fire-slot-${slot.rank}`);
        if (!el) continue;
        const m = top3[slot.rank - 1];
        const photo = el.querySelector('.fp-slot-photo');
        const nameEl = el.querySelector('.fp-slot-name');
        const rankEl = el.querySelector('.fp-slot-rank');
        const ptsEl  = el.querySelector('.fp-slot-points');
        if (!m) {
            el.classList.add('fp-slot-empty');
            photo.style.backgroundImage = '';
            photo.textContent = '';
            nameEl.textContent = '';
            if (ptsEl) ptsEl.textContent = '';
            continue;
        }
        el.classList.remove('fp-slot-empty');
        nameEl.textContent = m.name;
        if (rankEl) rankEl.textContent = `#${slot.rank}`;
        // Grouped thousands read far faster than a bare 5-digit run.
        if (ptsEl) ptsEl.textContent = `${m.points.toLocaleString('en-US')} نقطة`;
        const url = m.uid ? _fire.avatars[m.uid] : '';
        if (url) {
            photo.style.backgroundImage = `url("${url}")`;
            photo.textContent = '';
        } else {
            // No UID mapping / no avatar on file — fall back to the first letter so
            // the frame still reads as a person rather than an empty hole.
            photo.style.backgroundImage = '';
            photo.textContent = (m.name || '؟').trim().charAt(0);
        }
    }
}

async function openFireplaceOverlay() {
    // Only `open` gates the view. `loading` used to gate it too, which meant closing
    // during the points fetch locked you out of reopening until it resolved — much
    // more noticeable now that closing is a half-second fade you might reverse.
    if (_fire.open) return;
    const overlay = document.getElementById('fireplace-overlay');
    if (!overlay) return;
    _fire.open = true;
    gameState.keys = {};                 // drop any held movement key
    // Park the world camera exactly where it is. The game loop keeps running behind
    // the overlay, and a still-lerping camera would drift while you're not looking —
    // so the room you come back to wouldn't be the one you left (the "snap on exit").
    _fireFreezeCamera();
    document.body.classList.add('fireplace-active');
    overlay.setAttribute('aria-hidden', 'false');
    // Two frames before `.active`: the first commits the pre-fade state (opacity 0,
    // visibility hidden), the second flips it, so the transition actually runs.
    requestAnimationFrame(() => requestAnimationFrame(() => {
        if (_fire.open) overlay.classList.add('active');
    }));
    _fireStartFlame();

    // Show whatever we fetched last time instantly, then refresh in the background.
    if (_fire.top3) _fireRenderSlots(_fire.top3);
    if (_fire.loading) return;   // a fetch from the previous open is still in flight
    _fire.loading = true;
    try {
        const top3 = await fetchFireTop3();
        await Promise.all(top3.map(m => fireAvatarFor(m.uid)));
        _fire.top3 = top3;
        if (_fire.open) _fireRenderSlots(top3);
    } catch (e) {
        console.warn('[fireplace] points fetch failed', e);
    } finally {
        _fire.loading = false;
    }
}

function closeFireplaceOverlay() {
    if (!_fire.open) return;
    _fire.open = false;
    const overlay = document.getElementById('fireplace-overlay');
    if (overlay) {
        // Just drop `.active` — the CSS fades opacity out and only then flips
        // visibility, so the exit is the mirror of the entrance.
        overlay.classList.remove('active');
        overlay.setAttribute('aria-hidden', 'true');
    }
    document.body.classList.remove('fireplace-active');
    _fireUnfreezeCamera();
    // Keep the flame flickering through the 0.5s fade-out — freezing it the instant you
    // press close is visible. Guarded on `open` so reopening mid-fade can't be killed by
    // the timer the close that preceded it armed.
    setTimeout(() => { if (!_fire.open) _fireStopFlame(); }, 550);
}

// While the overlay is up the camera is pinned, then handed back the moment it
// closes. `updateCamera` lerps toward the player, so on release it eases from the
// frozen framing instead of jumping — the player never moved, so in practice
// there's nothing to ease at all.
function _fireFreezeCamera() {
    _fire.camFrozen = { x: gameState.camera.x, y: gameState.camera.y };
}
function _fireUnfreezeCamera() {
    _fire.camFrozen = null;
}
function fireplaceHoldsCamera() { return !!_fire.camFrozen; }

function setupFireplaceUI() {
    const overlay = document.getElementById('fireplace-overlay');
    if (!overlay || overlay._fireWired) return;
    overlay._fireWired = true;

    // Build the three frames from FIRE_SLOTS so the art coords live in ONE place.
    const stage = overlay.querySelector('.fp-stage');
    for (const slot of FIRE_SLOTS) {
        const el = document.createElement('div');
        el.id = `fire-slot-${slot.rank}`;
        el.className = `fp-slot fp-slot-rank${slot.rank} fp-slot-empty`;
        el.style.left   = `${slot.x * 100}%`;
        el.style.top    = `${slot.y * 100}%`;
        el.style.width  = `${slot.w * 100}%`;
        el.style.height = `${slot.h * 100}%`;
        el.innerHTML = '<div class="fp-slot-photo"></div>'
                     + '<div class="fp-slot-caption">'
                     +   '<div class="fp-slot-name"></div>'
                     +   '<div class="fp-slot-meta">'
                     +     '<span class="fp-slot-rank"></span>'
                     +     '<span class="fp-slot-points"></span>'
                     +   '</div>'
                     + '</div>';
        stage.appendChild(el);
    }

    overlay.querySelector('#fireplace-close')?.addEventListener('click', closeFireplaceOverlay);
    // Click the backdrop (never the fireplace itself) to close. `.fp-shake` covers
    // the whole overlay now, so an `e.target === overlay` test would never match —
    // ask instead whether the click landed on the fireplace art or the close button.
    overlay.addEventListener('click', (e) => {
        if (!e.target.closest('.fp-stage, .fp-close')) closeFireplaceOverlay();
    });
    window.addEventListener('keydown', (e) => { if (e.key === 'Escape' && _fire.open) closeFireplaceOverlay(); });
}

// ════════════════════════════════════════════════════════════════════════════
// Lemo — the office robot
// ════════════════════════════════════════════════════════════════════════════
// A client-only ambient character: nothing about him is written to Firebase, so
// every player meets him somewhere different and he costs zero download budget.
// He sleeps at LEMO_SPAWN until someone walks up, wakes, then wanders LEMO_SPOTS
// forever — idle → walk → idle, with a rare Play detour.
//
// SPRITE GEOMETRY. The five sheets were sliced out of 2048² source cells, each
// cropped to its OWN tight alpha box (`box`, still in source-cell px). Cropping
// per-animation rather than with one shared box keeps a third of the decoded
// pixels out of memory — Play needs the arms-out width, Idle doesn't — and
// because every box is recorded in the SAME source-cell space, the frames still
// line up exactly. (The source art also carries a stray alpha≤40 dot at the far
// right of every cell; the boxes were measured above that threshold, or it would
// have padded each frame by ~35% of dead width.)
//
// The rim light and the body shading are BAKED INTO the sheets by Art/Lemo/slice.py,
// not composited here — a live rim pass means an offscreen canvas every frame, which
// is the exact mobile cost the graphics tiers exist to avoid. He's lit from directly
// ABOVE on purpose: the rim sits on top-facing edges only, so it survives the
// horizontal mirror he does to walk left. A top-left rim would flip to top-right.
//
// Everything is placed off ONE anchor: the source-cell point that is Lemo's
// ground contact — LEMO_ANCHOR_SX/SY = the idle body's centre-x and feet-y —
// which maps to (lemo.x, lemo.y + LEMO_H/2). That's the same centre-origin,
// shadow-at-the-feet convention drawPlayers uses, so he sits in the world the
// way an avatar does and mirrors cleanly around his own centre when he turns.
const LEMO_BODY_SRC_W = 1018;     // idle body size in source-cell px (measured by slice.py)
const LEMO_BODY_SRC_H = 1394;
const LEMO_H = 88;                // world height of the idle body (a touch taller than a player)
const LEMO_SCALE = LEMO_H / LEMO_BODY_SRC_H;   // source-cell px → world px
const LEMO_W = LEMO_BODY_SRC_W * LEMO_SCALE;
const LEMO_ANCHOR_SX = 999;       // idle body centre-x, source-cell px
const LEMO_ANCHOR_SY = 1767;      // idle feet-y,        source-cell px

// fw/fh/box are printed by slice.py — re-run it and these must be updated to match.
const LEMO_ANIMS = {
    Sleeping: { frames: 40, cols: 4, fw: 280, fh: 318, box: [479, 233, 1883, 1820], fps: 8,  loop: true  },
    WakeUp:   { frames: 27, cols: 4, fw: 234, fh: 288, box: [410, 365, 1584, 1803], fps: 8,  loop: false },
    Idle:     { frames: 24, cols: 4, fw: 206, fh: 280, box: [486, 369, 1512, 1771], fps: 8,  loop: true  },
    Walk:     { frames: 60, cols: 4, fw: 210, fh: 298, box: [485, 368, 1537, 1860], fps: 10, loop: false },
    Play:     { frames: 52, cols: 4, fw: 342, fh: 338, box: [137, 26, 1847, 1719], fps: 8,  loop: false },
};

// The walk cycle can't just be looped: it opens with a warm-up and closes with an
// overshoot. So the TRAVEL is bound to frames 0→45 and the last 15 frames play out
// in place as he settles. One walk = one playthrough, whatever the distance.
const LEMO_WALK_MOVE_FRAMES = 45;

// Spawn + wander spots, in source-art px (measured off Art/Lemo/reff.png, which is
// the same 2210×3160 space as the workspace layers — hence sx2w/sy2w straight through).
const LEMO_SPAWN = { x: sx2w(137), y: sy2w(2711) };
const LEMO_SPOTS = [
    [363, 2169], [1645, 2320], [604, 2698], [1259, 2758], [191, 2952],
].map(([px, py]) => ({ x: sx2w(px), y: sy2w(py) }));

const LEMO_WAKE_R = 170;          // world px — how close you must get to wake him
// He still has to finish the running Idle cycle (3s) before he'll move, so these are
// a floor, not the whole wait — the effective idle rounds up to the next cycle.
const LEMO_IDLE_MIN_MS = 600;
const LEMO_IDLE_MAX_MS = 3200;
const LEMO_PLAY_CHANCE = 0.12;    // chance an idle ends in Play instead of a walk

// Travel easing — ease in AND out, but NOT as two power curves stitched at t=0.5
// (that was tried and it visibly kicked: a piecewise 0.5*(2t)^p1 / 1-0.5*(2(1-t))^p2
// only has a continuous VELOCITY at the seam when p1 === p2, so using a lower power
// for a faster start than the tail's power made the speed jump right at the midpoint
// — the "sudden speedup" bug). A logistic curve has no seam: it's one smooth
// function for the whole travel, and shifting its center below 0.5 front-loads the
// acceleration (fast pickup) while the back two-thirds decelerate into a long, gentle
// stop — same intent as before, minus the discontinuity.
const _LEMO_EASE_K = 7, _LEMO_EASE_C = 0.32;
const _LEMO_EASE_R0 = 1 / (1 + Math.exp(_LEMO_EASE_K * _LEMO_EASE_C));
const _LEMO_EASE_R1 = 1 / (1 + Math.exp(-_LEMO_EASE_K * (1 - _LEMO_EASE_C)));
const _lemoEase = (t) => {
    const raw = 1 / (1 + Math.exp(-_LEMO_EASE_K * (t - _LEMO_EASE_C)));
    return (raw - _LEMO_EASE_R0) / (_LEMO_EASE_R1 - _LEMO_EASE_R0);
};

const _lemo = {
    x: LEMO_SPAWN.x, y: LEMO_SPAWN.y,
    state: 'sleeping',            // sleeping | waking | idle | walking | playing
    anim: 'Sleeping',
    frame: 0,
    animT: 0,                     // ms into the current animation
    wakePending: false,
    idleUntil: 0,
    spot: null,
    prevSpot: null,                // the spot he was at before `spot` — see _lemoStartWalk
    walk: null,
    face: 1,                      // 1 = facing right (the art's default), -1 = mirrored
    sheets: {},
    started: false,
};

function ensureLemoSheet(name) {
    if (_lemo.sheets[name]) return;                 // loaded, loading, or freed
    const img = new Image();
    img.decoding = 'async';
    try { img.fetchPriority = 'low'; } catch (_) {}
    img.src = 'Art/Lemo/Sheets/' + name + '.webp';
    _lemo.sheets[name] = { img };
}

// Drawable, or null. Never blocks: a missing sheet just skips a frame of drawing.
function _lemoSheet(name) {
    const s = _lemo.sheets[name];
    if (!s) { ensureLemoSheet(name); return null; }
    const img = s.img;
    return (img && img.complete && img.naturalWidth) ? img : null;
}

// He only ever sleeps once per session, so Sleeping + WakeUp are ~15 MB of decoded
// frames that can never be needed again — free them the moment he's up. Same reason
// the world drops its source layers once the cache is composited (Safari OOM).
// The entries stay behind as tombstones so _lemoSheet can't re-fetch them.
function _lemoReleaseSleepSheets() {
    for (const n of ['Sleeping', 'WakeUp']) {
        const s = _lemo.sheets[n];
        if (s && s.img) { try { s.img.src = ''; } catch (_) {} }
        _lemo.sheets[n] = { img: null, freed: true };
    }
}

function _lemoSetAnim(name, state) {
    _lemo.anim = name;
    _lemo.state = state;
    _lemo.animT = 0;
    _lemo.frame = 0;
}

function _lemoGoIdle() {
    _lemoSetAnim('Idle', 'idle');
    _lemo.idleUntil = Date.now() + LEMO_IDLE_MIN_MS + Math.random() * (LEMO_IDLE_MAX_MS - LEMO_IDLE_MIN_MS);
}

function _lemoStartWalk() {
    // Nearest spot, not a random one — but picking the single nearest EVERY time
    // ping-pongs him between two neighbours forever once he's settled into a
    // pocket of the room. Sort by distance, take the closest 2, then roll between
    // those — close enough to always read as "he went to the nearby spot" while
    // the coin flip keeps him from a permanent back-and-forth.
    //
    // That alone still allowed a tight A → B → A loop (nothing stopped B's
    // closest-2 from including A right back), so the spot he was at immediately
    // before the current one is excluded too, not just the current one.
    const excl = new Set([_lemo.spot, _lemo.prevSpot].filter(Boolean));
    let cands = LEMO_SPOTS.filter(s => !excl.has(s));
    if (!cands.length) cands = LEMO_SPOTS.filter(s => s !== _lemo.spot);  // too few spots to exclude both
    cands.sort((a, b) => ((a.x - _lemo.x) ** 2 + (a.y - _lemo.y) ** 2)
                        - ((b.x - _lemo.x) ** 2 + (b.y - _lemo.y) ** 2));
    const pool = cands.slice(0, Math.min(2, cands.length));
    const spot = pool[Math.floor(Math.random() * pool.length)];
    _lemo.prevSpot = _lemo.spot;
    _lemo.spot = spot;
    _lemo.walk = { sx: _lemo.x, sy: _lemo.y, tx: spot.x, ty: spot.y };
    // The walk art faces RIGHT, so a leftward trip mirrors him on the spot; he
    // snaps back to the default once the animation finishes.
    _lemo.face = (spot.x < _lemo.x) ? -1 : 1;
    _lemoSetAnim('Walk', 'walking');
}

function startLemo() {
    if (_lemo.started) return;
    _lemo.started = true;
    ensureLemoSheet('Idle');
    ensureLemoSheet('Walk');

    // 50/50: either he's still curled up at his spot and you have to walk over to
    // him, or he's already been up a while — drop him on a random spot, awake.
    if (Math.random() < 0.5) {
        const spot = LEMO_SPOTS[Math.floor(Math.random() * LEMO_SPOTS.length)];
        _lemo.spot = spot;
        _lemo.x = spot.x;
        _lemo.y = spot.y;
        _lemoReleaseSleepSheets();      // tombstones them before they ever load
        _lemoGoIdle();
    } else {
        ensureLemoSheet('Sleeping');
        ensureLemoSheet('WakeUp');
        _lemo.x = LEMO_SPAWN.x;
        _lemo.y = LEMO_SPAWN.y;
        _lemoSetAnim('Sleeping', 'sleeping');
    }

    // Play is a rare detour and the heaviest sheet — keep it off the spawn path.
    const warmPlay = () => ensureLemoSheet('Play');
    if (window.requestIdleCallback) requestIdleCallback(warmPlay, { timeout: 20000 });
    else setTimeout(warmPlay, 12000);
}

function updateLemo(dt) {
    // Hidden: freeze him rather than keep simulating an invisible robot. He picks up
    // wherever he was if it's turned back on.
    if (!_lemo.started || gameState._hideLemo) return;
    const a = LEMO_ANIMS[_lemo.anim];
    const frameMs = 1000 / a.fps;

    _lemo.animT += dt;
    let f = Math.floor(_lemo.animT / frameMs);
    let justLooped = false, done = false;
    if (f >= a.frames) {
        if (a.loop) {
            _lemo.animT -= a.frames * frameMs;
            f = Math.floor(_lemo.animT / frameMs);
            justLooped = true;
        } else {
            f = a.frames - 1;
            done = true;                 // latches until the state handler moves on
        }
    }
    _lemo.frame = Math.max(0, Math.min(a.frames - 1, f));

    switch (_lemo.state) {
        case 'sleeping': {
            if (!_lemo.wakePending) {
                const p = gameState.players[gameState.userId];
                if (p) {
                    const dx = p.x - _lemo.x, dy = p.y - _lemo.y;
                    if (dx * dx + dy * dy < LEMO_WAKE_R * LEMO_WAKE_R) _lemo.wakePending = true;
                }
            }
            // Let the current sleep cycle finish before he stirs — no mid-loop cut.
            if (_lemo.wakePending && justLooped) _lemoSetAnim('WakeUp', 'waking');
            break;
        }
        case 'waking':
            if (done) { _lemoReleaseSleepSheets(); _lemoGoIdle(); }
            break;
        case 'idle':
            // Idle for 3–10s, then let the cycle land before deciding what's next.
            if (Date.now() >= _lemo.idleUntil && justLooped) {
                if (Math.random() < LEMO_PLAY_CHANCE && _lemoSheet('Play')) _lemoSetAnim('Play', 'playing');
                else _lemoStartWalk();
            }
            break;
        case 'playing':
            if (done) _lemoGoIdle();     // a play always drops back into more idling
            break;
        case 'walking': {
            const w = _lemo.walk;
            const moveMs = LEMO_WALK_MOVE_FRAMES * frameMs;
            const e = _lemoEase(Math.min(1, _lemo.animT / moveMs));
            _lemo.x = w.sx + (w.tx - w.sx) * e;
            _lemo.y = w.sy + (w.ty - w.sy) * e;
            if (done) { _lemo.face = 1; _lemoGoIdle(); }                    // snap back to default
            break;
        }
    }
}

function drawLemo() {
    if (!_lemo.started || gameState._hideLemo) return;
    const sheet = _lemoSheet(_lemo.anim);
    if (!sheet) return;
    const ctx = gameState.ctx;
    const a = LEMO_ANIMS[_lemo.anim];

    // Soft contact shadow on the floor — the same ellipse the avatars get, but
    // tighter than theirs: he stands on small feet, not a full body footprint.
    const shW = LEMO_W * 0.30;
    ctx.save();
    ctx.globalAlpha = 0.28;
    ctx.fillStyle = '#000';
    ctx.beginPath();
    ctx.ellipse(_lemo.x, _lemo.y + LEMO_H / 2 - 2, shW, shW * 0.32, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    const [bx0, by0, bx1, by1] = a.box;
    const col = _lemo.frame % a.cols;
    const row = (_lemo.frame / a.cols) | 0;
    ctx.save();
    ctx.translate(_lemo.x, _lemo.y);
    ctx.scale(_lemo.face, 1);           // mirrors around his own anchor
    // Drop shadow, matching the avatars' (drawPlayers uses the same values on the
    // ring). installLowGfxShadowGuard zeroes shadowBlur on the reduced tiers, so
    // this costs nothing on mobile — same as every other shadow in the world pass.
    ctx.shadowBlur = 10;
    ctx.shadowColor = 'rgba(0, 0, 0, 0.3)';
    ctx.shadowOffsetY = 4;
    ctx.drawImage(
        sheet,
        col * a.fw, row * a.fh, a.fw, a.fh,
        (bx0 - LEMO_ANCHOR_SX) * LEMO_SCALE,
        (by0 - LEMO_ANCHOR_SY) * LEMO_SCALE + LEMO_H / 2,
        (bx1 - bx0) * LEMO_SCALE,
        (by1 - by0) * LEMO_SCALE
    );
    ctx.restore();
}
